/* Per-extension copy for the /format/<ext> landing pages.
   ============================================================================
   WHY THIS FILE EXISTS
   The catalog (assets/js/core/formats.js) describes formats one ROW at a time,
   so every sibling extension in a row shares one `desc` (JPG, PNG and GIF all
   sit in the "Photo" row). That is fine for the overlay and the /formats hub,
   but a per-extension landing page needs something UNIQUE to say about each
   extension or the pages read as thin/duplicate content. This map supplies that
   unique line.

   WHO USES IT
   tools/prerender-format-pages.mjs merges this with the catalog: `blurb` becomes
   the page's opening "what is a .X file" sentence; `fact` becomes a "Did you
   know" row; the catalog `desc` supplies the "what Analyser does with it" part.

   SCOPE  (see CLAUDE.md -> "Generated SEO pages")
   - Every full-analysis extension (a real viewer / deep analysis) SHOULD have an
     entry; the generator WARNS and uses a generic fallback for any that is
     missing, so a save.bat run tells you what to fill in.
   - Well-known identification-only formats (the catalog's IDENTIFICATION_CORE
     set) also have entries here. The long-tail IDENTIFICATION_EXTENDED formats
     fall back, without a warning, to a line built from their catalog row.

   ENTRY SHAPE  { name, blurb, fact?, factApprox? }
   - `name`: a short human name shown in the title, e.g. 'JPEG image'.
   - `blurb`: one or two plain sentences - what the format is and, where there is
     a recognisable owner, WHICH program(s) make or open it (e.g. "Created and
     opened by Cockos REAPER."). For ubiquitous formats with no single owner
     (JPEG, ZIP) naming an app is optional - don't force it.
   - `fact`: a "Did you know" line - year invented, and if obsolete, what
     replaced it and when. Optional but wanted on every authored entry.
   - `factApprox`: set true when the date/history is lower-confidence; the page
     then shows a muted "(approximate)" marker beside the fact.
   House style throughout: British spelling, no em-dashes (use " - ").
   ============================================================================ */
export const EXT_PAGES = {
  // ---- Photos ----
  jpg:  { name: 'JPEG image', blurb: 'JPEG is the most widely used photo format, using lossy compression to keep files small. It is the default for most cameras, phones and the web.', fact: 'The JPEG standard was published in 1992 and is still the default photo format on virtually every camera and phone.' },
  jpeg: { name: 'JPEG image', blurb: 'JPEG is the most widely used photo format, using lossy compression to keep files small. It is the default for most cameras, phones and the web.', fact: 'No JPEG can be larger than 65,535 pixels on a side, because the format stores image width and height as 16-bit numbers.' },
  jif:  { name: 'JPEG image (JIF)', blurb: 'JIF is the original JPEG File Interchange name - an early variant of the JPEG image format, now usually seen as .jpg or .jfif.', fact: 'JIF was the original 1992 JPEG interchange naming, quickly superseded by JFIF and the familiar .jpg.' },
  jfif: { name: 'JPEG image (JFIF)', blurb: 'JFIF (JPEG File Interchange Format) is a standard JPEG image variant, functionally the same as a .jpg file.', fact: 'JFIF was defined in 1992 to standardise exactly how JPEG image data is stored in a file.' },
  png:  { name: 'PNG image', blurb: 'PNG is a lossless image format with full alpha transparency, ideal for graphics, screenshots and logos.', fact: 'PNG was created in 1996 as a free replacement for GIF, after a patent dispute over the LZW compression GIF used.' },
  gif:  { name: 'GIF image', blurb: 'GIF is an 8-bit (256-colour) image format best known for short looping animations.', fact: 'GIF was introduced by CompuServe in 1987; its looping animations later became a staple of internet culture.' },
  webp: { name: 'WebP image', blurb: 'WebP is a modern Google image format offering both lossy and lossless compression, smaller than JPEG or PNG at similar quality.', fact: 'Google released WebP in 2010, derived from its VP8 video codec.' },
  heic: { name: 'HEIC photo', blurb: 'HEIC (HEIF) is Apple’s high-efficiency image format used by iPhones, storing photos at higher quality and about half the size of JPEG.', fact: 'Apple adopted HEIC in 2017 with iOS 11, based on the MPEG HEIF standard finalised in 2015.' },
  heif: { name: 'HEIF photo', blurb: 'HEIF is the high-efficiency image format behind Apple’s HEIC, storing photos at higher quality and smaller size than JPEG.', fact: 'HEIF was finalised by MPEG in 2015 and is best known as the basis of Apple’s HEIC photos.' },
  bmp:  { name: 'Bitmap image', blurb: 'BMP is an uncompressed Windows bitmap image format - large but simple.', fact: 'BMP shipped with Windows 1.0 in 1985, making it one of the oldest image formats still in use.' },
  tiff: { name: 'TIFF image', blurb: 'TIFF is a high-quality, often lossless image format used in photography, scanning and publishing.', fact: 'TIFF was created by Aldus in 1986 for desktop publishing; Adobe controls the specification today.' },
  avif: { name: 'AVIF image', blurb: 'AVIF is a next-generation image format based on the AV1 video codec, with excellent compression and HDR support.', fact: 'AVIF arrived in 2019, built on the royalty-free AV1 codec from the Alliance for Open Media.' },
  jxl:  { name: 'JPEG XL image', blurb: 'JPEG XL (JXL) is a modern image format offering high compression, lossless JPEG recompression and HDR.', fact: 'JPEG XL was standardised in 2022 and can losslessly recompress existing JPEG files to save space.' },
  ico:  { name: 'Windows icon', blurb: 'ICO is the Windows icon format, storing one or more small images at several sizes for app icons and favicons.', fact: 'The ICO format dates back to Windows 1.0 in 1985.' },
  raw:  { name: 'Camera RAW', blurb: 'RAW refers to unprocessed camera sensor data; the generic .raw extension covers several manufacturers’ raw photo files. Opened in Adobe Lightroom and similar editors.', fact: 'RAW is not one format - each camera maker has its own, which is why Adobe created the open DNG in 2004.' },
  arw:  { name: 'Sony RAW', blurb: 'ARW is Sony’s camera RAW format, holding unprocessed sensor data from Sony Alpha cameras. Opened in Sony Imaging Edge or Adobe Lightroom.', fact: 'Sony introduced ARW with its Alpha camera line in 2006.' },
  cr2:  { name: 'Canon RAW (CR2)', blurb: 'CR2 is Canon’s older camera RAW format (Canon Raw v2), used by most Canon DSLRs. Opened in Canon Digital Photo Professional or Adobe Lightroom.', fact: 'Canon used CR2 from 2004 until replacing it with the newer CR3 in 2018.' },
  cr3:  { name: 'Canon RAW (CR3)', blurb: 'CR3 is Canon’s newer camera RAW format, used by recent EOS cameras. Opened in Canon Digital Photo Professional or Adobe Lightroom.', fact: 'Canon introduced CR3 in 2018 to replace the long-running CR2.' },
  nef:  { name: 'Nikon RAW', blurb: 'NEF is Nikon’s camera RAW format (Nikon Electronic Format), holding unprocessed sensor data. Opened in Nikon NX Studio or Adobe Lightroom.', fact: 'Nikon has used the NEF format since the late 1990s.' },
  dng:  { name: 'Digital Negative', blurb: 'DNG (Digital Negative) is Adobe’s open, manufacturer-independent camera RAW format. Opened in Adobe Lightroom and most raw editors.', fact: 'Adobe created DNG in 2004 as a universal, open alternative to each maker’s proprietary raw format.' },
  raf:  { name: 'Fujifilm RAW', blurb: 'RAF is Fujifilm’s camera RAW format. Opened in Fujifilm’s software or Adobe Lightroom.', fact: 'RAF holds the raw output of Fujifilm’s distinctive sensor designs.' },
  rw2:  { name: 'Panasonic RAW', blurb: 'RW2 is Panasonic’s camera RAW format, used by Lumix cameras. Opened in Adobe Lightroom or Panasonic’s software.', fact: 'RW2 is the raw format for Panasonic’s Lumix line.' },
  orf:  { name: 'Olympus RAW', blurb: 'ORF is Olympus’s camera RAW format. Opened in OM Workspace or Adobe Lightroom.', fact: 'ORF is the raw format used by Olympus (now OM System) cameras.' },
  pef:  { name: 'Pentax RAW', blurb: 'PEF is Pentax’s camera RAW format (Pentax Electronic Format). Opened in Adobe Lightroom or Pentax software.', fact: 'PEF is the raw format for Pentax DSLRs.' },
  sr2:  { name: 'Sony RAW (SR2)', blurb: 'SR2 is an older Sony camera RAW format, predating ARW. Opened in Adobe Lightroom.', fact: 'SR2 came from Sony’s earlier DSLR cameras before ARW took over.' },
  srw:  { name: 'Samsung RAW', blurb: 'SRW is Samsung’s camera RAW format. Opened in Adobe Lightroom.', fact: 'SRW is the raw format from Samsung’s NX mirrorless cameras.' },
  x3f:  { name: 'Sigma RAW', blurb: 'X3F is Sigma’s camera RAW format, produced by its Foveon X3 sensors. Opened in Sigma Photo Pro.', fact: 'X3F stores data from Sigma’s unusual three-layer Foveon sensor, which captures colour very differently to ordinary sensors.' },
  '3fr':{ name: 'Hasselblad RAW', blurb: '3FR is Hasselblad’s camera RAW format. Opened in Hasselblad Phocus.', fact: '3FR comes from Hasselblad’s medium-format cameras and digital backs.' },
  iiq:  { name: 'Phase One RAW', blurb: 'IIQ is Phase One’s medium-format camera RAW format (Intelligent Image Quality). Opened in Capture One.', fact: 'IIQ holds the very high resolution raw files from Phase One’s medium-format backs.' },
  mrw:  { name: 'Minolta RAW', blurb: 'MRW is Minolta’s camera RAW format. Opened in Adobe Lightroom.', fact: 'MRW dates from Minolta’s DSLRs, before Sony took over the camera line in 2006.' },
  nrw:  { name: 'Nikon RAW (NRW)', blurb: 'NRW is a Nikon camera RAW format used by some Coolpix compacts. Opened in Nikon NX Studio or Adobe Lightroom.', fact: 'NRW is a lighter Nikon raw format used in Coolpix compact cameras.' },
  rwl:  { name: 'Leica RAW', blurb: 'RWL is Leica’s camera RAW format. Opened in Adobe Lightroom.', fact: 'RWL is the raw format used by several Leica cameras.' },
  crw:  { name: 'Canon RAW (CRW)', blurb: 'CRW is Canon’s original camera RAW format, predating CR2. Opened in Canon Digital Photo Professional.', fact: 'CRW was Canon’s first raw format, used before CR2 arrived in 2004.' },
  gpr:  { name: 'GoPro RAW', blurb: 'GPR is GoPro’s camera RAW format, based on Adobe DNG. Opened in GoPro software or Adobe Lightroom.', fact: 'GPR is built on Adobe’s open DNG format, tuned for GoPro action cameras.' },
  fff:  { name: 'Hasselblad RAW (FFF)', blurb: 'FFF is the Hasselblad and Imacon camera RAW format. Opened in Hasselblad Phocus.', fact: 'FFF dates from Imacon scanners and backs, a company Hasselblad merged with in 2004.' },
  mef:  { name: 'Mamiya RAW', blurb: 'MEF is Mamiya’s camera RAW format. Opened in Adobe Lightroom.', fact: 'MEF is the raw format from Mamiya’s medium-format cameras.' },
  mos:  { name: 'Leaf RAW', blurb: 'MOS is Leaf’s medium-format camera RAW format. Opened in Capture One or Leaf Capture.', fact: 'MOS comes from Leaf digital camera backs, prized in studio photography.' },
  kdc:  { name: 'Kodak RAW (KDC)', blurb: 'KDC is a Kodak camera RAW format. Opened in Adobe Lightroom.', fact: 'KDC dates from Kodak’s consumer digital cameras.' },
  dcr:  { name: 'Kodak RAW (DCR)', blurb: 'DCR is a Kodak camera RAW format. Opened in Adobe Lightroom.', fact: 'DCR is one of Kodak’s early digital camera raw formats.' },
  dcs:  { name: 'Kodak RAW (DCS)', blurb: 'DCS is Kodak’s professional camera RAW format. Opened in Adobe Lightroom.', fact: 'DCS comes from Kodak’s pioneering professional DSLRs of the 1990s.' },
  erf:  { name: 'Epson RAW', blurb: 'ERF is Epson’s camera RAW format. Opened in Adobe Lightroom.', fact: 'ERF was used by the Epson R-D1, one of the first digital rangefinder cameras.' },
  srf:  { name: 'Sony RAW (SRF)', blurb: 'SRF is an older Sony camera RAW format. Opened in Adobe Lightroom.', fact: 'SRF came from Sony’s fixed-lens Cyber-shot prosumer cameras such as the DSC-F828, predating the later SR2 and ARW formats.' },
  thm:  { name: 'Camera thumbnail', blurb: 'THM is a small JPEG thumbnail that cameras save alongside videos or RAW photos.', fact: 'A THM file is really just a JPEG preview the camera writes next to the main file.' },

  // ---- Sound ----
  mp3:  { name: 'MP3 audio', blurb: 'MP3 is the most common lossy audio format, compressing music to small files with near-universal device support.', fact: 'MP3 was finalised by Germany’s Fraunhofer Institute in 1993 and went on to ignite the digital-music revolution.' },
  wav:  { name: 'WAV audio', blurb: 'WAV is an uncompressed, lossless audio format common in recording and editing.', fact: 'WAV was created jointly by Microsoft and IBM in 1991.' },
  m4a:  { name: 'M4A audio', blurb: 'M4A is an MP4-based audio file, usually holding AAC (or ALAC lossless) audio - used by Apple Music and iTunes.', fact: 'M4A became widespread through Apple’s iTunes Store, which launched in 2003.' },
  m4b:  { name: 'M4B audiobook', blurb: 'M4B is an MP4-based audiobook format that supports chapters and bookmarks. Used by Apple Books and audiobook players.', fact: 'M4B adds chapter and bookmark support on top of the M4A audio format.' },
  aac:  { name: 'AAC audio', blurb: 'AAC is a lossy audio format that succeeded MP3, offering better quality at the same bitrate.', fact: 'AAC was standardised in 1997 as MP3’s successor and is the default for YouTube and Apple Music.' },
  flac: { name: 'FLAC audio', blurb: 'FLAC is a popular lossless audio format that compresses without losing any quality.', fact: 'FLAC was released in 2001 and is the most popular format for lossless music archiving.' },
  ogg:  { name: 'Ogg audio', blurb: 'OGG is an open audio container, usually holding Vorbis or Opus audio.', fact: 'The Ogg container comes from the non-profit Xiph.Org Foundation, which released Vorbis audio in 2000.' },
  opus: { name: 'Opus audio', blurb: 'Opus is a modern, highly efficient lossy audio codec used for streaming and voice.', fact: 'Opus was standardised in 2012 and now powers voice chat in Discord, WhatsApp and Zoom.' },
  aiff: { name: 'AIFF audio', blurb: 'AIFF is Apple’s uncompressed, lossless audio format, similar to WAV.', fact: 'Apple created AIFF in 1988, based on Electronic Arts’ earlier IFF format.' },
  wma:  { name: 'Windows Media Audio', blurb: 'WMA is Microsoft’s Windows Media Audio format.', fact: 'Microsoft launched WMA in 1999 to compete with MP3.' },
  amr:  { name: 'AMR audio', blurb: 'AMR is a speech-optimised audio format used for voice recordings on phones.', fact: 'AMR was adopted in 1999 as the standard voice codec for GSM mobile networks.' },
  ac3:  { name: 'Dolby Digital (AC-3)', blurb: 'AC-3 (Dolby Digital) is a surround-sound audio format used on DVDs and in broadcast.', fact: 'Dolby Digital debuted in cinemas in 1992 and became the standard sound format for DVDs.' },
  dts:  { name: 'DTS audio', blurb: 'DTS is a surround-sound audio format used in films and on Blu-ray.', fact: 'DTS launched in 1993, first heard in the cinema release of Jurassic Park.' },
  mka:  { name: 'Matroska audio', blurb: 'MKA is the Matroska audio container, the audio-only counterpart of MKV.', fact: 'MKA is part of the open Matroska family, first released in 2002.' },

  // ---- Lyrics ----
  lrc:  { name: 'Synced lyrics', blurb: 'LRC is a synchronised lyrics format that time-stamps each line to a song for karaoke-style display.', fact: 'LRC lyrics appeared in the late 1990s alongside the first software MP3 players.' },

  // ---- MIDI ----
  mid:  { name: 'MIDI sequence', blurb: 'MIDI stores musical note and instrument instructions rather than recorded audio, so any synthesiser can play it back.', fact: 'The MIDI standard was agreed by rival synthesiser makers in 1983 and is still how electronic instruments talk to each other.' },
  midi: { name: 'MIDI sequence', blurb: 'MIDI stores musical note and instrument instructions rather than recorded audio, so any synthesiser can play it back.', fact: 'MIDI’s chief architects, Dave Smith of Sequential Circuits and Roland founder Ikutaro Kakehashi, received a Technical Grammy in 2013 for its creation.' },

  // ---- Video ----
  mp4:  { name: 'MP4 video', blurb: 'MP4 is the most common video container, widely supported and usually holding H.264 video with AAC audio.', fact: 'MP4 was standardised in 2001, based on Apple’s QuickTime format.' },
  mov:  { name: 'QuickTime video', blurb: 'MOV is Apple’s QuickTime video container, common from iPhones and Macs.', fact: 'Apple introduced the QuickTime MOV format in 1991.' },
  avi:  { name: 'AVI video', blurb: 'AVI is a classic Microsoft video container.', fact: 'Microsoft created AVI in 1992 as part of Video for Windows.' },
  mkv:  { name: 'Matroska video', blurb: 'MKV (Matroska) is a flexible open video container that can hold many video, audio and subtitle tracks.', fact: 'Matroska launched in 2002 as an open, do-everything alternative to AVI.' },
  webm: { name: 'WebM video', blurb: 'WebM is an open, royalty-free video format designed for the web, using VP8, VP9 or AV1.', fact: 'Google released WebM in 2010 to give the web a royalty-free video format.' },
  wmv:  { name: 'Windows Media Video', blurb: 'WMV is Microsoft’s Windows Media Video format.', fact: 'Microsoft launched WMV in 1999 as part of Windows Media.' },
  flv:  { name: 'Flash video', blurb: 'FLV is the Flash Video container, once the standard for web video.', fact: 'FLV powered nearly all web video in the early YouTube era before Flash was retired by Adobe in 2020.' },
  '3gp':{ name: '3GP mobile video', blurb: '3GP is a mobile video container used by older phones.', fact: '3GP was created for the first 3G mobile phones in the early 2000s.' },
  '3g2':{ name: '3G2 mobile video', blurb: '3G2 is a mobile video container used on CDMA phones, related to 3GP.', fact: '3G2 is the version of 3GP made for CDMA mobile networks.' },
  mpg:  { name: 'MPEG video', blurb: 'MPG (MPEG) is an early standard video format using MPEG-1/2 compression.', fact: 'The MPEG-1 standard behind MPG arrived in 1993 and gave us the Video CD.' },
  mpeg: { name: 'MPEG video', blurb: 'MPEG is an early standard video format using MPEG-1/2 compression.', fact: 'MPEG-1’s Layer II audio found a long second life in broadcasting: the original DAB digital radio standard adopted it, and many stations still transmit in it today.' },
  mts:  { name: 'AVCHD video', blurb: 'MTS is the AVCHD video format used by camcorders, holding H.264 video.', fact: 'AVCHD was launched by Sony and Panasonic in 2006 for HD camcorders.' },
  m2ts: { name: 'AVCHD video (M2TS)', blurb: 'M2TS is the AVCHD/Blu-ray transport-stream video format used by camcorders.', fact: 'M2TS is the transport-stream form of AVCHD, also used on Blu-ray discs.' },
  ts:   { name: 'Transport stream / TypeScript', blurb: 'TS has two unrelated uses: an MPEG-2 transport-stream video file (broadcast and recordings), and TypeScript source code. Analyser tells them apart by their contents.', fact: 'Confusingly, .ts is both an MPEG transport stream (from 1995) and TypeScript code (from 2012).' },
  vob:  { name: 'DVD video', blurb: 'VOB is the video format used on DVD-Video discs.', fact: 'VOB is the container on every DVD-Video disc, a format launched in 1996.' },
  ogv:  { name: 'Ogg video', blurb: 'OGV is the Ogg video format, an open container usually holding Theora video.', fact: 'OGV uses the royalty-free Theora codec, released by Xiph.Org in 2004.' },
  h264: { name: 'H.264 stream', blurb: 'H.264 (AVC) is the most widely used video codec; a raw .h264 file is an unwrapped elementary stream.', fact: 'H.264 was standardised in 2003 and is still the most widely used video codec in the world.' },
  '264':{ name: 'H.264 stream', blurb: 'A .264 file is a raw H.264 (AVC) video elementary stream, without a container.', fact: 'The number in .264 comes from the ITU-T’s H-series of standards: it is the direct descendant of H.261, the 1988 videoconferencing codec that established the basic design still used by video compression today.' },
  avc:  { name: 'H.264 / AVC stream', blurb: 'AVC is another name for the H.264 video codec; a raw .avc file is an unwrapped elementary stream.', fact: 'In 2013 Cisco open-sourced its AVC codec as OpenH264 and offered to pay the patent royalties on its binaries itself, which is how Firefox was able to add H.264 support for WebRTC video calls.' },
  h265: { name: 'H.265 stream', blurb: 'H.265 (HEVC) is a high-efficiency video codec; a raw .h265 file is an unwrapped elementary stream.', fact: 'H.265 (HEVC) arrived in 2013, roughly doubling H.264’s efficiency at the same quality.' },
  '265':{ name: 'H.265 stream', blurb: 'A .265 file is a raw H.265 (HEVC) video elementary stream, without a container.', fact: 'Apple’s HEIC photo format, the iPhone’s default camera output since 2017, stores its images using HEVC compression, so billions of photos are saved with this video codec.' },
  hevc: { name: 'HEVC stream', blurb: 'HEVC is another name for the H.265 video codec; a raw .hevc file is an unwrapped elementary stream.', fact: 'HDR10, the most widely supported HDR video standard, is defined on top of HEVC’s Main 10 profile, whose 10-bit colour depth is where the format gets its name.' },

  // ---- Editing timelines ----
  edl:    { name: 'Edit Decision List', blurb: 'EDL (Edit Decision List) is a plain-text video-editing format listing cuts and timecodes. Read by DaVinci Resolve, Premiere Pro and most editors.', fact: 'EDLs date back to the 1970s, when they controlled tape-based video editing machines.' },
  fcpxml: { name: 'Final Cut Pro XML', blurb: 'FCPXML is Apple’s Final Cut Pro project interchange format - an XML description of an edit. Created by Final Cut Pro.', fact: 'FCPXML is the interchange format for Final Cut Pro X, introduced by Apple in 2011.' },
  otio:   { name: 'OpenTimelineIO', blurb: 'OTIO (OpenTimelineIO) is an open editing-timeline interchange format used across film and VFX tools.', fact: 'OpenTimelineIO was created at Pixar and open-sourced in 2018.' },

  // ---- Subtitles ----
  srt: { name: 'SubRip subtitles', blurb: 'SRT (SubRip) is the most common subtitle format - a simple text file of timed captions. Read by VLC and virtually every media player.', fact: 'The SRT format comes from the SubRip subtitle-ripping tool released around 2000.' },
  vtt: { name: 'WebVTT subtitles', blurb: 'WebVTT (VTT) is the web-standard subtitle format used by HTML5 video.', fact: 'WebVTT was created in 2010 as the captions standard for HTML5 video.' },
  ass: { name: 'ASS subtitles', blurb: 'ASS (Advanced SubStation Alpha) is a styled subtitle format supporting fonts, colours and positioning. Edited with Aegisub.', fact: 'ASS grew out of the anime fansubbing scene in the early 2000s, extending the older SSA format.' },
  ssa: { name: 'SSA subtitles', blurb: 'SSA (SubStation Alpha) is a styled subtitle format, the predecessor of ASS.', fact: 'SSA was created by the SubStation Alpha editor in 1998 and was later extended into ASS.' },

  // ---- Documents ----
  pdf:  { name: 'PDF document', blurb: 'PDF (Portable Document Format) is a fixed-layout document format for sharing and printing. Created and read by Adobe Acrobat, browsers and countless apps.', fact: 'Adobe co-founder John Warnock created PDF in 1993; it became an open ISO standard in 2008.' },
  docx: { name: 'Word document', blurb: 'DOCX is the modern Microsoft Word document format, stored as a zipped XML package.', fact: 'DOCX is Microsoft Word’s modern format, which replaced the binary .doc with Office 2007.' },
  xlsx: { name: 'Excel spreadsheet', blurb: 'XLSX is the modern Microsoft Excel spreadsheet format, stored as a zipped XML package.', fact: 'XLSX became Excel’s default format with Microsoft Office 2007, replacing the old .xls.' },
  pptx: { name: 'PowerPoint presentation', blurb: 'PPTX is the modern Microsoft PowerPoint presentation format, stored as a zipped XML package.', fact: 'PPTX became PowerPoint’s default format with Microsoft Office 2007, replacing the old .ppt.' },
  epub: { name: 'EPUB ebook', blurb: 'EPUB is the open ebook format used by most readers - a zipped package of HTML and assets. Opened in Apple Books, calibre and most e-readers.', fact: 'EPUB was released in 2007 by the International Digital Publishing Forum and is the standard everywhere except Amazon Kindle.' },
  odt:  { name: 'OpenDocument text', blurb: 'ODT is the OpenDocument text format, the default document of LibreOffice and OpenOffice - a zipped XML package, the open-standard counterpart to Word DOCX.', fact: 'OpenDocument (ODF) became an ISO standard in 2006 and is the default save format of LibreOffice.' },
  ods:  { name: 'OpenDocument spreadsheet', blurb: 'ODS is the OpenDocument spreadsheet format used by LibreOffice Calc and OpenOffice - a zipped XML package, the open-standard counterpart to Excel XLSX.', fact: 'ODS shares the OpenDocument container with ODT and ODP; only the content.xml payload differs.' },
  odp:  { name: 'OpenDocument presentation', blurb: 'ODP is the OpenDocument presentation format used by LibreOffice Impress and OpenOffice - a zipped XML package, the open-standard counterpart to PowerPoint PPTX.', fact: 'ODP stores each slide as a draw:page element inside the same OpenDocument container as ODT and ODS.' },
  doc:  { name: 'Word 97-2003 document', blurb: 'DOC is the legacy binary Microsoft Word format used before Office 2007, stored in an OLE2 compound file rather than zipped XML.', fact: 'The .doc binary format dates to Word for Windows in 1989 and was Word’s default until DOCX arrived in 2007.' },
  xls:  { name: 'Excel 97-2003 spreadsheet', blurb: 'XLS is the legacy binary Microsoft Excel format used before Office 2007, storing cells in BIFF records inside an OLE2 compound file.', fact: 'The BIFF8 .xls format was Excel’s default from 1997 until XLSX replaced it in Office 2007.' },
  ppt:  { name: 'PowerPoint 97-2003 presentation', blurb: 'PPT is the legacy binary Microsoft PowerPoint format used before Office 2007, stored as records inside an OLE2 compound file.', fact: 'The binary .ppt format was PowerPoint’s default until PPTX replaced it with Office 2007.' },
  docm: { name: 'Word macro-enabled document', blurb: 'DOCM is a macro-enabled Microsoft Word document - the same zipped XML package as DOCX, but allowed to carry VBA macros.', fact: 'Office uses the M suffix (DOCM/XLSM/PPTM) to mark macro-enabled files so they are not silently trusted.' },
  dotx: { name: 'Word template', blurb: 'DOTX is a Microsoft Word template - the same zipped XML package as DOCX, used as the starting point for new documents.' },
  dotm: { name: 'Word macro-enabled template', blurb: 'DOTM is a macro-enabled Microsoft Word template - a DOTX template that may also contain VBA macros.' },
  xlsm: { name: 'Excel macro-enabled workbook', blurb: 'XLSM is a macro-enabled Microsoft Excel workbook - the same zipped XML package as XLSX, but allowed to carry VBA macros.' },
  xltx: { name: 'Excel template', blurb: 'XLTX is a Microsoft Excel template - the same zipped XML package as XLSX, used as the starting point for new workbooks.' },
  xltm: { name: 'Excel macro-enabled template', blurb: 'XLTM is a macro-enabled Microsoft Excel template - an XLTX template that may also contain VBA macros.' },
  pptm: { name: 'PowerPoint macro-enabled presentation', blurb: 'PPTM is a macro-enabled Microsoft PowerPoint presentation - the same zipped XML package as PPTX, but allowed to carry VBA macros.' },
  ppsx: { name: 'PowerPoint slideshow', blurb: 'PPSX is a PowerPoint slideshow - the same zipped XML package as PPTX, set to open straight into the presentation.' },
  ppsm: { name: 'PowerPoint macro-enabled slideshow', blurb: 'PPSM is a macro-enabled PowerPoint slideshow - a PPSX that may also contain VBA macros.' },
  potx: { name: 'PowerPoint template', blurb: 'POTX is a Microsoft PowerPoint template - the same zipped XML package as PPTX, used as the starting point for new presentations.' },
  potm: { name: 'PowerPoint macro-enabled template', blurb: 'POTM is a macro-enabled Microsoft PowerPoint template - a POTX that may also contain VBA macros.' },
  ott:  { name: 'OpenDocument text template', blurb: 'OTT is an OpenDocument text template - the same package as ODT, used by LibreOffice and OpenOffice as the basis for new documents.' },
  ots:  { name: 'OpenDocument spreadsheet template', blurb: 'OTS is an OpenDocument spreadsheet template - the same package as ODS, used as the basis for new spreadsheets.' },
  otp:  { name: 'OpenDocument presentation template', blurb: 'OTP is an OpenDocument presentation template - the same package as ODP, used as the basis for new presentations.' },
  odg:  { name: 'OpenDocument graphics', blurb: 'ODG is the OpenDocument graphics format used by LibreOffice Draw and OpenOffice for vector drawings and diagrams - a zipped XML package.', fact: 'ODG shares the OpenDocument container with ODT, ODS and ODP; its body is an office:drawing of draw:page shapes.' },
  otg:  { name: 'OpenDocument graphics template', blurb: 'OTG is an OpenDocument graphics template - the same package as ODG, used as the basis for new drawings.' },

  // ---- Data ----
  csv:  { name: 'CSV table', blurb: 'CSV is a plain-text table format storing rows of comma-separated values. Opened in Excel, Google Sheets and any text editor.', fact: 'CSV has been used since the earliest days of computing but was only formally documented in 2005, as RFC 4180.' },
  tsv:  { name: 'TSV table', blurb: 'TSV is a plain-text table format storing tab-separated values. Opened in Excel and any text editor.', fact: 'TSV is the tab-separated cousin of CSV, useful when the data itself contains commas.' },
  svg:  { name: 'SVG vector image', blurb: 'SVG is an XML-based vector image format that scales to any size without losing quality. Opened in browsers, Inkscape and Adobe Illustrator.', fact: 'SVG became a W3C web standard in 2001.' },

  // ---- Web / code ----
  html: { name: 'HTML page', blurb: 'HTML is the markup language of web pages.', fact: 'Tim Berners-Lee created HTML in 1991 to build the World Wide Web.' },
  css:  { name: 'CSS stylesheet', blurb: 'CSS is the stylesheet language that controls the look of web pages.', fact: 'CSS was proposed by Hakon Wium Lie in 1994 and first standardised in 1996.' },
  js:   { name: 'JavaScript', blurb: 'JavaScript (JS) is the programming language of the web.', fact: 'JavaScript was famously written by Brendan Eich at Netscape in just ten days in 1995.' },
  tsx:  { name: 'TypeScript + JSX', blurb: 'TSX is a TypeScript source file containing JSX/React markup.', fact: 'It combines TypeScript, released by Microsoft in 2012, with React’s JSX syntax.' },
  jsx:  { name: 'JavaScript + JSX', blurb: 'JSX is a JavaScript source file containing React markup.', fact: 'JSX was introduced by Facebook alongside React in 2013.' },
  json: { name: 'JSON data', blurb: 'JSON is a lightweight, human-readable data-interchange format.', fact: 'JSON was specified and popularised by Douglas Crockford in the early 2000s.' },
  yaml: { name: 'YAML data', blurb: 'YAML is a human-readable data format often used for configuration files.', fact: 'YAML was first released in 2001 as a friendlier alternative to XML for configuration.' },
  xml:  { name: 'XML data', blurb: 'XML is a flexible markup language for structured data.', fact: 'XML became a W3C standard in 1998 and underpins countless file formats, including DOCX and SVG.' },
  md:   { name: 'Markdown', blurb: 'Markdown (MD) is a lightweight plain-text formatting syntax that renders to HTML.', fact: 'Markdown was created by John Gruber, with Aaron Swartz, in 2004.' },

  // ---- 3D models ----
  stl:  { name: 'STL 3D model', blurb: 'STL is the most common 3D-printing mesh format, storing a model’s surface as triangles. Exported by most CAD tools and read by every slicer.', fact: 'STL was created by 3D Systems in 1987 for the first stereolithography 3D printers - hence the name.' },
  obj:  { name: 'OBJ 3D model', blurb: 'OBJ is a widely supported 3D model format storing geometry, and optionally materials and texture coordinates. Read by Blender, Maya and most 3D tools.', fact: 'OBJ was developed by Wavefront Technologies in the 1990s and is still a universal exchange format.' },
  ply:  { name: 'PLY 3D model', blurb: 'PLY (Polygon File Format) stores 3D meshes and point clouds, often with per-vertex colour. Common in 3D scanning.', fact: 'PLY was created at Stanford in the 1990s and is famous for storing the Stanford Bunny scan.' },
  off:  { name: 'OFF 3D model', blurb: 'OFF (Object File Format) is a simple 3D mesh format storing polygons.', fact: 'OFF is a long-standing teaching and research mesh format from the early 1990s.' },
  step: { name: 'STEP CAD model', blurb: 'STEP is a standard CAD exchange format for precise 3D solid models, used across engineering tools.', fact: 'STEP (ISO 10303) was first published in 1994 as a universal CAD exchange standard.' },
  stp:  { name: 'STEP CAD model', blurb: 'STP is the same standard CAD exchange format as STEP, for precise 3D solid models.', fact: 'STP is just STEP under its short extension - the ISO 10303 CAD exchange standard, published in 1994.' },
  iges: { name: 'IGES CAD model', blurb: 'IGES is an older standard CAD exchange format for 3D models and surfaces.', fact: 'IGES was the first widely used CAD exchange format, published in the United States in 1980.' },
  igs:  { name: 'IGES CAD model', blurb: 'IGS is the same older CAD exchange format as IGES, for 3D models and surfaces.', fact: 'IGS is IGES under its short extension - the first widely used CAD exchange format, from 1980.' },
  brep: { name: 'BREP CAD solid', blurb: 'BREP is a boundary-representation CAD format describing exact solid geometry (OpenCASCADE).', fact: 'Boundary representation has been the core way CAD kernels describe solids since the 1970s.' },
  '3mf':{ name: '3MF 3D print', blurb: '3MF is a modern 3D-printing format - a zipped package that is richer than STL.', fact: 'The 3MF Consortium, backed by Microsoft, released the format in 2015 to fix STL’s long-standing shortcomings.' },
  amf:  { name: 'AMF 3D print', blurb: 'AMF (Additive Manufacturing Format) is an XML-based 3D-printing format supporting colour and materials.', fact: 'AMF was published as an ISO/ASTM standard in 2011 as an STL successor, though 3MF has since overtaken it.' },

  // ---- Archives ----
  zip:  { name: 'ZIP archive', blurb: 'ZIP is the most common archive format, bundling and compressing multiple files into one. Built into Windows, macOS and tools like 7-Zip.', fact: 'Phil Katz created ZIP in 1989 for his PKZIP tool, and it remains the world’s default archive format.' },

  // ---- Maps ----
  gpx:    { name: 'GPS track (GPX)', blurb: 'GPX is the standard GPS exchange format, storing tracks, routes and waypoints as XML. Read by Strava, Garmin and mapping apps.', fact: 'GPX was released in 2002 as a universal, open way to share GPS data between devices and apps.' },
  kml:    { name: 'Google Earth (KML)', blurb: 'KML is Google’s XML format for geographic data, used by Google Earth and Maps.', fact: 'KML came from Keyhole, the company Google bought in 2004 to build Google Earth; it became an open OGC standard in 2008.' },
  geojson:{ name: 'GeoJSON', blurb: 'GeoJSON is a JSON format for geographic features such as points, lines and polygons.', fact: 'GeoJSON was published in 2008 and standardised as RFC 7946 in 2016.' },

  // ==========================================================================
  // Well-known identification-only formats (catalog IDENTIFICATION_CORE).
  // ==========================================================================

  // ---- Documents (legacy + open document) ----
  doc:     { name: 'Word document (legacy)', blurb: 'DOC is the classic Microsoft Word document format. Created and opened by Microsoft Word.', fact: 'DOC was Word’s format from 1983 until DOCX replaced it in 2007.' },
  xls:     { name: 'Excel spreadsheet (legacy)', blurb: 'XLS is the classic Microsoft Excel spreadsheet format. Created and opened by Microsoft Excel.', fact: 'XLS was Excel’s binary format until XLSX replaced it in 2007.' },
  ppt:     { name: 'PowerPoint (legacy)', blurb: 'PPT is the classic Microsoft PowerPoint presentation format. Created and opened by Microsoft PowerPoint.', fact: 'PPT was PowerPoint’s format until PPTX replaced it in 2007.' },
  ppsx:    { name: 'PowerPoint slideshow', blurb: 'PPSX is a PowerPoint file that opens straight into the slideshow, rather than the editor. Created by Microsoft PowerPoint.', fact: 'PPSX is PowerPoint’s show-only format, which arrived with Office 2007’s XML files.' },
  odt:     { name: 'OpenDocument text', blurb: 'ODT is the OpenDocument word-processing format. Created and opened by LibreOffice Writer and OpenOffice.', fact: 'ODT is the OpenDocument text format used by LibreOffice Writer and OpenOffice, ratified as a standard in 2006.' },
  ods:     { name: 'OpenDocument spreadsheet', blurb: 'ODS is the OpenDocument spreadsheet format. Created and opened by LibreOffice Calc.', fact: 'ODS is the OpenDocument spreadsheet used by LibreOffice Calc, ratified as a standard in 2006.' },
  odp:     { name: 'OpenDocument presentation', blurb: 'ODP is the OpenDocument presentation format. Created and opened by LibreOffice Impress.', fact: 'ODP is the OpenDocument presentation used by LibreOffice Impress, ratified as a standard in 2006.' },
  odg:     { name: 'OpenDocument drawing', blurb: 'ODG is the OpenDocument drawing format. Created and opened by LibreOffice Draw.', fact: 'ODG is the OpenDocument drawing used by LibreOffice Draw, ratified as a standard in 2006.' },
  rtf:     { name: 'Rich Text Format', blurb: 'RTF is a portable rich-text document format. Opened by WordPad, Microsoft Word and most word processors.', fact: 'Microsoft created RTF in 1987, and it still opens in WordPad, Word and almost every word processor.' },
  pages:   { name: 'Apple Pages document', blurb: 'A Pages file is a document from Apple’s word processor. Created and opened by Apple Pages.', fact: 'Pages launched in 2005 as part of Apple’s iWork suite.' },
  numbers: { name: 'Apple Numbers spreadsheet', blurb: 'A Numbers file is a spreadsheet from Apple’s iWork suite. Created and opened by Apple Numbers.', fact: 'Numbers was introduced by Apple in 2007.' },
  keynote: { name: 'Apple Keynote presentation', blurb: 'A Keynote file is a presentation from Apple’s iWork suite. Created and opened by Apple Keynote.', fact: 'Keynote was originally built for Steve Jobs’s own keynote presentations and released in 2003.' },

  // ---- Adobe ----
  psd:        { name: 'Photoshop document', blurb: 'PSD is Adobe Photoshop’s native layered image format. Created and opened by Adobe Photoshop.', fact: 'PSD is Photoshop’s native format; Photoshop first shipped in 1990 and effectively created the digital-imaging industry.' },
  psb:        { name: 'Photoshop big document', blurb: 'PSB is Photoshop’s large-document format for huge images. Created and opened by Adobe Photoshop.', fact: 'PSB was added in Photoshop CS (2003) to handle files beyond 30,000 pixels or 2 GB.' },
  ai:         { name: 'Adobe Illustrator artwork', blurb: 'AI is Adobe Illustrator’s native vector artwork format. Created and opened by Adobe Illustrator.', fact: 'Illustrator launched in 1987 and was one of the first apps designed for Apple’s Macintosh.' },
  indd:       { name: 'InDesign document', blurb: 'INDD is an Adobe InDesign page-layout document. Created and opened by Adobe InDesign.', fact: 'InDesign launched in 1999 as Adobe’s replacement for PageMaker.' },
  indt:       { name: 'InDesign template', blurb: 'INDT is an Adobe InDesign template, used to start new documents. Created and opened by Adobe InDesign.', fact: 'InDesign 2.0, released in January 2002, was the first desktop-publishing application to run natively on Mac OS X.' },
  idml:       { name: 'InDesign Markup', blurb: 'IDML is InDesign’s XML-based interchange format, used to move layouts between versions. Created by Adobe InDesign.', fact: 'IDML is Adobe InDesign’s interchange format, which replaced the older INX around 2008.' },
  aep:        { name: 'After Effects project', blurb: 'AEP is an Adobe After Effects project file. Created and opened by Adobe After Effects.', fact: 'After Effects began in 1993 and is the standard tool for motion graphics and VFX compositing.' },
  aepx:       { name: 'After Effects project (XML)', blurb: 'AEPX is the XML form of an After Effects project. Created and opened by Adobe After Effects.', fact: 'The XML project format behind .aepx arrived with After Effects CS4 in 2008, aimed at automation workflows where scripts edit project details without ever launching the application.' },
  aet:        { name: 'After Effects template', blurb: 'AET is an Adobe After Effects project template. Created and opened by Adobe After Effects.', fact: 'Five of After Effects’ original developers received an Academy Scientific and Engineering Award in 2019, recognising the program’s design and its role in film title work and screen graphics.' },
  prproj:     { name: 'Premiere Pro project', blurb: 'PRPROJ is an Adobe Premiere Pro video-editing project. Created and opened by Adobe Premiere Pro.', fact: 'Adobe Premiere first appeared in 1991, one of the earliest software video editors.' },
  prel:       { name: 'Premiere Elements project', blurb: 'PREL is an Adobe Premiere Elements project - the consumer version of Premiere Pro. Created and opened by Premiere Elements.', fact: 'Premiere Elements is the simplified, home-user edition of Adobe’s Premiere video editor.' },
  mogrt:      { name: 'Motion Graphics Template', blurb: 'MOGRT is a reusable Motion Graphics Template shared between After Effects and Premiere Pro. Created by Adobe’s video apps.', fact: 'MOGRT templates, introduced by Adobe in 2017, move animated graphics between After Effects and Premiere Pro.' },
  sesx:       { name: 'Audition session', blurb: 'SESX is an Adobe Audition multitrack session. Created and opened by Adobe Audition.', fact: 'Audition grew out of Cool Edit Pro, which Adobe bought from Syntrillium in 2003.' },
  xd:         { name: 'Adobe XD design', blurb: 'XD is an Adobe XD interface-design file. Created and opened by Adobe XD.', fact: 'XD launched in 2016 but Adobe wound down its development in 2023 after its bid to buy Figma collapsed.' },
  fla:        { name: 'Animate (Flash) source', blurb: 'FLA is the editable source file of Adobe Animate, formerly Flash. Created and opened by Adobe Animate.', fact: 'FLA dates back to Macromedia Flash in the late 1990s; Adobe renamed the app to Animate in 2016.' },
  swf:        { name: 'Flash movie', blurb: 'SWF is the compiled Flash format that ran web animations and games. Played by the old Flash Player.', fact: 'SWF powered web games and animation for two decades until Adobe retired Flash at the end of 2020.' },
  xmp:        { name: 'XMP metadata', blurb: 'XMP is Adobe’s XML metadata sidecar, storing edits and information about a media file. Used across Adobe apps.', fact: 'Adobe introduced XMP in 2001 as an open standard for embedding metadata in files.' },
  lrtemplate: { name: 'Lightroom preset (legacy)', blurb: 'LRtemplate is an older Adobe Lightroom develop preset. Created and opened by Adobe Lightroom.', fact: 'Adobe Lightroom replaced its .lrtemplate presets with a newer XMP-based preset format.' },
  lrcat:      { name: 'Lightroom catalog', blurb: 'LRcat is the Adobe Lightroom catalog database that tracks all your photos and edits. Created by Lightroom Classic.', fact: 'The Lightroom catalog is actually a SQLite database under the hood.' },
  acv:        { name: 'Photoshop Curves preset', blurb: 'ACV stores a Photoshop Curves adjustment. Created and opened by Adobe Photoshop.', fact: 'Photoshop has let users save and load adjustment presets like this since the 1990s.' },
  aco:        { name: 'Photoshop swatches', blurb: 'ACO is a Photoshop colour-swatch palette. Created and opened by Adobe Photoshop.', fact: 'An ACO file lets artists share a chosen set of colours between Photoshop projects.' },
  asl:        { name: 'Photoshop layer styles', blurb: 'ASL stores reusable Photoshop layer styles. Created and opened by Adobe Photoshop.', fact: 'Layer styles were introduced in Photoshop 6 in 2000.' },
  abr:        { name: 'Photoshop brushes', blurb: 'ABR is a Photoshop brush-preset file. Created and opened by Adobe Photoshop.', fact: 'Custom, shareable brushes have been a Photoshop hallmark since the 1990s.' },
  grd:        { name: 'Photoshop gradients', blurb: 'GRD stores Photoshop gradient presets. Created and opened by Adobe Photoshop.', fact: 'GRD files let artists share gradient sets between Photoshop installations.' },
  pat:        { name: 'Photoshop patterns', blurb: 'PAT is a Photoshop pattern-preset file. Created and opened by Adobe Photoshop.', fact: 'PAT files store tileable patterns for filling and texturing in Photoshop.' },

  // ---- Design ----
  fig:       { name: 'Figma design', blurb: 'FIG is a Figma interface-design file. Created and opened by Figma.', fact: 'Figma launched in 2016; Adobe’s 20-billion-dollar bid to buy it collapsed under regulators in 2023.' },
  sketch:    { name: 'Sketch design', blurb: 'A Sketch file is a UI-design document from the Mac app Sketch. Created and opened by Sketch.', fact: 'Sketch was released in 2010 and helped define the modern app-design workflow before Figma.' },
  afphoto:   { name: 'Affinity Photo document', blurb: 'AFPHOTO is a document from Affinity Photo, Serif’s photo editor. Created and opened by Affinity Photo.', fact: 'Affinity Photo launched in 2015 as a one-off-purchase rival to Adobe Photoshop.' },
  afdesign:  { name: 'Affinity Designer document', blurb: 'AFDESIGN is a document from Affinity Designer, Serif’s vector app. Created and opened by Affinity Designer.', fact: 'Affinity Designer launched in 2014 as a one-off-purchase rival to Adobe Illustrator.' },
  afpub:     { name: 'Affinity Publisher document', blurb: 'AFPUB is a document from Affinity Publisher, Serif’s page-layout app. Created and opened by Affinity Publisher.', fact: 'Affinity Publisher completed Serif’s design suite when it launched in 2019.' },
  procreate: { name: 'Procreate artwork', blurb: 'A Procreate file is a painting from the iPad app Procreate. Created and opened by Procreate.', fact: 'Procreate launched in 2011 and became the best-known painting app on the iPad.' },
  xcf:       { name: 'GIMP image', blurb: 'XCF is the native layered-image format of GIMP, the free image editor. Created and opened by GIMP.', fact: 'GIMP first appeared in 1996 and is the best-known free alternative to Photoshop.' },
  kra:       { name: 'Krita document', blurb: 'KRA is the native format of Krita, a free painting app for digital artists. Created and opened by Krita.', fact: 'Krita grew out of the KDE project and is built specifically for digital painting.' },
  pdn:       { name: 'Paint.NET image', blurb: 'PDN is the native layered format of Paint.NET, a free Windows image editor. Created and opened by Paint.NET.', fact: 'Paint.NET began in 2004 as a university project meant to better Microsoft Paint.' },
  spp:       { name: 'Substance Painter project', blurb: 'SPP is a project from Adobe Substance 3D Painter, used to texture 3D models. Created and opened by Substance Painter.', fact: 'Substance Painter came from Allegorithmic, which Adobe acquired in 2019.' },
  sbsar:     { name: 'Substance material', blurb: 'SBSAR is a procedural material from the Substance toolset. Used by Substance Painter and Designer.', fact: 'Game engines such as Unity and Unreal can load .sbsar materials through Substance plug-ins, letting artists tweak exposed parameters without leaving the engine.' },
  sbs:       { name: 'Substance Designer source', blurb: 'SBS is the editable source of a Substance procedural material. Created and opened by Adobe Substance 3D Designer.', fact: 'Substance Designer evolved from MaPZone, a free node-based texturing tool by Allegorithmic, before version 1.0 of Designer shipped in 2010.' },

  // ---- CAD ----
  dwg:        { name: 'AutoCAD drawing', blurb: 'DWG is AutoCAD’s native 2D/3D drawing format. Created and opened by Autodesk AutoCAD.', fact: 'DWG is AutoCAD’s native format; AutoCAD launched in 1982 and made desktop CAD mainstream.' },
  dxf:        { name: 'CAD drawing exchange (DXF)', blurb: 'DXF is an open CAD drawing-exchange format readable by almost every CAD program. Created by Autodesk.', fact: 'Autodesk created DXF in 1982 as an open way to move drawings between CAD programs.' },
  dwt:        { name: 'AutoCAD template', blurb: 'DWT is an AutoCAD drawing template, used to start new drawings. Created and opened by Autodesk AutoCAD.', fact: 'DWT is an AutoCAD drawing template, storing the standard layers and styles a firm reuses.' },
  sldprt:     { name: 'SolidWorks part', blurb: 'SLDPRT is a single-part 3D model from SolidWorks. Created and opened by SolidWorks.', fact: 'SolidWorks launched in 1995 and made 3D mechanical CAD affordable on Windows PCs.' },
  sldasm:     { name: 'SolidWorks assembly', blurb: 'SLDASM is a SolidWorks assembly of several parts. Created and opened by SolidWorks.', fact: 'Parts in a .sldasm are held together with mates - geometric relations such as coincident, concentric and parallel that also define how the mechanism can move.' },
  slddrw:     { name: 'SolidWorks drawing', blurb: 'SLDDRW is a 2D engineering drawing from SolidWorks. Created and opened by SolidWorks.', fact: 'Dassault Systèmes, the French company behind CATIA, bought SolidWorks in 1997 for about 310 million dollars in stock.' },
  sldreg:     { name: 'SolidWorks settings backup', blurb: 'SLDREG is a settings backup exported by the SolidWorks Settings Wizard - a Windows registry export of your SolidWorks preferences. Created and opened by SolidWorks.', fact: 'A .sldreg is really a plain REGEDIT4 registry file, so Analyser reads the saved SOLIDWORKS release, the settings groups and every backed-up registry key straight from the text.' },
  svap:       { name: 'SOLIDWORKS Visualize appearance', blurb: 'SVAP is an appearance (material) for SOLIDWORKS Visualize, the ray-traced rendering tool - a ZIP package holding the material definition and its textures. Created and opened by SOLIDWORKS Visualize.', fact: 'Visualize began life as Bunkspeed, a standalone product Dassault Systèmes acquired and folded into the SOLIDWORKS family.' },
  svpj:       { name: 'SOLIDWORKS Visualize project', blurb: 'SVPJ is a project file for SOLIDWORKS Visualize, bundling the scene, models, appearances and camera setup as a ZIP package. Created and opened by SOLIDWORKS Visualize.', fact: 'Visualize uses the model only as geometry - lighting, materials and cameras live in the .svpj, so the same part can be rendered many different ways.' },
  f3d:        { name: 'Fusion 360 design', blurb: 'F3D is a design file from Autodesk Fusion 360. Created and opened by Fusion 360.', fact: 'Fusion 360 launched in 2013 as a cloud-based, all-in-one CAD/CAM tool.' },
  f3z:        { name: 'Fusion 360 archive', blurb: 'F3Z is a Fusion 360 archive bundling a design with everything it references. Created by Fusion 360.', fact: 'Autodesk offers Fusion 360 free for personal hobbyist use, which has made its files a fixture of the maker and 3D-printing community.' },
  ipt:        { name: 'Inventor part', blurb: 'IPT is a single-part 3D model from Autodesk Inventor. Created and opened by Inventor.', fact: 'Autodesk launched Inventor in 1999 as its parametric mechanical-design tool.' },
  iam:        { name: 'Inventor assembly', blurb: 'IAM is an Autodesk Inventor assembly of several parts. Created and opened by Inventor.', fact: 'Inventor models its geometry with ShapeManager, Autodesk’s own kernel forked from the ACIS modeller in 2001.' },
  idw:        { name: 'Inventor drawing', blurb: 'IDW is a 2D drawing from Autodesk Inventor. Created and opened by Inventor.', fact: 'Drawings in Inventor can follow several national drafting standards, including ISO, ANSI, DIN, GOST and JIS, selectable per document.' },
  '3dm':      { name: 'Rhino 3D model', blurb: '3DM is the native model format of Rhino (Rhinoceros 3D). Created and opened by Rhino, built on the open OpenNURBS toolkit.', fact: 'Rhino’s 3DM format is based on the openly published OpenNURBS standard.' },
  skp:        { name: 'SketchUp model', blurb: 'SKP is a 3D model from SketchUp. Created and opened by SketchUp.', fact: 'SketchUp launched in 2000 and was owned by Google from 2006 to 2012.' },
  '3ds':      { name: '3D Studio model', blurb: '3DS is the legacy model format of 3D Studio, the ancestor of today’s 3ds Max. Read by Autodesk 3ds Max and many 3D tools.', fact: '3DS comes from the original DOS-based 3D Studio of the early 1990s.' },
  max:        { name: '3ds Max scene', blurb: 'MAX is the native scene format of Autodesk 3ds Max. Created and opened by 3ds Max.', fact: '3ds Max is a leading 3D tool for games and visual effects, descended from 1990s 3D Studio.' },
  c4d:        { name: 'Cinema 4D scene', blurb: 'C4D is the native scene format of Maxon Cinema 4D. Created and opened by Cinema 4D.', fact: 'Cinema 4D is especially popular in motion graphics and broadcast design.' },
  hip:        { name: 'Houdini scene', blurb: 'HIP is the scene file of SideFX Houdini, the procedural VFX tool. Created and opened by Houdini.', fact: 'Houdini’s node-based, procedural approach makes it a favourite for film visual effects.' },
  zpr:        { name: 'ZBrush project', blurb: 'ZPR is a project from ZBrush, the digital-sculpting app. Created and opened by Maxon ZBrush.', fact: 'ZBrush revolutionised digital sculpting and is used to model film and game characters.' },
  ztl:        { name: 'ZBrush tool', blurb: 'ZTL is a ZBrush tool file, holding a sculpted model. Created and opened by Maxon ZBrush.', fact: 'ZBrush made its public debut at the SIGGRAPH show in 1999, starting out as a quirky 2.5D painting program before becoming the standard for digital sculpting.' },
  ma:         { name: 'Maya scene (ASCII)', blurb: 'MA is a Maya scene saved in a readable text form. Created and opened by Autodesk Maya.', fact: 'Maya is a leading film and VFX 3D tool and has won an Academy Award for its impact.' },
  mb:         { name: 'Maya scene (binary)', blurb: 'MB is a Maya scene saved in compact binary form. Created and opened by Autodesk Maya.', fact: 'The name Maya comes from the Sanskrit word for illusion, a fitting choice for software built to conjure imaginary worlds.' },
  catpart:    { name: 'CATIA part', blurb: 'CATPART is a single-part model from CATIA. Created and opened by Dassault Systemes CATIA.', fact: 'CATIA is high-end CAD used to design aircraft and cars, including much of the Boeing 777.' },
  catproduct: { name: 'CATIA assembly', blurb: 'CATPRODUCT is a CATIA assembly of multiple parts. Created and opened by Dassault Systemes CATIA.', fact: 'Architect Frank Gehry famously adopted CATIA, originally an aerospace tool, to work out the curved titanium skin of the Guggenheim Museum Bilbao.' },
  prt:        { name: 'CAD part file', blurb: 'PRT is a part file used by several CAD systems, including Siemens NX and PTC Creo.', fact: 'Several rival CAD systems all happen to use the .prt extension for parts.' },
  asm:        { name: 'CAD assembly file', blurb: 'ASM is an assembly file used by CAD systems such as PTC Creo and Solid Edge.', fact: 'Like .prt, the .asm extension is shared by several different CAD programs.' },
  brd:        { name: 'PCB layout (EAGLE)', blurb: 'BRD is a printed-circuit-board layout, most associated with EAGLE. Created and opened by Autodesk EAGLE.', fact: 'EAGLE was a hugely popular PCB tool, especially among hobbyists, before Autodesk acquired it in 2016.' },
  sch:        { name: 'Circuit schematic', blurb: 'SCH is a circuit schematic from EAGLE or another electronics-design tool.', fact: 'A schematic captures a circuit’s wiring before it becomes a physical board layout.' },
  kicad_pcb:  { name: 'KiCad board', blurb: 'A .kicad_pcb file is a printed-circuit-board layout from KiCad. Created and opened by KiCad.', fact: 'KiCad is a free, open-source PCB suite backed by CERN, widely used in open hardware.' },
  gh:         { name: 'Grasshopper definition', blurb: 'GH is a Grasshopper visual-programming definition for Rhino. Created and opened by Grasshopper in Rhino.', fact: 'Grasshopper lets designers build geometry with visual node graphs instead of code.' },
  ghx:        { name: 'Grasshopper definition (XML)', blurb: 'GHX is the XML form of a Grasshopper definition. Created and opened by Grasshopper in Rhino.', fact: 'After a decade as a free add-on download, Grasshopper became a built-in part of Rhino with the release of Rhino 6 in 2018.' },

  // ---- CAD exchange ----
  sat: { name: 'ACIS model (SAT)', blurb: 'SAT is a solid-model exchange file from the ACIS modelling kernel. Read by many CAD programs.', fact: 'ACIS is a 3D modelling kernel from Spatial Corporation used inside many CAD tools.' },
  x_t: { name: 'Parasolid model (text)', blurb: 'X_T is a Parasolid solid-model exchange file in text form. Read by SolidWorks, Siemens NX and more.', fact: 'Parasolid is the modelling kernel behind SolidWorks, Solid Edge and Siemens NX.' },
  x_b: { name: 'Parasolid model (binary)', blurb: 'X_B is the binary form of a Parasolid solid-model exchange file. Read by SolidWorks, Siemens NX and more.', fact: 'Parasolid version 1.0 shipped in 1988, and Siemens now licenses the kernel to hundreds of other software products.' },

  // ---- 3D / printing ----
  fbx:   { name: 'FBX 3D scene', blurb: 'FBX is a widely used 3D interchange format for models, animation and scenes. Owned by Autodesk and read by most 3D and game tools.', fact: 'FBX began at Kaydara for the MotionBuilder app and is now Autodesk’s main 3D exchange format.' },
  gltf:  { name: 'glTF 3D model', blurb: 'glTF is a modern, efficient 3D model format for real-time graphics and the web.', fact: 'glTF was released by the Khronos Group in 2015 and is often called "the JPEG of 3D".' },
  glb:   { name: 'glTF binary (GLB)', blurb: 'GLB is the single-file binary version of glTF, bundling geometry, textures and animation together.', fact: 'GLB is the packaged form of glTF, the Khronos 3D format released in 2015.' },
  usdz:  { name: 'USDZ AR model', blurb: 'USDZ is Apple’s augmented-reality 3D format, opened straight from Safari and iMessage. Based on Pixar’s USD.', fact: 'Apple introduced USDZ in 2018 as the format for AR Quick Look on iPhone and iPad.' },
  usd:   { name: 'Universal Scene Description', blurb: 'USD (Universal Scene Description) is a powerful 3D scene format used across film and 3D pipelines. Created by Pixar.', fact: 'Pixar created USD for its own films and open-sourced it in 2016; it now anchors NVIDIA’s Omniverse.' },
  usda:  { name: 'USD scene (text)', blurb: 'USDA is the human-readable text form of Pixar’s USD scene format.', fact: 'In 2023 Pixar joined Adobe, Apple, Autodesk and NVIDIA to form the Alliance for OpenUSD, charged with turning the format into a formal open standard.' },
  blend: { name: 'Blender file', blurb: 'BLEND is the native file of Blender, the free 3D-creation suite. Created and opened by Blender.', fact: 'Blender first appeared in 1994 and is now the most widely used free 3D tool in the world.' },

  // ---- Archives ----
  rar: { name: 'RAR archive', blurb: 'RAR is a compressed archive format. Created by WinRAR and opened by WinRAR, 7-Zip and others.', fact: 'WinRAR’s RAR format was created by Russian developer Eugene Roshal in 1993 - the name means Roshal Archive.' },
  '7z':{ name: '7-Zip archive', blurb: '7Z is a high-compression archive format. Created and opened by the free 7-Zip tool.', fact: '7z is the native format of 7-Zip, released in 1999, and usually compresses tighter than ZIP.' },
  tar: { name: 'TAR archive', blurb: 'TAR bundles many files into one, usually before compressing with gzip or another tool. Standard on Unix and Linux.', fact: 'TAR dates back to 1979 Unix; the name is short for "tape archive".' },
  gz:  { name: 'GZip archive', blurb: 'GZ is a file compressed with gzip, common on the web and on Linux.', fact: 'GZip was created in 1992 as a free, patent-unencumbered replacement for the older Unix compress.' },
  bz2: { name: 'BZip2 archive', blurb: 'BZ2 is a file compressed with bzip2, offering tighter compression than gzip.', fact: 'BZip2 arrived in 1996 and squeezes files smaller than gzip, though more slowly.' },
  xz:  { name: 'XZ archive', blurb: 'XZ is a file compressed with the high-ratio LZMA algorithm, common for Linux packages.', fact: 'XZ was released in 2009 and uses the same LZMA compression as 7-Zip.' },
  zst: { name: 'Zstandard archive', blurb: 'ZST is a file compressed with Zstandard, prized for being fast and efficient.', fact: 'Zstandard was created by Facebook in 2016 and is now used everywhere from Linux to game engines.' },
  tgz: { name: 'Gzipped TAR archive', blurb: 'TGZ is a TAR archive compressed with gzip, the classic way to bundle files on Unix.', fact: 'TGZ simply pairs the 1979 TAR format with 1992’s gzip compression.' },

  // ---- Fonts ----
  ttf:   { name: 'TrueType font', blurb: 'TTF is the TrueType font format, used across Windows, macOS and the web.', fact: 'TrueType was developed by Apple in the late 1980s as a rival to Adobe’s Type 1 fonts.' },
  otf:   { name: 'OpenType font', blurb: 'OTF is the OpenType font format, a richer successor to TrueType.', fact: 'OpenType was created jointly by Microsoft and Adobe in 1996.' },
  woff:  { name: 'Web font (WOFF)', blurb: 'WOFF is a compressed font format made for fast loading on web pages.', fact: 'WOFF became a W3C web-font standard in 2012.' },
  woff2: { name: 'Web font (WOFF2)', blurb: 'WOFF2 is the newer web-font format, even smaller thanks to Brotli compression.', fact: 'WOFF2 became a W3C standard in 2018 and is now the default web-font format.' },
  ttc:   { name: 'TrueType collection', blurb: 'TTC bundles several related fonts into a single file, sharing common data.', fact: 'TTC collections let font families that share glyphs save space by storing them once.' },

  // ---- eBooks ----
  mobi: { name: 'Mobipocket ebook', blurb: 'MOBI is an e-book format once used by Amazon Kindle. Opened by calibre and older Kindles.', fact: 'MOBI came from Mobipocket in 2000; Amazon adopted it for the Kindle, then retired it in 2022.' },
  azw:  { name: 'Kindle ebook (AZW)', blurb: 'AZW is Amazon’s original Kindle e-book format, based on MOBI. Opened by Amazon Kindle.', fact: 'AZW arrived with the very first Amazon Kindle in 2007.' },
  azw3: { name: 'Kindle ebook (AZW3)', blurb: 'AZW3 (KF8) is the richer Kindle e-book format. Opened by Amazon Kindle.', fact: 'AZW3, also called KF8, arrived with the Kindle Fire in 2011 to allow richer formatting.' },
  fb2:  { name: 'FictionBook ebook', blurb: 'FB2 (FictionBook) is an XML-based e-book format. Opened by calibre and many readers.', fact: 'FictionBook is an open XML e-book format that became especially popular in Russia.' },
  djvu: { name: 'DjVu document', blurb: 'DjVu is a format for scanned documents and books, smaller than PDF for the same scan. Opened by DjView and others.', fact: 'DjVu, created at AT&T Labs in 1998, is read with DjView and other free viewers.' },

  // ---- Subtitles (other) ----
  sub: { name: 'SUB subtitles', blurb: 'SUB files hold subtitles, either as text (MicroDVD, SubViewer) or as bitmap images ripped from a DVD.', fact: 'The text-based MicroDVD .sub format dates from the early 2000s.' },

  // ---- Music production ----
  als:    { name: 'Ableton Live set', blurb: 'ALS is an Ableton Live project (a "set"). Created and opened by Ableton Live.', fact: 'Ableton Live launched in 2001 and reshaped electronic-music production and live performance.' },
  alp:    { name: 'Ableton Live Pack', blurb: 'ALP is an Ableton Live Pack, bundling instruments, presets and samples. Opened by Ableton Live.', fact: 'Live Packs are how Ableton and artists distribute ready-made sounds and kits.' },
  flp:    { name: 'FL Studio project', blurb: 'FLP is an FL Studio music project. Created and opened by FL Studio.', fact: 'FL Studio began life as FruityLoops in 1997 and is famous for its lifetime free updates.' },
  rpp:    { name: 'REAPER project', blurb: 'RPP is a REAPER digital-audio-workstation project. Created and opened by Cockos REAPER.', fact: 'REAPER was released by Cockos in 2006 and is known for its tiny size and low price.' },
  logic:  { name: 'Logic Pro project', blurb: 'A LOGIC file is an Apple Logic Pro music project. Created and opened by Logic Pro.', fact: 'Apple bought Logic from German company Emagic in 2002 and made it a Mac flagship.' },
  logicx: { name: 'Logic Pro X project', blurb: 'A LOGICX file is a Logic Pro X music project. Created and opened by Apple Logic Pro.', fact: 'Logic Pro X, the 2013 release that introduced this extension, was sold exclusively through the Mac App Store for 199.99 US dollars.' },
  ptx:    { name: 'Pro Tools session', blurb: 'PTX is a Pro Tools session file. Created and opened by Avid Pro Tools.', fact: 'Pro Tools is the long-standing studio standard for recording and mixing professional audio.' },
  cpr:    { name: 'Cubase project', blurb: 'CPR is a Steinberg Cubase music project. Created and opened by Cubase.', fact: 'Cubase dates back to 1989 and pioneered on-screen MIDI sequencing.' },
  band:   { name: 'GarageBand project', blurb: 'A BAND file is a GarageBand music project. Created and opened by Apple GarageBand.', fact: 'GarageBand launched in 2004 and put music recording into the hands of everyday Mac users.' },

  // ---- Databases ----
  sqlite:  { name: 'SQLite database', blurb: 'SQLite is a complete database stored in a single file. Used inside countless apps, phones and browsers.', fact: 'SQLite was created by D. Richard Hipp in 2000 and is the most widely deployed database in the world.' },
  sqlite3: { name: 'SQLite database', blurb: 'A .sqlite3 file is a SQLite database in a single file. Used inside countless apps and devices.', fact: 'The 3 in the extension refers to SQLite’s version 3 file format, introduced in 2004 and kept backwards compatible ever since.' },
  db:      { name: 'Database file', blurb: 'A .db file usually holds a SQLite database, the engine built into nearly every device.', fact: 'SQLite’s developers have publicly pledged to keep the file format supported and cross-compatible through to the year 2050.' },
  db3:     { name: 'SQLite database', blurb: 'A .db3 file is typically a SQLite database in a single file.', fact: 'SQLite even flies - Airbus uses it in the flight software of the A350 airliner, where the code is tested to aviation-grade standards.' },
  mdb:     { name: 'Access database (legacy)', blurb: 'MDB is the classic Microsoft Access database format. Created and opened by Microsoft Access.', fact: 'MDB was Access’s format from its 1992 debut until ACCDB replaced it in 2007.' },
  accdb:   { name: 'Access database', blurb: 'ACCDB is the modern Microsoft Access database format. Created and opened by Microsoft Access.', fact: 'ACCDB replaced the older MDB format in Access 2007.' },
  sql:     { name: 'SQL script', blurb: 'A .sql file is a plain-text set of database commands, used to back up or rebuild a database.', fact: 'SQL, the query language these files use, was created at IBM in the 1970s.' },

  // ---- GIS / mapping ----
  shp: { name: 'Shapefile', blurb: 'SHP (Shapefile) is the most common GIS vector format, storing map features. Created by Esri and read by every GIS tool.', fact: 'Esri created the Shapefile in the early 1990s and it remains the de-facto GIS exchange format.' },
  kmz: { name: 'Zipped Google Earth', blurb: 'KMZ is a zipped KML file, the format Google Earth uses for places and overlays. Opened by Google Earth.', fact: 'KMZ packs a KML map and its images into one zipped bundle for Google Earth.' },

  // ---- Disk images ----
  iso:   { name: 'ISO disc image', blurb: 'An ISO is an exact image of an optical disc, used to burn or mount CDs and DVDs.', fact: 'ISO files are named after the ISO 9660 CD filesystem standard from 1988.' },
  img:   { name: 'Raw disk image', blurb: 'IMG is a raw, sector-by-sector copy of a disk, card or floppy. Written by tools like dd and Win32 Disk Imager.', fact: 'An IMG is a bit-for-bit copy, so it can recreate a drive exactly, partitions and all.' },
  vhd:   { name: 'Virtual hard disk', blurb: 'VHD is a Microsoft virtual hard disk used by virtual machines. Created by Hyper-V and Virtual PC.', fact: 'VHD came from Connectix Virtual PC, which Microsoft acquired in 2003.' },
  vhdx:  { name: 'Virtual hard disk (VHDX)', blurb: 'VHDX is Microsoft’s newer virtual hard disk, supporting much larger sizes. Created by Hyper-V.', fact: 'VHDX is the Hyper-V virtual-disk format introduced with Windows Server 2012, supporting far larger disks than VHD.' },
  vmdk:  { name: 'VMware virtual disk', blurb: 'VMDK is VMware’s virtual hard disk format. Created and opened by VMware.', fact: 'VMDK is the virtual-disk format of VMware, the company that popularised x86 virtualisation.' },
  qcow2: { name: 'QEMU virtual disk', blurb: 'QCOW2 is the copy-on-write virtual disk used by QEMU and KVM. Created by QEMU.', fact: 'QCOW2 is QEMU’s disk format, storing space only as it is used and supporting snapshots.' },
  vdi:   { name: 'VirtualBox disk', blurb: 'VDI is the native virtual-disk format of Oracle VirtualBox. Created and opened by VirtualBox.', fact: 'VDI is the disk format for VirtualBox, the popular free virtualisation tool.' },

  // ---- Recordings ----
  rec: { name: 'Recording / session file', blurb: 'A .rec file may be a PVR/DVR TV recording or a data-recovery session file - Analyser tells them apart.', fact: 'The .rec extension is reused by set-top-box recorders and by recovery tools like GetDataBack.' },

  // ---- Game engines ----
  godot:        { name: 'Godot project', blurb: 'A Godot file is part of a project for the Godot game engine. Created and opened by Godot.', fact: 'Godot is a free, open-source game engine first released publicly in 2014.' },
  tscn:         { name: 'Godot scene', blurb: 'TSCN is a Godot scene saved in a readable text form. Created and opened by Godot.', fact: 'Godot’s text scene files are designed to work cleanly with version control like Git.' },
  tres:         { name: 'Godot resource', blurb: 'TRES is a Godot resource file, such as a material or animation. Created and opened by Godot.', fact: 'Nearly everything in Godot - materials, animations, shaders, even scripts - is a Resource, saveable as readable text in a .tres or as compact binary in a .res.' },
  unitypackage: { name: 'Unity package', blurb: 'A .unitypackage bundles assets for the Unity game engine. Created and opened by Unity.', fact: 'Unity launched in 2005 and became the engine behind a huge share of mobile and indie games.' },
  uasset:       { name: 'Unreal Engine asset', blurb: 'UASSET is an asset for Unreal Engine, such as a mesh, texture or material. Created and opened by Unreal Engine.', fact: 'Unreal Engine dates back to the 1998 game Unreal and now powers games, film and architecture.' },
  umap:         { name: 'Unreal Engine map', blurb: 'UMAP is an Unreal Engine level (map) file. Created and opened by Unreal Engine.', fact: 'In classic Unreal Tournament a map’s filename declared its game mode, with prefixes such as DM- for Deathmatch and CTF- for Capture the Flag.' },

  // ---- Game saves ----
  bepis: { name: 'ULTRAKILL save', blurb: 'BEPIS is a save file from the game ULTRAKILL, storing your progress as a .NET BinaryFormatter stream. Analyser decodes it into your money, weapons, level and difficulty progress, per-level ranks and Cyber Grind high score.', fact: 'ULTRAKILL, released in 2020, gives its save files the joke extension .bepis.' },

  // ---- Valve / Steam ----
  vdf: { name: 'Valve KeyValues', blurb: 'VDF is Valve’s KeyValues text format, used throughout Steam and Source-engine games. Read by Steam.', fact: 'VDF files store everything from Steam settings to Source-engine game data.' },
  acf: { name: 'Steam app manifest', blurb: 'ACF is a Steam manifest tracking an installed game - its App ID, name and size. Created by Steam.', fact: 'Steam writes an ACF manifest for every game so it knows what is installed and up to date.' },

  // ---- Config ----
  toml:       { name: 'TOML config', blurb: 'TOML is a clear, minimal configuration-file format popular in modern software, especially Rust.', fact: 'TOML was created in 2013 by GitHub co-founder Tom Preston-Werner - the name means "Tom’s Obvious, Minimal Language".' },
  ini:        { name: 'INI config', blurb: 'INI is a simple key-and-section settings file, long used on Windows.', fact: 'The INI file goes back to early Windows in the 1980s as its original settings format.' },
  env:        { name: 'Environment file', blurb: 'A .env file stores environment variables and secrets for an application.', fact: '.env files were popularised by the Twelve-Factor App method for keeping config out of code.' },
  conf:       { name: 'Config file', blurb: 'A .conf file holds plain-text settings, common on Unix and Linux servers.', fact: 'Many classic services, from Apache to SSH, keep their settings in .conf files.' },
  cfg:        { name: 'Config file', blurb: 'A .cfg file stores configuration settings for all kinds of programs and games.', fact: 'The .cfg extension is used everywhere from games to system tools for saved settings.' },
  properties: { name: 'Java properties', blurb: 'A .properties file stores key-value settings, mainly in Java applications.', fact: 'Java has used .properties files for configuration and translations since the 1990s.' },

  // ---- Executables ----
  exe:      { name: 'Windows program', blurb: 'EXE is a Windows executable program. Run on Microsoft Windows.', fact: 'The EXE format traces back to MS-DOS in 1981 and is still how Windows programs launch.' },
  dll:      { name: 'Windows library', blurb: 'DLL is a Windows dynamic-link library, holding shared code used by programs. Used by Windows.', fact: 'DLLs let many Windows programs share the same code, a design dating to the first Windows in 1985.' },
  msi:      { name: 'Windows installer', blurb: 'MSI is a Windows Installer package used to install software. Run by Windows Installer.', fact: 'The MSI format was introduced with Microsoft Office 2000 as a standard way to install software.' },
  apk:      { name: 'Android app', blurb: 'APK is the Android application package used to install apps. Installed on Android.', fact: 'APK is Android’s app package; Android first launched in 2008.' },
  ipa:      { name: 'iOS app', blurb: 'IPA is the iOS application package. Installed on Apple iPhone and iPad.', fact: 'IPA packages have delivered iPhone apps since the App Store opened in 2008.' },
  dmg:      { name: 'macOS disk image', blurb: 'DMG is a macOS disk image, the usual way Mac apps are downloaded and installed. Opened on macOS.', fact: 'A DMG mounts like a virtual disk, which is why Mac apps so often arrive as one.' },
  appimage: { name: 'Linux AppImage', blurb: 'AppImage packs a Linux application into a single runnable file needing no installation. Run on Linux.', fact: 'AppImage lets one file run across many Linux distributions without being installed.' },

  // ---- Video editing ----
  veg: { name: 'VEGAS Pro project', blurb: 'VEG is a project from VEGAS Pro, a video editor. Created and opened by VEGAS Pro (now from MAGIX).', fact: 'VEGAS Pro began at Sonic Foundry, then passed to Sony and now MAGIX.' },
  vf:  { name: 'VEGAS project', blurb: 'VF is a project file used by VEGAS Pro. Created and opened by VEGAS Pro.', fact: 'The .vf extension is short for Vegas Film and belongs to VEGAS Movie Studio, the consumer edition - VEGAS Pro can open its projects, but Movie Studio cannot open .veg files in return.' },
  drp: { name: 'DaVinci Resolve project', blurb: 'DRP is a project from DaVinci Resolve, the pro editing and colour-grading suite. Created by Blackmagic Design.', fact: 'DaVinci Resolve grew from a high-end colour-grading system into a full editor that Blackmagic offers free.' },
  drt: { name: 'DaVinci Resolve timeline', blurb: 'DRT is a timeline exported from DaVinci Resolve. Created and opened by DaVinci Resolve.', fact: 'Two of Resolve’s built-in pages began as entirely separate products: Blackmagic bought the Fusion VFX tool from eyeon in 2014 and audio specialist Fairlight in 2016, then folded both into Resolve.' },
  wfp: { name: 'Filmora project', blurb: 'WFP is a project from Wondershare Filmora, a consumer video editor. Created and opened by Filmora.', fact: 'Filmora is aimed at everyday creators who want easy editing without a steep learning curve.' },
  wsp: { name: 'Filmora project', blurb: 'WSP is a project file used by Wondershare Filmora. Created and opened by Filmora.', fact: 'Filmora started out in 2012 as Wondershare Video Editor, and the software only took the Filmora name in a 2015 rebrand, after a brief earlier spell under the name Vivideo.' },

  // ---- CNC / 3D print ----
  gcode: { name: 'G-code', blurb: 'G-code is the instruction language that tells 3D printers and CNC machines how to move. Produced by slicers like Cura and PrusaSlicer.', fact: 'G-code dates back to the 1950s, when it was created at MIT for the first numerically controlled machine tools.' },
  gco:   { name: 'G-code', blurb: 'A .gco file is G-code for a 3D printer or CNC machine. Produced by slicers like Cura and PrusaSlicer.', fact: 'The clipped .gco name exists because many 3D-printer firmwares read SD cards using DOS-style 8.3 filenames, leaving room for only three letters after the dot.' },
  nc:    { name: 'CNC G-code', blurb: 'NC files hold G-code for CNC machines - the name stands for Numerical Control. Produced by CAM software.', fact: '"NC" means Numerical Control, the 1950s technology that G-code grew out of.' },
  ngc:   { name: 'LinuxCNC G-code', blurb: 'NGC is the G-code dialect used by the open-source LinuxCNC controller. Run by LinuxCNC.', fact: 'NGC files target LinuxCNC, a free controller that turns a PC into a CNC machine brain.' },
  tap:   { name: 'CNC G-code (TAP)', blurb: 'TAP files hold CNC G-code, a nod to the old paper-tape programs machines once read.', fact: 'The .tap name recalls the punched paper tape that fed early CNC machines.' },
  cnc:   { name: 'CNC program', blurb: 'A .cnc file holds machine instructions for a CNC mill, router or cutter. Produced by CAM software.', fact: 'CNC stands for Computer Numerical Control, the technology behind automated machining.' },

  // ---- Surround audio ----
  ec3:    { name: 'Dolby Digital Plus', blurb: 'EC3 holds Dolby Digital Plus (E-AC-3) surround audio, used by streaming and Blu-ray.', fact: 'Dolby Digital Plus made its disc debut on HD DVD, where it was a mandatory codec, appearing on launch titles such as Serenity in April 2006.' },
  eac3:   { name: 'Dolby Digital Plus', blurb: 'EAC3 holds Dolby Digital Plus (E-AC-3) surround audio, used by streaming and Blu-ray.', fact: 'Dolby Digital Plus extends the older Dolby Digital with more channels and higher quality for streaming.' },
  truehd: { name: 'Dolby TrueHD', blurb: 'TrueHD holds Dolby’s lossless surround audio, used on Blu-ray discs.', fact: 'Dolby TrueHD launched around 2006 as a lossless surround format for high-definition discs.' },
  thd:    { name: 'Dolby TrueHD', blurb: 'THD holds Dolby TrueHD lossless surround audio, used on Blu-ray.', fact: 'A TrueHD stream on Blu-ray can peak at 18 Mbit/s, dozens of times the bitrate of a typical lossy Dolby Digital track.' },
  mlp:    { name: 'Meridian Lossless Packing', blurb: 'MLP (Meridian Lossless Packing) is the lossless audio technology behind Dolby TrueHD.', fact: 'MLP was first used on DVD-Audio discs and later became the basis of Dolby TrueHD.' },
  atmos:  { name: 'Dolby Atmos', blurb: 'An Atmos file carries Dolby Atmos object-based surround sound, with height channels.', fact: 'Dolby Atmos debuted in cinemas in 2012, adding overhead channels for truly 3D sound.' },

  // ---- Certificates ----
  crt: { name: 'X.509 certificate', blurb: 'CRT holds an X.509 security certificate, used to prove identity and secure HTTPS.', fact: 'X.509, the certificate standard behind HTTPS, was first published in 1988.' },
  cer: { name: 'X.509 certificate', blurb: 'CER holds an X.509 security certificate, used to prove identity and secure connections.', fact: 'Windows treats .cer as its house extension for certificates - double-clicking one opens the built-in certificate viewer with its Install Certificate button, and the Certificate Export Wizard saves to .cer by default.' },
  pem: { name: 'PEM certificate / key', blurb: 'PEM is a text encoding for certificates and keys, recognisable by its BEGIN/END lines.', fact: 'PEM is named after Privacy-Enhanced Mail, a 1990s secure-email standard whose encoding outlived it.' },
  der: { name: 'DER certificate', blurb: 'DER is the binary encoding of an X.509 certificate or key.', fact: 'DER is the strict binary form of the same X.509 certificates that PEM stores as text.' },

  // ---- Engineering ----
  cdp: { name: 'CDP model file', blurb: 'CDP is shared by two unrelated tools: a CDP4 concurrent-design model from the COMET systems-engineering platform used by the European Space Agency, or a decision-analysis model from Criterium DecisionPlus.', fact: 'Criterium DecisionPlus, by InfoHarvest, saves its decision models as .cdp and ranks options using methods such as the Analytic Hierarchy Process (AHP) and SMART.' },

  // ---- Logs ----
  log: { name: 'Log file', blurb: 'A .log file is a plain-text record an application writes as it runs, used for troubleshooting.', fact: 'Log files are how almost every program leaves a trail of what it did and when.' },

  // ---- Camera catalog ----
  ctg: { name: 'Canon camera catalog', blurb: 'CTG is the catalog index a Canon camera keeps of the photos and videos in each folder. Holds no image data.', fact: 'A Canon camera writes a CTG to keep track of how many shots are in each DCIM folder.' },

  // ---- Shortcuts ----
  lnk:    { name: 'Windows shortcut', blurb: 'LNK is a Windows shortcut pointing to a program or file. Created and opened by Windows.', fact: 'Shortcuts have been part of Windows since Windows 95 in 1995, and quietly record the target’s details.' },
  url:    { name: 'Internet shortcut', blurb: 'A .url file is a saved internet shortcut that opens a web page. Created and opened by Windows.', fact: 'A .url file is a tiny text shortcut Windows uses to hold the address of a web page.' },
  webloc: { name: 'macOS web shortcut', blurb: 'WEBLOC is the macOS equivalent of a saved web link, dragged from a browser. Opened on macOS.', fact: 'WEBLOC is how macOS saves a web link as a file you can keep on your desktop.' },

  // ---- Other ----
  torrent:    { name: 'BitTorrent file', blurb: 'A .torrent file holds the information BitTorrent needs to download a file from many peers. Opened by clients like qBittorrent.', fact: 'BitTorrent launched in 2001 and the small .torrent file describes what to download, not the data itself.' },
  part:       { name: 'Partial download', blurb: 'A .part file is an unfinished download, renamed once it completes. Created by Firefox and other apps.', fact: 'Firefox and other browsers add the .part suffix while a download is still in progress.' },
  crdownload: { name: 'Chrome partial download', blurb: 'A .crdownload file is an in-progress download created by Google Chrome.', fact: 'Chrome adds the .crdownload suffix while a file downloads, removing it once finished.' },

  // ==========================================================================
  // Long-tail identification-only formats (catalog IDENTIFICATION_EXTENDED).
  // Added in groups; new groups are inserted above the EXT_PAGES_END marker.
  // ==========================================================================

  // ---- Developer / data ----
  jwt:          { name: 'JSON Web Token', blurb: 'A JWT (JSON Web Token) carries signed identity claims, widely used to log in to web APIs.', fact: 'The JWT standard was published as RFC 7519 in 2015 and is now a default for stateless web logins.' },
  har:          { name: 'HTTP Archive', blurb: 'HAR records a browser session’s network requests for debugging. Saved by browser developer tools.', fact: 'The HAR format was developed around 2007 to share web-performance traces between tools.', factApprox: true },
  ipynb:        { name: 'Jupyter Notebook', blurb: 'IPYNB is a Jupyter Notebook, mixing live code, results and notes. Created and opened by Jupyter.', fact: 'The notebook grew out of IPython and took the Jupyter name when Project Jupyter launched in 2014.' },
  jsonl:        { name: 'JSON Lines', blurb: 'JSONL stores one JSON object per line, handy for streaming and large datasets.', fact: 'JSON Lines became popular in the 2010s for log files and data pipelines.' },
  ndjson:       { name: 'Newline-delimited JSON', blurb: 'NDJSON stores one JSON record per line, used for streaming data.', fact: 'Elasticsearch’s bulk API is one of the format’s best-known users, requiring every command and document to sit on its own newline-terminated line.' },
  diff:         { name: 'Diff file', blurb: 'A diff lists the changes between two versions of text. Applied with the patch tool, central to coding.', fact: 'The Unix diff tool was created at Bell Labs in 1974.' },
  patch:        { name: 'Patch file', blurb: 'A patch file records text changes to apply to source code. Used across software development.', fact: 'The patch tool, written by Larry Wall in 1985, let programmers share fixes as small text files.' },
  wasm:         { name: 'WebAssembly', blurb: 'WASM (WebAssembly) is a fast, compiled binary format that runs inside web browsers.', fact: 'WebAssembly reached all major browsers in 2017, letting languages like C++ and Rust run on the web.' },
  class:        { name: 'Java class file', blurb: 'CLASS is compiled Java bytecode, run by the Java Virtual Machine.', fact: 'Java bytecode dates from Java’s 1995 launch and runs unchanged on any device with a JVM.' },
  npy:          { name: 'NumPy array', blurb: 'NPY stores a NumPy array, the core data type of Python’s scientific stack.', fact: 'The .npy format was designed to save NumPy arrays to disk efficiently.' },
  safetensors:  { name: 'Safetensors weights', blurb: 'Safetensors stores AI model weights safely and quickly. Created by Hugging Face.', fact: 'Hugging Face introduced Safetensors in 2022 to load model weights fast and avoid the security risks of Python pickles.' },
  gguf:         { name: 'GGUF model', blurb: 'GGUF stores quantised large-language-model weights for local inference. Used by llama.cpp.', fact: 'GGUF was introduced in 2023 by the llama.cpp project to run language models on ordinary computers.' },
  map:          { name: 'Source map', blurb: 'A .map file links minified web code back to its readable source for debugging.', fact: 'Source maps let browser dev tools show original code even when a site ships minified files.' },
  sln:          { name: 'Visual Studio solution', blurb: 'SLN is a Microsoft Visual Studio solution grouping related projects. Opened by Visual Studio.', fact: 'The .sln file ties together all the projects that make up a Visual Studio solution.' },
  csproj:       { name: 'C# project', blurb: 'CSPROJ is a C# project file for Visual Studio and the .NET build system.', fact: 'A .csproj lists the files, settings and dependencies the .NET build needs.' },
  vbproj:       { name: 'Visual Basic project', blurb: 'VBPROJ is a Visual Basic .NET project file for Visual Studio.', fact: 'A .vbproj is the Visual Basic counterpart of the C# .csproj project file.' },
  fsproj:       { name: 'F# project', blurb: 'FSPROJ is an F# project file for Visual Studio and .NET.', fact: 'A .fsproj is the F# counterpart of the .NET project file.' },
  vcxproj:      { name: 'C++ project', blurb: 'VCXPROJ is a Visual C++ project file for Visual Studio.', fact: 'VCXPROJ replaced the older .vcproj format in Visual Studio 2010.' },
  gradle:       { name: 'Gradle build script', blurb: 'A .gradle file is a build script for Gradle, the build tool behind most Android apps.', fact: 'Gradle is the official build system for Android development.' },
  tf:           { name: 'Terraform config', blurb: 'TF is a Terraform configuration describing cloud infrastructure as code. Created by HashiCorp.', fact: 'Terraform, released by HashiCorp in 2014, popularised managing servers as version-controlled code.' },
  tfstate:      { name: 'Terraform state', blurb: 'TFState records the real cloud resources Terraform is managing, as JSON.', fact: 'Terraform keeps a state file mapping your config to the resources it actually created.' },
  editorconfig: { name: 'EditorConfig', blurb: 'An .editorconfig file sets consistent coding styles across different editors and IDEs.', fact: 'EditorConfig, adopted around 2012, lets a whole team’s editors agree on indentation and spacing.' },
  proto:        { name: 'Protocol Buffers schema', blurb: 'A .proto file defines Protocol Buffers data structures. Created by Google.', fact: 'Google built Protocol Buffers internally in the early 2000s and open-sourced them in 2008.' },
  graphql:      { name: 'GraphQL schema', blurb: 'A GraphQL file defines an API’s query schema. Created by Facebook.', fact: 'Facebook developed GraphQL internally in 2012 and released it publicly in 2015.' },
  gql:          { name: 'GraphQL schema', blurb: 'GQL is a GraphQL schema or query file. Used with GraphQL APIs.', fact: 'Lee Byron, Nick Schrock and Dan Schafer, three Facebook engineers, are credited as GraphQL’s co-creators.' },
  sarif:        { name: 'SARIF results', blurb: 'SARIF is a standard JSON format for static-analysis and code-scanning results.', fact: 'SARIF was standardised by OASIS in 2020 so security tools can share their findings.' },
  pyc:          { name: 'Python bytecode', blurb: 'PYC is compiled Python bytecode, cached to make programs start faster.', fact: 'Python writes .pyc files so it doesn’t have to recompile your source on every run.' },
  plist:        { name: 'Property list', blurb: 'A property list (plist) stores settings and data on macOS and iOS, as XML or binary.', fact: 'Property lists have held Apple app preferences since the NeXTSTEP days of the late 1980s.' },

  // ---- RAW sidecars / cinema ----
  aae:  { name: 'Apple Photos edit', blurb: 'AAE is an Apple Photos edit sidecar, recording adjustments without altering the original. Created by Apple Photos.', fact: 'An AAE file lets Apple Photos keep your edits separate so the original photo stays untouched.' },
  pp3:  { name: 'RawTherapee sidecar', blurb: 'PP3 holds the develop recipe RawTherapee applies to a raw photo. Created by RawTherapee.', fact: 'RawTherapee is a free, open-source raw photo developer.' },
  cos:  { name: 'Capture One settings', blurb: 'COS stores Capture One edit settings for a raw photo. Created by Capture One.', fact: 'Capture One is a professional raw editor favoured in studio and fashion photography.' },
  cof:  { name: 'Capture One settings', blurb: 'COF is a Capture One settings file accompanying a raw photo. Created by Capture One.', fact: 'Capture One comes from Phase One, the Danish maker of medium-format cameras, and began life as companion software for its high-end digital backs.' },
  cop:  { name: 'Capture One settings', blurb: 'COP is a Capture One settings file accompanying a raw photo. Created by Capture One.', fact: 'For years Capture One shipped special brand-specific editions for Sony, Fujifilm and Nikon cameras, before retiring them between 2022 and 2024.' },
  dop:  { name: 'DxO PhotoLab sidecar', blurb: 'DOP is a DxO PhotoLab edit sidecar for a raw photo. Created by DxO PhotoLab.', fact: 'DxO PhotoLab is known for its strong lens corrections and noise reduction.' },
  nksc: { name: 'Nikon NX Studio sidecar', blurb: 'NKSC is a Nikon NX Studio edit sidecar for a raw photo. Created by Nikon NX Studio.', fact: 'Nikon’s NX Studio stores its raw adjustments in NKSC sidecar files.' },
  r3d:  { name: 'REDCODE raw video', blurb: 'R3D is REDCODE raw cinema footage from RED digital cinema cameras.', fact: 'RED’s R3D format brought raw video to digital cinema cameras in the mid-2000s.' },
  braw: { name: 'Blackmagic RAW', blurb: 'BRAW is Blackmagic RAW cinema footage. Created by Blackmagic Design cameras.', fact: 'Blackmagic RAW launched in 2018 as an efficient raw codec for Blackmagic cinema cameras.' },
  crm:  { name: 'Canon Cinema RAW Light', blurb: 'CRM is Canon Cinema RAW Light video. Recorded by Canon cinema and mirrorless cameras.', fact: 'Cinema RAW Light lets Canon cameras record raw video at manageable file sizes.' },
  ari:  { name: 'ARRIRAW frame', blurb: 'ARI is an ARRIRAW frame from ARRI digital cinema cameras.', fact: 'ARRI’s Alexa cameras and ARRIRAW are a mainstay of Hollywood production.' },
  cine: { name: 'Phantom high-speed video', blurb: 'CINE is footage from Vision Research Phantom high-speed cameras.', fact: 'Phantom cameras shoot the ultra-slow-motion footage seen in films and sports broadcasts.' },
  fpf:  { name: 'FLIR thermal image', blurb: 'FPF is a FLIR thermal-imaging file, storing temperature data as an image.', fact: 'FLIR thermal cameras record per-pixel temperatures, not just colours.' },
  eip:  { name: 'Capture One package', blurb: 'EIP is a Capture One Enhanced Image Package bundling a raw file with its edits. Created by Capture One.', fact: 'An EIP keeps a raw photo and its Capture One adjustments together in one file.' },
  bay:  { name: 'Casio raw photo', blurb: 'BAY is a camera raw photo format associated with Casio cameras.', fact: 'BAY holds the unprocessed Bayer-sensor data from certain cameras.' },
  pxn:  { name: 'Logitech raw photo', blurb: 'PXN is a raw photo format from certain Logitech and webcam-style cameras.', fact: 'PXN is an uncommon raw format from a handful of older cameras.' },
  rwz:  { name: 'Rawzor raw photo', blurb: 'RWZ is a camera raw photo compressed by the Rawzor tool.', fact: 'Rawzor losslessly compressed camera raw files to save storage space.' },

  // ---- Archives (packages) ----
  lz4:    { name: 'LZ4 stream', blurb: 'LZ4 is an extremely fast compression format, used where speed matters more than ratio. Analyser decompresses it in the browser so you can open the file inside.', fact: 'LZ4, released in 2011, powers fast compression in databases, filesystems and game engines.' },
  lzma:   { name: 'LZMA stream', blurb: 'LZMA is a high-ratio compression format, the algorithm behind 7-Zip and XZ. Analyser decompresses the legacy .lzma stream in the browser so you can open the file inside.', fact: 'LZMA was developed by Igor Pavlov for 7-Zip in the late 1990s.' },
  z:      { name: 'compress (.Z) archive', blurb: 'Z is a file squeezed with classic Unix compress, the LZW tool that predates gzip. Analyser decompresses it in the browser so you can open the file inside.', fact: 'Unix compress and its .Z files date to 1984; patent worries over its LZW algorithm spurred the creation of gzip.' },
  z:      { name: 'Unix compress', blurb: 'A .Z file is compressed with the classic Unix compress tool.', fact: 'Unix compress and its .Z files date from 1984 but were largely replaced by gzip.' },
  cpio:   { name: 'cpio archive', blurb: 'CPIO is a Unix archive stream, used in Linux boot images and RPM packages.', fact: 'cpio is one of the oldest Unix archivers and still lives inside Linux initramfs images.' },
  a:      { name: 'Static library (ar)', blurb: 'A .a file is a Unix static library - an ar archive of compiled object files.', fact: 'The ar archiver is among the oldest Unix tools, used to bundle compiled code into libraries.' },
  whl:    { name: 'Python wheel', blurb: 'WHL is a Python wheel, a ready-to-install package. Installed with pip.', fact: 'The wheel format, standardised in 2012, made installing Python packages much faster.' },
  nupkg:  { name: 'NuGet package', blurb: 'NUPKG is a NuGet package for .NET libraries. Used by Visual Studio.', fact: 'NuGet is Microsoft’s package manager for .NET, launched in 2010.' },
  crx:    { name: 'Chrome extension', blurb: 'CRX is a packaged Google Chrome extension. Installed in Chrome.', fact: 'CRX is how Chrome extensions are bundled and signed for the Web Store.' },
  xpi:    { name: 'Firefox add-on', blurb: 'XPI is a packaged Firefox or Mozilla extension. Installed in Firefox.', fact: 'XPI ("cross-platform install") bundles date back to Netscape and the Mozilla Suite, predating Firefox.' },
  vsix:   { name: 'Visual Studio extension', blurb: 'VSIX is a Visual Studio or VS Code extension package. Created by Microsoft.', fact: 'VSIX bundles an extension for installation into Visual Studio or VS Code.' },
  asar:   { name: 'Electron archive', blurb: 'ASAR is an Electron app archive bundling a desktop app’s web code.', fact: 'Electron uses ASAR archives to pack the code behind apps like Slack and VS Code.' },
  appx:   { name: 'Windows app package', blurb: 'APPX is a modern Windows app package from the Microsoft Store.', fact: 'APPX arrived with Windows 8 in 2012 as the package format for Store apps.' },
  msix:   { name: 'Windows app package (MSIX)', blurb: 'MSIX is the modern Windows app-installer package. Used by the Microsoft Store.', fact: 'MSIX, introduced in 2018, is Microsoft’s modern successor to APPX and MSI.' },
  apkg:   { name: 'Anki deck', blurb: 'APKG is an Anki flashcard deck. Opened by the Anki study app.', fact: 'Anki is a popular spaced-repetition flashcard app, and an APKG bundles a shareable deck.' },
  conda:  { name: 'Conda package', blurb: 'CONDA is a package for the conda environment manager, common in data science.', fact: 'Conda packages scientific Python and other tools together with all their dependencies.' },
  deb:    { name: 'Debian package', blurb: 'DEB is a Debian or Ubuntu software package. Installed with apt or dpkg.', fact: 'The .deb package has been the heart of Debian Linux since 1993.' },
  rpm:    { name: 'RPM package', blurb: 'RPM is a Red Hat or Fedora software package. Installed with rpm or dnf.', fact: 'RPM (Red Hat Package Manager) dates from 1997 and is used across Red Hat-family Linux.' },
  gem:    { name: 'RubyGem', blurb: 'GEM is a RubyGems package for the Ruby programming language.', fact: 'RubyGems became Ruby’s standard package system in the mid-2000s.' },
  cab:    { name: 'Windows Cabinet', blurb: 'CAB is a Microsoft Cabinet archive, used inside Windows installers and updates.', fact: 'Microsoft’s CAB format has bundled Windows installation files since the early 1990s.' },
  ace:    { name: 'ACE archive', blurb: 'ACE is a compressed archive from the WinACE tool, once a WinRAR rival.', fact: 'ACE was popular in the late 1990s but faded after serious security flaws were found.' },
  arj:    { name: 'ARJ archive', blurb: 'ARJ is a DOS-era compressed archive format.', fact: 'ARJ ("Archived by Robert Jung") was a popular DOS archiver in the early 1990s.' },
  lzh:    { name: 'LHA archive', blurb: 'LZH is an archive from the LHarc/LHA tool, especially popular in Japan.', fact: 'LHA was a dominant archiver in 1990s Japan, used on the Amiga and PC.' },
  lha:    { name: 'LHA archive', blurb: 'LHA is a compressed archive from the LHarc tool, especially popular in Japan.', fact: 'The tool behind .lha was briefly called just LH, but was renamed LHA when MS-DOS 5.0 arrived with a built-in LH (load high) command of the same name.' },
  zoo:    { name: 'Zoo archive', blurb: 'ZOO is an early cross-platform compressed archive format.', fact: 'The Zoo archiver was used in the late 1980s before ZIP took over.' },
  arc:    { name: 'ARC archive', blurb: 'ARC is one of the earliest PC archive formats.', fact: 'ARC, from the mid-1980s, sparked an early-PC legal fight that helped give rise to PKZIP.' },

  // ---- Email / calendar / contacts ----
  eml:     { name: 'Email message', blurb: 'EML is a single saved email message. Opened by Outlook, Thunderbird and Apple Mail.', fact: 'EML stores a single email in the layout defined for internet mail in 1982, and opens in Outlook, Thunderbird and Apple Mail.' },
  emlx:    { name: 'Apple Mail message', blurb: 'EMLX is the single-message format used by Apple Mail.', fact: 'Apple Mail saves each message it stores as an individual EMLX file.' },
  mbox:    { name: 'Mailbox file', blurb: 'MBOX stores many emails in one file - the classic Unix mailbox format.', fact: 'The mbox mailbox format goes back to early Unix mail in the 1970s.' },
  ics:     { name: 'iCalendar event', blurb: 'ICS is an iCalendar event or calendar. Opened by Google Calendar, Outlook and Apple Calendar.', fact: 'iCalendar (RFC 5545) is the standard behind the calendar invites apps send each other.' },
  ical:    { name: 'iCalendar event', blurb: 'ICAL is an iCalendar event or calendar file. Opened by most calendar apps.', fact: 'Apple’s Mac calendar app was named iCal from 2002 until 2012, a name licensed from Brown Bear Software, which had been using it since 1997.' },
  ifb:     { name: 'iCalendar free/busy', blurb: 'IFB is an iCalendar free/busy file, sharing when someone is available.', fact: 'Free/busy files let calendars show availability without revealing event details.' },
  vcf:     { name: 'vCard contact', blurb: 'VCF (vCard) is an electronic contact card. Opened by phones and address books.', fact: 'The vCard format, from 1995, is how contacts are shared between phones and apps.' },
  vcard:   { name: 'vCard contact', blurb: 'A vCard is an electronic contact card. Opened by phones and address books.', fact: 'Many paper business cards now carry a vCard packed into a QR code, letting a phone camera capture the contact details in one scan.' },
  vcs:     { name: 'vCalendar event', blurb: 'VCS is an older vCalendar event file, the predecessor of iCalendar.', fact: 'vCalendar came first in 1996 and was soon succeeded by today’s iCalendar.' },
  ldif:    { name: 'LDAP data export', blurb: 'LDIF is a text export of an LDAP directory of users or contacts.', fact: 'LDIF is the standard text format for moving entries in and out of LDAP directories.' },
  contact: { name: 'Windows contact', blurb: 'A .contact file is a Windows Contacts card.', fact: 'Windows Contacts stored each person as an XML .contact file in Windows Vista and 7.' },
  msg:     { name: 'Outlook message', blurb: 'MSG is a saved Outlook email or appointment, attachments and all. Created by Microsoft Outlook.', fact: 'An MSG file preserves a complete Outlook item outside the mailbox.' },
  pst:     { name: 'Outlook data file', blurb: 'PST is a Microsoft Outlook data file storing a whole mailbox. Created by Outlook.', fact: 'An Outlook PST can hold years of mail, contacts and calendar in a single file.' },
  ost:     { name: 'Outlook offline cache', blurb: 'OST is an offline cache of a Microsoft Outlook mailbox.', fact: 'An OST keeps a local copy of your mailbox so Outlook works without a connection.' },
  nsf:     { name: 'HCL Notes database', blurb: 'NSF is an IBM/HCL Notes database, often holding email.', fact: 'NSF is the database behind Lotus Notes, now HCL Notes, used in many large companies.' },
  edb:     { name: 'Exchange database', blurb: 'EDB is a Microsoft Exchange Server mailbox database.', fact: 'An Exchange EDB can store the mailboxes of an entire organisation.' },
  dbx:     { name: 'Outlook Express folder', blurb: 'DBX is an Outlook Express mail-folder file, used in older Windows.', fact: 'Outlook Express stored each mail folder as a DBX file in Windows XP and earlier.' },

  // ---- Security / keys / certs ----
  key:      { name: 'Cryptographic key', blurb: 'A .key file holds a cryptographic private or public key, used to secure connections and sign data.', fact: 'Keep private .key files secret - anyone holding one can impersonate you.' },
  pub:      { name: 'Public key', blurb: 'A .pub file is a public key, such as an SSH key you share with servers.', fact: 'Public keys are safe to share; they pair with a private key you keep hidden.' },
  p8:       { name: 'PKCS#8 private key', blurb: 'P8 is a PKCS#8 private key, used by Apple developer services among others.', fact: 'PKCS#8 is a standard wrapper for storing a private key of any algorithm.' },
  csr:      { name: 'Certificate request', blurb: 'CSR is a Certificate Signing Request sent to a certificate authority.', fact: 'A CSR is how you ask a certificate authority to issue your HTTPS certificate.' },
  crl:      { name: 'Certificate revocation list', blurb: 'CRL is a list of certificates that should no longer be trusted.', fact: 'A CRL lets software reject certificates that were revoked before they expired.' },
  p7b:      { name: 'PKCS#7 certificate bundle', blurb: 'P7B is a PKCS#7 bundle of certificates, often a certificate chain.', fact: 'P7B files carry certificates only - never the private key.' },
  p7c:      { name: 'PKCS#7 certificate bundle', blurb: 'P7C is a PKCS#7 certificate bundle, often a chain of certificates.', fact: 'PKCS stands for Public-Key Cryptography Standards, a numbered series RSA first published in June 1991 - this format takes its name from standard number seven.' },
  ppk:      { name: 'PuTTY private key', blurb: 'PPK is a PuTTY private key, used to log in to servers over SSH on Windows.', fact: 'PuTTY is the classic Windows SSH client, and PPK is its own key format.' },
  ovpn:     { name: 'OpenVPN config', blurb: 'OVPN is an OpenVPN configuration file for a VPN connection.', fact: 'OpenVPN has been a leading open-source VPN since 2001.' },
  wg:       { name: 'WireGuard config', blurb: 'A WireGuard config sets up a fast, modern VPN tunnel.', fact: 'WireGuard, merged into the Linux kernel in 2020, is prized for being simple and fast.' },
  jks:      { name: 'Java KeyStore', blurb: 'JKS is a Java KeyStore holding keys and certificates for Java apps.', fact: 'JKS was Java’s default keystore until the cross-platform PKCS#12 took over in Java 9.' },
  keystore: { name: 'Java KeyStore', blurb: 'A .keystore file holds keys and certificates, commonly used to sign Android apps.', fact: 'Android developers sign every app with a key kept in a keystore file.' },
  jceks:    { name: 'Java JCEKS keystore', blurb: 'JCEKS is a stronger variant of the Java KeyStore.', fact: 'JCEKS adds stronger key protection than the original JKS keystore.' },
  // ---- Apple/Windows config & network capture ----
  mobileconfig:    { name: 'Apple configuration profile', blurb: 'A .mobileconfig profile pushes settings - Wi-Fi, VPN, email, restrictions - onto iPhones, iPads and Macs. Used by Apple device management.', fact: 'IT departments use configuration profiles to set up company iPhones without touching each device by hand.' },
  mobileprovision: { name: 'iOS provisioning profile', blurb: 'A .mobileprovision file authorises an iOS app to run on specific devices during development. Created by Apple’s developer tools.', fact: 'A provisioning profile, made by Apple’s developer tools, ties an app, its signing certificate and a list of test devices together.' },
  reg:             { name: 'Windows Registry export', blurb: 'A .reg file is an exported chunk of the Windows Registry that can be merged back in. Created by Registry Editor.', fact: 'Double-clicking a .reg file writes its keys straight into the Windows Registry.' },
  pcap:            { name: 'Packet capture', blurb: 'PCAP records raw network traffic for analysis. Opened by Wireshark and tcpdump.', fact: 'The pcap format comes from the tcpdump network tool, and captures are usually opened in Wireshark.' },
  pcapng:          { name: 'Packet capture (next gen)', blurb: 'PCAPNG is the modern, richer network-capture format. Opened by Wireshark.', fact: 'PCAPNG, read by Wireshark, replaced classic pcap with support for multiple interfaces and richer metadata.' },
  p12:             { name: 'PKCS#12 keystore', blurb: 'P12 bundles a private key with its certificate chain in one password-protected file.', fact: 'PKCS#12 is the cross-platform standard for moving a key and its certificates together.' },
  pfx:             { name: 'PKCS#12 keystore', blurb: 'PFX is Microsoft’s name for a PKCS#12 file holding a key and its certificates. Used by Windows and IIS.', fact: 'PFX and P12 are the same format - PFX is just the older Microsoft name.' },
  kdbx:            { name: 'KeePass database', blurb: 'KDBX is an encrypted password database. Opened by KeePass and compatible apps.', fact: 'KeePass is a long-running open-source password manager, and KDBX is its encrypted vault.' },
  evtx:            { name: 'Windows Event Log', blurb: 'EVTX is a Windows Event Log, recording system and security events. Opened by Event Viewer.', fact: 'EVTX is the Windows Event Log read by Event Viewer, introduced with Windows Vista in 2006.' },

  // ---- Game ROMs & patches ----
  nes:     { name: 'NES ROM', blurb: 'NES is a Nintendo Entertainment System game ROM, run on emulators.', fact: 'The NES launched as the Famicom in Japan in 1983 and revived the home console market.' },
  gb:      { name: 'Game Boy ROM', blurb: 'GB is a Nintendo Game Boy game ROM, run on emulators.', fact: 'The Game Boy launched in 1989 and sold over 100 million units worldwide.' },
  gbc:     { name: 'Game Boy Color ROM', blurb: 'GBC is a Game Boy Color game ROM, run on emulators.', fact: 'The Game Boy Color arrived in 1998, adding colour to the handheld line.' },
  gba:     { name: 'Game Boy Advance ROM', blurb: 'GBA is a Game Boy Advance game ROM, run on emulators.', fact: 'The Game Boy Advance launched in 2001 with 32-bit power in a handheld.' },
  sfc:     { name: 'Super Famicom ROM', blurb: 'SFC is a Super Nintendo (Super Famicom) game ROM, run on emulators.', fact: 'The Super Nintendo arrived in 1990 and is fondly remembered for its 16-bit classics.' },
  smc:     { name: 'SNES ROM', blurb: 'SMC is a Super Nintendo game ROM, named after the Super Magicom copier.', fact: 'The SMC name comes from the Super Magicom, a 1990s device for copying SNES cartridges.' },
  nds:     { name: 'Nintendo DS ROM', blurb: 'NDS is a Nintendo DS game ROM, run on emulators.', fact: 'The dual-screen Nintendo DS launched in 2004 and became one of the best-selling consoles ever.' },
  dsi:     { name: 'Nintendo DSi ROM', blurb: 'DSI is a Nintendo DSi game ROM, for the camera-equipped DS revision.', fact: 'The DSi, released in 2008, added cameras and a download store to the DS line.' },
  z64:     { name: 'Nintendo 64 ROM', blurb: 'Z64 is a Nintendo 64 game ROM in big-endian byte order, run on emulators.', fact: 'The Nintendo 64, launched in 1996, was the last major console to use cartridges.' },
  n64:     { name: 'Nintendo 64 ROM', blurb: 'N64 is a Nintendo 64 game ROM in little-endian byte order, run on emulators.', fact: 'N64 ROMs come in several byte orders, which is why the same game has .z64, .n64 and .v64 versions.' },
  v64:     { name: 'Nintendo 64 ROM', blurb: 'V64 is a Nintendo 64 game ROM in byte-swapped order, from the Doctor V64 copier.', fact: 'The .v64 order comes from the Doctor V64, a 1990s N64 backup device.' },
  gen:     { name: 'Mega Drive ROM', blurb: 'GEN is a Sega Genesis (Mega Drive) game ROM, run on emulators.', fact: 'The Sega Mega Drive, known as the Genesis in North America, launched in 1988.' },
  smd:     { name: 'Mega Drive ROM', blurb: 'SMD is a Sega Genesis (Mega Drive) game ROM, named after the Super Magic Drive copier.', fact: 'The .smd order comes from the Super Magic Drive, a 1990s Mega Drive backup unit.' },
  ips:     { name: 'IPS ROM patch', blurb: 'IPS is a patch file that modifies a game ROM, widely used in ROM hacking and translations.', fact: 'The simple IPS patch format has powered fan translations and ROM hacks since the early 1990s.', factApprox: true },
  bps:     { name: 'BPS ROM patch', blurb: 'BPS is a modern ROM-patch format that fixes the size limits of older IPS patches.', fact: 'BPS improved on IPS with checksums and support for large ROMs.' },
  ups:     { name: 'UPS ROM patch', blurb: 'UPS is a ROM-patch format used to distribute ROM hacks and translations.', fact: 'UPS patches store only the differences between the original and modified ROM.' },
  ppf:     { name: 'PlayStation patch', blurb: 'PPF (PlayStation Patch Format) patches disc images, commonly for PS1 and PS2 games.', fact: 'PPF was created to patch CD-based console images that IPS could not handle.' },
  wad:     { name: 'Doom/Wii WAD', blurb: 'WAD packs game data - levels, textures and sounds for Doom, or a channel for the Wii.', fact: 'Doom’s 1993 WAD ("Where’s All the Data") files launched a huge modding community.' },
  nbt:     { name: 'Minecraft NBT data', blurb: 'NBT is Minecraft’s Named Binary Tag format, storing world and player data.', fact: 'NBT is the tree-structured format Minecraft uses to save almost everything in a world.' },
  mcworld: { name: 'Minecraft world', blurb: 'MCWORLD is an exported Minecraft: Bedrock Edition world, ready to share or import.', fact: 'An MCWORLD bundles an entire Minecraft world into one shareable file.' },

  // ---- Game assets & engine packages ----
  ase:     { name: 'Aseprite sprite', blurb: 'ASE is an Aseprite sprite file, holding layers and animation frames for pixel art. Created by Aseprite.', fact: 'Aseprite is a popular pixel-art and animation tool among indie game developers.' },
  pck:     { name: 'Godot resource pack', blurb: 'PCK bundles a Godot game’s assets and scenes into one package. Created by the Godot engine.', fact: 'Godot ships a game’s data as a PCK pack alongside the executable.' },
  pak:     { name: 'Game data pack', blurb: 'PAK is a game data archive holding levels, textures and sounds. Used by Quake, Unreal and many engines.', fact: 'The PAK archive dates back to id Software’s Quake in 1996.' },
  pk3:     { name: 'Quake III archive', blurb: 'PK3 is a Quake III game archive - really a renamed ZIP of game data.', fact: 'Quake III adopted ZIP-based PK3 files in 1999, making game content easy to mod.' },
  bsp:     { name: 'Compiled game map', blurb: 'BSP is a compiled 3D game level, used by Quake, Half-Life and Source games.', fact: 'BSP (Binary Space Partitioning) maps let 1990s engines render complex levels fast.' },
  vpk:     { name: 'Valve pack', blurb: 'VPK is a Valve Pak archive of game assets for Source-engine games. Created by Valve.', fact: 'Valve ships the content for games like Team Fortress 2 and Dota 2 in VPK packs.' },
  vtf:     { name: 'Valve Texture Format', blurb: 'VTF stores a texture for Valve’s Source engine. Created by Valve.', fact: 'VTF is the texture format of Valve’s Source engine, behind games such as Half-Life 2.' },
  vmt:     { name: 'Valve material', blurb: 'VMT is a Valve Material Type file describing how a Source-engine surface looks.', fact: 'A VMT tells the Source engine which texture to use and how it should be shaded.' },
  ktx:     { name: 'Khronos texture', blurb: 'KTX stores GPU textures ready for OpenGL and Vulkan. Standardised by the Khronos Group.', fact: 'KTX holds textures in formats the graphics card can use directly, mipmaps and all.' },
  ktx2:    { name: 'Khronos texture v2', blurb: 'KTX2 is the modern Khronos texture container, with Basis Universal compression.', fact: 'KTX2, finalised in 2021, adds efficient supercompression for game and web textures.' },
  tmx:     { name: 'Tiled map', blurb: 'TMX is a tile-based game map. Created by the Tiled map editor.', fact: 'Tiled is a widely used free editor for building 2D game levels out of tiles.' },
  tmj:     { name: 'Tiled map (JSON)', blurb: 'TMJ is the JSON form of a Tiled tile map. Created by the Tiled map editor.', fact: 'TMJ is just a Tiled map saved as JSON instead of XML.' },
  love:    { name: 'LÖVE game', blurb: 'A .love file is a packaged game for the LÖVE 2D engine - a ZIP of Lua code and assets.', fact: 'LÖVE is a free framework for making 2D games in the Lua language.' },
  package: { name: 'The Sims package', blurb: 'A .package file is custom content or a mod for The Sims, holding meshes and textures.', fact: 'The Sims’ package files power a huge community of custom furniture, clothes and mods.' },
  mpq:     { name: 'Blizzard MPQ archive', blurb: 'MPQ (Mo’PaQ) is Blizzard’s game-data archive, used by Diablo, StarCraft and WarCraft.', fact: 'Blizzard’s MPQ format, from 1996, packed the data for classics like Diablo and StarCraft.' },
  cia:     { name: '3DS install package', blurb: 'CIA is a Nintendo 3DS installable title package, used with custom firmware.', fact: 'A CIA bundles a 3DS title so it can be installed straight to the console’s home menu.' },
  nsp:     { name: 'Switch package', blurb: 'NSP is a Nintendo Switch installable game package.', fact: 'NSP is the Switch’s digital title format, the download counterpart to a game card.' },
  xci:     { name: 'Switch cartridge image', blurb: 'XCI is a dumped Nintendo Switch game-card image.', fact: 'An XCI is a full copy of a Switch game cartridge’s contents.' },

  // ---- Virtual machines & disc images ----
  ovf:  { name: 'Open Virtualization Format', blurb: 'OVF describes a virtual machine in a portable, vendor-neutral way.', fact: 'OVF, standardised in 2009, lets a virtual machine move between VMware, VirtualBox and others.' },
  ova:  { name: 'OVF appliance', blurb: 'OVA is a single-file archive of an OVF virtual machine, ready to import.', fact: 'An OVA packs a whole virtual appliance - disks and config - into one shareable file.' },
  vbox: { name: 'VirtualBox machine', blurb: 'VBOX is an Oracle VirtualBox virtual-machine settings file. Created by VirtualBox.', fact: 'A .vbox file holds an Oracle VirtualBox machine’s configuration, pointing to its separate virtual disks.' },
  vmx:  { name: 'VMware machine', blurb: 'VMX is a VMware virtual-machine configuration file. Created by VMware.', fact: 'The .vmx file defines a VMware VM’s hardware - its CPU, memory and disks.' },
  cue:  { name: 'Cue sheet', blurb: 'A CUE sheet describes the track layout of a CD image, paired with a BIN file.', fact: 'Cue sheets map out where each track sits inside a disc image.' },
  ccd:  { name: 'CloneCD image', blurb: 'CCD is a CloneCD disc-image descriptor, paired with .img and .sub files.', fact: 'CloneCD was a popular tool for making exact copies of CDs and DVDs.' },
  nrg:  { name: 'Nero disc image', blurb: 'NRG is a disc image created by Nero Burning ROM.', fact: 'Nero Burning ROM was the go-to CD/DVD burning suite of the early 2000s.' },
  mds:  { name: 'Media Descriptor', blurb: 'MDS is a disc-image descriptor from Alcohol 120%, paired with an MDF file.', fact: 'Alcohol 120% paired an MDS descriptor with an MDF image to copy protected discs.' },
  mdf:  { name: 'Media disc image', blurb: 'MDF holds the data of a disc image, paired with an MDS descriptor.', fact: 'MDF/MDS image pairs come from the Alcohol 120% disc-copying software.' },

  // ---- Firmware & binaries ----
  hex:    { name: 'Intel HEX', blurb: 'HEX is an Intel HEX file, carrying firmware as text to flash onto microcontrollers.', fact: 'Intel HEX, from 1973, is still how firmware reaches countless chips today.' },
  srec:   { name: 'Motorola S-record', blurb: 'SREC is a Motorola S-record file, storing firmware as ASCII hex for flashing.', fact: 'Motorola created the S-record format in the 1970s for loading code onto chips.' },
  s19:    { name: 'Motorola S-record', blurb: 'S19 is a Motorola S-record firmware file with 16-bit addresses.', fact: 'The number in .s19/.s28/.s37 marks how many address bytes each record uses.' },
  s28:    { name: 'Motorola S-record', blurb: 'S28 is a Motorola S-record firmware file with 24-bit addresses.', fact: 'Records with 24-bit addresses suited Motorola’s 68000 family, whose external address bus was exactly 24 lines wide.' },
  s37:    { name: 'Motorola S-record', blurb: 'S37 is a Motorola S-record firmware file with 32-bit addresses.', fact: 'Motorola’s S-records compete with Intel HEX, a rival 1970s format that encodes the same firmware data in lines beginning with a colon instead of an S.' },
  mot:    { name: 'Motorola S-record', blurb: 'MOT is a Motorola S-record firmware file for flashing microcontrollers.', fact: 'The Motorola S-record format stores binary firmware safely as plain text.' },
  uf2:    { name: 'USB Flashing Format', blurb: 'UF2 lets you flash a microcontroller by dragging the file onto a USB drive. Created by Microsoft.', fact: 'Microsoft made UF2 for MakeCode so beginners could flash boards with a simple drag-and-drop.' },
  elf:    { name: 'ELF executable', blurb: 'ELF is the executable and library format used by Linux and many Unix systems.', fact: 'ELF became the standard Unix binary format in the 1990s, replacing older a.out files.' },
  axf:    { name: 'ARM executable', blurb: 'AXF is an ARM ELF executable with debug information, used in embedded development.', fact: 'AXF is the ELF-based image produced by Arm’s development toolchains.' },
  o:      { name: 'Object file', blurb: 'A .o file is compiled object code, linked together to build a program.', fact: 'Object files hold machine code that the linker stitches into a finished program.' },
  so:     { name: 'Shared library', blurb: 'A .so file is a Linux shared library, loaded by programs at runtime.', fact: 'Shared objects let many Linux programs reuse the same library code in memory.' },
  dtb:    { name: 'Device Tree Blob', blurb: 'DTB describes a device’s hardware layout for the Linux kernel to read at boot.', fact: 'Device trees let one Linux kernel boot on many different ARM boards.' },
  dtbo:   { name: 'Device Tree Overlay', blurb: 'DTBO is a device-tree overlay that patches hardware settings on top of a base DTB.', fact: 'Overlays let add-on boards describe their hardware without rebuilding the whole device tree.' },
  uimage: { name: 'U-Boot image', blurb: 'A uImage is a kernel image wrapped for the U-Boot bootloader, common on embedded Linux.', fact: 'U-Boot is the bootloader behind most embedded Linux devices.' },

  // ---- Disk & filesystem images ----
  gpt:      { name: 'GUID Partition Table', blurb: 'GPT is the modern partition layout that organises a disk into volumes.', fact: 'GPT replaced the old MBR scheme, lifting the 2 TB disk limit in the 2000s.' },
  mbr:      { name: 'Master Boot Record', blurb: 'MBR is the classic first sector of a disk, holding the partition table and boot code.', fact: 'The MBR scheme dates from the 1983 IBM PC and capped disks at 2 TB.' },
  ext4:     { name: 'ext4 filesystem image', blurb: 'EXT4 is an image of the default Linux filesystem.', fact: 'ext4 became Linux’s default filesystem around 2008 and still is on many systems.' },
  ext:      { name: 'ext filesystem image', blurb: 'EXT is an image of a Linux extended filesystem.', fact: 'The ext family has been Linux’s native filesystem line since the early 1990s.' },
  squashfs: { name: 'SquashFS image', blurb: 'SquashFS is a compressed, read-only Linux filesystem, used in live CDs and routers.', fact: 'SquashFS squeezes a whole read-only filesystem down, ideal for Linux live images.' },
  sfs:      { name: 'SquashFS image', blurb: 'SFS is a SquashFS compressed read-only filesystem image.', fact: 'SquashFS packs read-only system files tightly, common in embedded Linux.' },
  cramfs:   { name: 'cramfs image', blurb: 'cramfs is a small compressed read-only filesystem for embedded Linux.', fact: 'cramfs was an early compressed filesystem for squeezing Linux onto tiny flash chips.' },
  romfs:    { name: 'romfs image', blurb: 'romfs is a simple read-only filesystem used in embedded and boot images.', fact: 'romfs trades features for simplicity, fitting where space is tight.' },
  wim:      { name: 'Windows Imaging Format', blurb: 'WIM is Microsoft’s file-based disk image, used to deploy Windows.', fact: 'Windows itself installs from a WIM image on the setup media.' },
  swm:      { name: 'Split WIM image', blurb: 'SWM is a Windows Imaging file split into pieces to fit on smaller media.', fact: 'A WIM too big for a DVD or FAT32 drive is split into numbered SWM parts.' },
  esd:      { name: 'Windows ESD image', blurb: 'ESD is a heavily compressed Windows image, used by Windows Update downloads.', fact: 'ESD ("Electronic Software Download") shrinks a Windows image for faster downloading.' },
  ewf:      { name: 'EnCase forensic image', blurb: 'EWF is an EnCase Expert Witness Format disk image, used in digital forensics.', fact: 'EWF images preserve a suspect’s drive with checksums for use as legal evidence.' },
  jffs2:    { name: 'JFFS2 flash image', blurb: 'JFFS2 is a journalling filesystem image for raw flash memory in embedded devices.', fact: 'JFFS2 was designed to spread writes evenly so flash chips wear out slowly.' },
  ubifs:    { name: 'UBIFS flash image', blurb: 'UBIFS is a modern Linux filesystem image for large flash chips.', fact: 'UBIFS succeeded JFFS2 to handle the bigger flash memory in newer devices.' },
  yaffs2:   { name: 'YAFFS2 flash image', blurb: 'YAFFS2 is a flash filesystem image once common on Android devices.', fact: 'YAFFS2 was the filesystem on many early Android phones.' },
  isz:      { name: 'Compressed ISO', blurb: 'ISZ is a compressed disc image. Created by UltraISO.', fact: 'ISZ is UltraISO’s compressed, optionally encrypted take on the ISO image.' },
  cdi:      { name: 'DiscJuggler image', blurb: 'CDI is a disc image from DiscJuggler, popular for Dreamcast backups.', fact: 'CDI images are closely associated with the Sega Dreamcast scene.' },
  vmsn:     { name: 'VMware snapshot', blurb: 'VMSN stores a VMware virtual-machine snapshot - a frozen point in time.', fact: 'A VMware snapshot lets you roll a virtual machine back to an earlier state.' },
  vmem:     { name: 'VMware memory image', blurb: 'VMEM is the paged memory of a VMware virtual machine, useful for forensics.', fact: 'A VMEM file is essentially a virtual machine’s RAM saved to disk.' },

  // ---- Science & medical ----
  dcm:   { name: 'DICOM medical image', blurb: 'DCM is a DICOM medical image - an X-ray, CT or MRI scan with patient data.', fact: 'DICOM, standardised in 1993, is how hospitals store and exchange medical scans worldwide.' },
  dicom: { name: 'DICOM medical image', blurb: 'DICOM stores a medical scan together with patient and study information.', fact: 'DICOM, standardised in 1993, is the universal format for hospital imaging.' },
  nii:   { name: 'NIfTI brain scan', blurb: 'NII is a NIfTI neuroimaging file, used in brain MRI research.', fact: 'NIfTI was created in the early 2000s to standardise brain-scan data for researchers.' },
  fit:   { name: 'Garmin activity', blurb: 'FIT records a workout - GPS track, heart rate and more. Created by Garmin devices.', fact: 'Garmin’s FIT format is the standard for fitness watches and bike computers.' },
  tcx:   { name: 'Garmin Training Center', blurb: 'TCX is a Garmin Training Center XML workout file with route and heart-rate data.', fact: 'TCX was Garmin’s XML workout format before the more compact FIT took over.' },
  fits:  { name: 'Astronomy image (FITS)', blurb: 'FITS is the Flexible Image Transport System, the standard format for astronomical data.', fact: 'FITS has stored telescope images and data since 1981 and is still used by NASA today.' },
  fts:   { name: 'Astronomy image (FITS)', blurb: 'FTS is a Flexible Image Transport System file holding astronomical imaging or data.', fact: 'FITS has been astronomy’s data standard since 1981.' },
  fasta: { name: 'FASTA sequence', blurb: 'FASTA stores DNA, RNA or protein sequences as plain text, central to bioinformatics.', fact: 'The FASTA format dates from a 1985 sequence-search program of the same name.' },
  fa:    { name: 'FASTA sequence', blurb: 'FA is a FASTA file of DNA, RNA or protein sequences.', fact: 'FASTA is the simplest and most common way to store biological sequences.' },
  fna:   { name: 'FASTA nucleotides', blurb: 'FNA is a FASTA file specifically holding nucleotide (DNA/RNA) sequences.', fact: 'The .fna suffix marks a FASTA file as nucleic-acid sequences.' },
  faa:   { name: 'FASTA proteins', blurb: 'FAA is a FASTA file holding amino-acid (protein) sequences.', fact: 'The .faa suffix marks a FASTA file as protein sequences.' },

  // ---- Bioinformatics & chemistry ----
  fastq:    { name: 'FASTQ reads', blurb: 'FASTQ stores DNA sequencing reads together with per-base quality scores.', fact: 'FASTQ is the standard output of modern DNA sequencing machines.' },
  fq:       { name: 'FASTQ reads', blurb: 'FQ is a FASTQ file of sequencing reads with quality scores.', fact: 'FASTQ pairs each read with quality scores showing how confident the sequencer was.' },
  mol:      { name: 'MDL Molfile', blurb: 'MOL describes a single molecule’s atoms and bonds. Used by chemistry software.', fact: 'The MDL Molfile has been a core chemistry format since the 1980s.' },
  sdf:      { name: 'Structure-data file', blurb: 'SDF holds one or more molecules plus associated data, common in chemical databases.', fact: 'SDF extends the Molfile to carry many molecules and their properties together.' },
  mol2:     { name: 'Tripos molecule', blurb: 'MOL2 is a Tripos molecule file widely used in molecular modelling.', fact: 'The MOL2 format comes from Tripos’s SYBYL modelling software.' },
  cif:      { name: 'Crystallographic Information File', blurb: 'CIF stores crystal structure data, the standard in crystallography.', fact: 'CIF, adopted in 1991, is how crystal structures are archived and shared.' },
  mmcif:    { name: 'Macromolecular CIF', blurb: 'mmCIF stores large biological structures like proteins from the Protein Data Bank.', fact: 'mmCIF is now the main format of the Protein Data Bank, replacing the older PDB layout.' },
  xyz:      { name: 'XYZ coordinates', blurb: 'XYZ is a simple text list of atoms and their 3D coordinates.', fact: 'The XYZ format is the plainest way to record where every atom in a molecule sits.' },

  // ---- Electronics / PCB design ----
  gbr:   { name: 'Gerber PCB', blurb: 'GBR is a Gerber file describing one layer of a printed circuit board for manufacture.', fact: 'Gerber, the industry standard for sending PCB designs to fabs, dates from the 1980s.' },
  gbl:   { name: 'Gerber bottom layer', blurb: 'GBL is the Gerber file for a circuit board’s bottom copper layer.', fact: 'Each PCB layer gets its own Gerber file when sent off for fabrication.' },
  gtl:   { name: 'Gerber top layer', blurb: 'GTL is the Gerber file for a circuit board’s top copper layer.', fact: 'Joseph Gerber, whose company gave the format its name, fled Nazi-occupied Vienna as a boy and built his first invention from the elastic waistband of his pyjamas.' },
  drl:   { name: 'Excellon drill file', blurb: 'DRL is an Excellon drill file telling the factory where to drill a PCB’s holes.', fact: 'Drill files pair with Gerbers to tell the machine where each board hole goes.' },
  xln:   { name: 'PCB drill file', blurb: 'XLN is a drill file describing the holes to make in a printed circuit board.', fact: 'Drill files tell the factory the position and size of every hole in a board.' },
  cir:   { name: 'SPICE circuit', blurb: 'CIR is a SPICE circuit description for simulating electronics.', fact: 'SPICE, born at Berkeley in 1973, is the foundation of analogue circuit simulation.' },
  sp:    { name: 'SPICE netlist', blurb: 'SP is a SPICE netlist listing components and connections for circuit simulation.', fact: 'A SPICE netlist describes a circuit as a list of parts and the nodes joining them.' },
  spi:   { name: 'SPICE netlist', blurb: 'SPI is a SPICE netlist used to simulate an electronic circuit.', fact: 'SPICE simulation lets engineers test a circuit before building it.' },
  spice: { name: 'SPICE simulation', blurb: 'A .spice file describes a circuit for the SPICE simulator.', fact: 'SPICE has been the standard circuit-simulation engine since the 1970s.' },

  // ---- Scientific signals & statistics ----
  edf:      { name: 'European Data Format', blurb: 'EDF stores biological signals such as EEG and sleep recordings.', fact: 'EDF, created in 1992, is the standard format for sleep and brain-signal recordings.' },
  bdf:      { name: 'BioSemi Data Format', blurb: 'BDF is a 24-bit biosignal recording format, an extension of EDF used for EEG.', fact: 'BDF extended EDF to 24-bit precision for BioSemi’s EEG systems.' },
  jdx:      { name: 'JCAMP-DX spectrum', blurb: 'JDX is a JCAMP-DX file storing spectroscopy data such as infrared spectra.', fact: 'JCAMP-DX was created in the 1980s to exchange chemical spectra as plain text.' },
  dx:       { name: 'JCAMP-DX spectrum', blurb: 'DX is a JCAMP-DX spectroscopy data file.', fact: 'JCAMP-DX lets labs swap infrared and other spectra in a readable text format.' },
  sav:      { name: 'SPSS dataset', blurb: 'SAV is an IBM SPSS statistics data file, used in social-science research.', fact: 'SPSS has been a staple of social-science statistics since the late 1960s.' },
  dta:      { name: 'Stata dataset', blurb: 'DTA is a Stata statistics data file, common in economics research.', fact: 'Stata, launched in 1985, is a favourite statistics package in economics.' },
  sas7bdat: { name: 'SAS dataset', blurb: 'SAS7BDAT is a dataset for the SAS statistical software.', fact: 'SAS has been a heavyweight in enterprise statistics and analytics since the 1970s.' },

  // ---- Scientific visualisation & genomics ----
  vtk:  { name: 'VTK data', blurb: 'VTK stores 3D scientific data for the Visualization Toolkit.', fact: 'The Visualization Toolkit, open-sourced in 1998, powers much scientific 3D visualisation.' },
  vtu:  { name: 'VTK unstructured grid', blurb: 'VTU is a VTK XML file holding an unstructured mesh for scientific visualisation.', fact: 'VTU is part of VTK’s modern XML-based file family.' },
  vtp:  { name: 'VTK polygon data', blurb: 'VTP is a VTK XML file storing polygonal geometry for visualisation.', fact: 'VTP holds points and polygons in VTK’s XML format.' },
  vti:  { name: 'VTK image data', blurb: 'VTI is a VTK XML file holding a regular grid of values, such as a volume.', fact: 'VTI stores image and volume data on a regular grid for VTK.' },
  segy: { name: 'SEG-Y seismic', blurb: 'SEG-Y stores reflection-seismic survey data, the standard in oil and gas exploration.', fact: 'SEG-Y, defined in 1975, is how the energy industry stores seismic survey data.' },
  sgy:  { name: 'SEG-Y seismic', blurb: 'SGY is a SEG-Y seismic data file from geophysical surveys.', fact: 'SEG-Y has been the seismic-data standard since the 1970s.' },
  bam:  { name: 'Binary alignment map', blurb: 'BAM stores DNA sequencing reads aligned to a reference genome, in compressed binary.', fact: 'BAM is the compressed binary form of the SAM alignment format in genomics.' },
  sam:  { name: 'Sequence alignment map', blurb: 'SAM is a text format for DNA reads aligned to a reference genome.', fact: 'SAM, introduced in 2009, became the standard for storing sequence alignments.' },
  bcf:  { name: 'Binary variant call', blurb: 'BCF is the compressed binary form of a genomic variant-call (VCF) file.', fact: 'BCF speeds up handling of the huge variant lists produced in genomics.' },
  hea:  { name: 'PhysioNet header', blurb: 'HEA is a WFDB header describing a physiological recording such as an ECG.', fact: 'HEA headers accompany the signal files in PhysioNet’s research databases.' },

  // ---- Feeds, system & diagnostics ----
  opml:     { name: 'Outline (OPML)', blurb: 'OPML stores outlines, most often lists of RSS feed subscriptions.', fact: 'OPML, from 2000, is how people export and share their feed-reader subscriptions.' },
  rss:      { name: 'RSS feed', blurb: 'RSS is a web feed listing a site’s latest articles. Read by feed readers and podcast apps.', fact: 'RSS, which spread in the early 2000s, still powers podcasts and news feeds today.' },
  atom:     { name: 'Atom feed', blurb: 'ATOM is a web feed format, a more formal alternative to RSS.', fact: 'The Atom feed standard (RFC 4287) was published in 2005 to clean up RSS’s rough edges.' },
  desktop:  { name: 'Linux desktop entry', blurb: 'A .desktop file is a Linux application launcher, defining an app’s name, icon and command.', fact: 'Desktop entries are how Linux menus and shortcuts know about installed apps.' },
  nfo:      { name: 'Info file', blurb: 'NFO is a plain-text information file, often with ASCII-art art from the warez and demo scene.', fact: 'Scene NFO files turned ASCII art into a badge of identity in the 1990s.' },
  service:  { name: 'systemd service unit', blurb: 'A .service file tells systemd how to run a background service on Linux.', fact: 'systemd, adopted across Linux from 2010, uses unit files like these to manage services.' },
  crash:    { name: 'Crash report', blurb: 'A .crash file records details of a program that crashed, for debugging.', fact: 'Crash reports capture what a program was doing the moment it failed.' },
  ab:       { name: 'Android backup', blurb: 'AB is an Android backup archive made with the adb backup command.', fact: 'An AB file can hold an Android device’s apps and data in one backup.' },
  job:      { name: 'Scheduled task', blurb: 'A .job file is a Windows Task Scheduler task definition.', fact: 'JOB files stored scheduled tasks in older versions of Windows.' },
  pol:      { name: 'Group Policy file', blurb: 'A .pol file holds Windows Group Policy registry settings pushed to managed PCs.', fact: 'Registry.pol files are how Windows domains enforce settings on company computers.' },
  scr:      { name: 'Windows screensaver', blurb: 'SCR is a Windows screensaver - actually an executable program.', fact: 'A screensaver is just a Windows program with an .scr name, which made them a malware trick.' },
  ds_store: { name: 'macOS folder metadata', blurb: 'A .DS_Store file stores how macOS displays a folder - icon positions and view settings.', fact: 'macOS scatters hidden .DS_Store files in folders, often to the annoyance of other systems.' },
  thumbsdb: { name: 'Windows thumbnail cache', blurb: 'Thumbs.db is a Windows cache of folder thumbnail images.', fact: 'Older Windows left a Thumbs.db in each folder to show picture previews faster.' },
  dsym:     { name: 'Apple debug symbols', blurb: 'A .dSYM bundle holds the debug symbols that turn an Apple app crash into readable line numbers.', fact: 'dSYM files let developers decode crash reports from shipped iOS and Mac apps.' },
  dwarf:    { name: 'DWARF debug info', blurb: 'DWARF is a debugging-information format embedded in or beside compiled programs.', fact: 'DWARF, paired with the ELF format, is what debuggers read to map code back to source.' },
  sdb:      { name: 'Application shim database', blurb: 'SDB is a Windows application-compatibility shim database.', fact: 'Shim databases let old programs keep working on newer Windows.' },

  // ---- Images (raster, vector & icons) ----
  tga:      { name: 'Targa image', blurb: 'TGA (Truevision Targa) is a raster image format long used in games and 3D rendering.', fact: 'The Targa format dates from 1984 and was an early home for 24-bit colour images.' },
  qoi:      { name: 'Quite OK Image', blurb: 'QOI is a simple, fast lossless image format.', fact: 'QOI appeared in 2021 as a tiny format that compresses about as well as PNG but far faster.' },
  ppm:      { name: 'Portable Pixmap', blurb: 'PPM is a plain, uncompressed colour image from the Netpbm toolkit.', fact: 'The Netpbm formats trade efficiency for being dead simple to read and write.' },
  pgm:      { name: 'Portable Graymap', blurb: 'PGM is a simple greyscale image from the Netpbm toolkit.', fact: 'PGM stores a greyscale image as plain numbers, one per pixel.' },
  pbm:      { name: 'Portable Bitmap', blurb: 'PBM is a simple black-and-white image from the Netpbm toolkit.', fact: 'PBM, the original Netpbm format from the 1980s, stores just black and white pixels.' },
  pnm:      { name: 'Portable Anymap', blurb: 'PNM is any of the Netpbm image types - bitmap, greymap or pixmap.', fact: 'PNM is an umbrella name for the simple PBM, PGM and PPM image formats.' },
  pam:      { name: 'Portable Arbitrary Map', blurb: 'PAM is the modern Netpbm image format, adding transparency and arbitrary channels.', fact: 'PAM extended the old Netpbm formats with an alpha channel and more.' },
  pcx:      { name: 'PCX image', blurb: 'PCX is an early PC raster image format from ZSoft’s PC Paintbrush.', fact: 'PCX was one of the most common image formats on DOS PCs in the 1980s.' },
  ff:       { name: 'farbfeld image', blurb: 'FF is a farbfeld image, a deliberately minimal lossless format from the suckless project.', fact: 'farbfeld is designed to be the simplest possible image format to process.' },
  farbfeld: { name: 'farbfeld image', blurb: 'farbfeld is a deliberately minimal lossless image format from the suckless project.', fact: 'farbfeld strips an image down to a tiny header and raw pixels for easy processing.' },
  wbmp:     { name: 'Wireless Bitmap', blurb: 'WBMP is a 1-bit image format made for early mobile phones.', fact: 'WBMP carried simple black-and-white graphics to phones in the WAP era around 2000.' },
  xbm:      { name: 'X Bitmap', blurb: 'XBM is an X Window System bitmap, stored as C source code.', fact: 'XBM images are literally snippets of C code, a quirk of early Unix graphics.' },
  xpm:      { name: 'X Pixmap', blurb: 'XPM is an X Window System colour image, also stored as C source code.', fact: 'XPM added colour to the C-source image trick of the older XBM format.' },
  ras:      { name: 'Sun Raster', blurb: 'RAS is a Sun Raster image from Sun Microsystems workstations.', fact: 'Sun Raster was the native image format on 1980s and 90s Sun workstations.' },
  sgi:      { name: 'SGI image', blurb: 'SGI is a raster image from Silicon Graphics workstations.', fact: 'The SGI image format came from the graphics workstations that rendered early CGI films.' },
  bw:       { name: 'SGI greyscale image', blurb: 'BW is a black-and-white image from Silicon Graphics systems.', fact: 'BW is the single-channel greyscale variant of the SGI image format.' },
  hdr:      { name: 'Radiance HDR', blurb: 'HDR is a Radiance high-dynamic-range image, storing a huge brightness range.', fact: 'Radiance HDR, from 1989, let computer graphics capture real-world light levels.' },
  dds:      { name: 'DirectDraw Surface', blurb: 'DDS stores GPU-ready textures with mipmaps, widely used in games. Created by Microsoft.', fact: 'DDS is the texture format of choice for DirectX games.' },
  exr:      { name: 'OpenEXR image', blurb: 'EXR (OpenEXR) is a high-dynamic-range image format used in film and visual effects. Created by Industrial Light & Magic.', fact: 'ILM created OpenEXR in 1999 and released it openly in 2003; it is now standard in VFX.' },
  jp2:      { name: 'JPEG 2000', blurb: 'JP2 is a JPEG 2000 image, offering better compression than ordinary JPEG.', fact: 'JPEG 2000 arrived in 2000 but never overtook plain JPEG outside niches like cinema and archiving.' },
  j2k:      { name: 'JPEG 2000 codestream', blurb: 'J2K is a raw JPEG 2000 codestream without the JP2 file wrapper.', fact: 'J2K holds JPEG 2000 image data without the extra metadata of a full JP2 file.' },
  jpf:      { name: 'JPEG 2000 (JPX)', blurb: 'JPF is an extended JPEG 2000 image with extra features.', fact: 'JPF uses the extended JPX form of JPEG 2000.' },
  jpx:      { name: 'JPEG 2000 (JPX)', blurb: 'JPX is the extended JPEG 2000 format, adding features over basic JP2.', fact: 'JPX extends JPEG 2000 with multiple layers and richer colour.' },
  jpc:      { name: 'JPEG 2000 codestream', blurb: 'JPC is a raw JPEG 2000 codestream.', fact: 'A JPEG 2000 codestream decodes progressively - cut the file short at any point and it still yields a complete image, just at lower quality or resolution.' },
  jxr:      { name: 'JPEG XR', blurb: 'JXR is a JPEG XR image, Microsoft’s high-quality successor to JPEG.', fact: 'JPEG XR grew out of Microsoft’s HD Photo and became a standard in 2009.' },
  wdp:      { name: 'HD Photo (JPEG XR)', blurb: 'WDP is Microsoft’s HD Photo, the format that became JPEG XR.', fact: 'WDP was Microsoft’s Windows Media Photo before it was standardised as JPEG XR.' },
  hdp:      { name: 'HD Photo (JPEG XR)', blurb: 'HDP is a Microsoft HD Photo image, an early form of JPEG XR.', fact: 'HD Photo was Microsoft’s attempt at a better JPEG, later standardised as JPEG XR.' },
  eps:      { name: 'Encapsulated PostScript', blurb: 'EPS is a vector graphic in PostScript, long used in print and design.', fact: 'EPS was the workhorse vector format for print design before PDF took over.' },
  ps:       { name: 'PostScript', blurb: 'PS is a PostScript document, a page-description language for printers. Created by Adobe.', fact: 'Adobe’s PostScript, launched in 1984, sparked the desktop-publishing revolution.' },
  wmf:      { name: 'Windows Metafile', blurb: 'WMF is a Windows vector graphic, used for clip art and Office drawings.', fact: 'WMF has carried Windows vector clip art since the late 1980s.', factApprox: true },
  emf:      { name: 'Enhanced Metafile', blurb: 'EMF is the 32-bit successor to WMF for Windows vector graphics.', fact: 'EMF replaced the older WMF format to handle richer Windows graphics.' },
  emz:      { name: 'Compressed Enhanced Metafile', blurb: 'EMZ is a compressed (gzipped) Windows Enhanced Metafile vector graphic.', fact: 'EMZ is just an EMF vector image squeezed with gzip.' },
  icns:     { name: 'Apple icon', blurb: 'ICNS holds an app icon at many sizes for macOS. Created by Apple.', fact: 'macOS apps store their icon, from tiny to huge, in a single ICNS file.' },
  cur:      { name: 'Windows cursor', blurb: 'CUR is a Windows mouse-cursor image, with a defined hotspot.', fact: 'A CUR file is like an icon but marks the exact pixel the cursor points with.' },
  ani:      { name: 'Animated cursor', blurb: 'ANI is an animated Windows mouse cursor.', fact: 'ANI files gave Windows its spinning and waving animated cursors.' },
  mng:      { name: 'Animated PNG (MNG)', blurb: 'MNG is an animation format, the multi-image cousin of PNG.', fact: 'MNG aimed to be PNG’s animated sibling but lost out to GIF and later APNG.' },
  lottie:   { name: 'Lottie animation', blurb: 'A Lottie file is a small JSON-based vector animation that plays on web and mobile. Created by Airbnb.', fact: 'Airbnb released Lottie in 2017 to ship smooth vector animations as tiny files.' },

  // ---- 3D models & scenes ----
  vox:    { name: 'MagicaVoxel model', blurb: 'VOX is a voxel 3D model. Created by MagicaVoxel.', fact: 'MagicaVoxel is a popular free editor for building models out of cubes.' },
  dae:    { name: 'COLLADA scene', blurb: 'DAE (COLLADA) is an open 3D interchange format for models and scenes.', fact: 'COLLADA was created in 2004 as a vendor-neutral way to move 3D assets between tools.' },
  zae:    { name: 'Zipped COLLADA', blurb: 'ZAE is a COLLADA 3D scene zipped together with its textures.', fact: 'ZAE bundles a COLLADA model and all its assets into one archive.' },
  usdc:   { name: 'USD (binary)', blurb: 'USDC is the binary form of Pixar’s Universal Scene Description for 3D pipelines.', fact: 'Pixar open-sourced USD in 2016 and it now underpins film and 3D production pipelines.' },
  x3d:    { name: 'X3D scene', blurb: 'X3D is an XML-based 3D scene format, the successor to VRML.', fact: 'X3D was standardised in the early 2000s to bring VRML into the XML age.' },
  wrl:    { name: 'VRML world', blurb: 'WRL is a VRML file describing an interactive 3D world, an early format for 3D on the web.', fact: 'VRML promised 3D worlds in the browser back in the mid-1990s.' },
  vrml:   { name: 'VRML world', blurb: 'VRML is the Virtual Reality Modeling Language for 3D scenes on the early web.', fact: 'VRML, from 1994, was an early attempt to put navigable 3D worlds online.' },
  lwo:    { name: 'LightWave object', blurb: 'LWO is a 3D model from NewTek LightWave 3D.', fact: 'LightWave 3D helped render the effects for shows like Babylon 5.' },
  lws:    { name: 'LightWave scene', blurb: 'LWS is a LightWave 3D scene file, tying together models, lights and animation.', fact: 'An LWS scene references LWO objects to assemble a full LightWave shot.' },
  drawio: { name: 'diagrams.net diagram', blurb: 'A .drawio file is a diagram - flowcharts, network maps and more. Created by diagrams.net (draw.io).', fact: 'diagrams.net is a free diagramming tool used widely for flowcharts and architecture diagrams.' },
  md2:    { name: 'Quake II model', blurb: 'MD2 is an animated 3D character model from Quake II.', fact: 'MD2’s vertex animation gave Quake II its characters in 1997.' },
  md3:    { name: 'Quake III model', blurb: 'MD3 is an animated 3D model format from Quake III Arena.', fact: 'MD3 improved on MD2 by splitting models into parts for smoother animation.' },
  mdl:    { name: 'Quake/Half-Life model', blurb: 'MDL is a 3D model format used by the Quake and Half-Life engines.', fact: 'The MDL format carried the characters of id and Valve’s early shooters.' },

  // ---- 3D scans, point clouds & BIM ----
  vrm:      { name: 'VRM avatar', blurb: 'VRM is a 3D avatar format built on glTF, widely used for VTubers and VR. Created by the VRM Consortium.', fact: 'VRM was introduced in 2018 to give VTubers and VR apps a shared avatar standard.' },
  jt:       { name: 'JT 3D model', blurb: 'JT is a lightweight 3D format for sharing and reviewing CAD models. Created by Siemens.', fact: 'JT became an ISO standard in 2012 for exchanging 3D product data across the industry.' },
  las:      { name: 'LiDAR point cloud', blurb: 'LAS stores LiDAR point clouds from laser scanning and aerial surveys.', fact: 'The LAS format, standardised by ASPRS in 2003, is the industry standard for LiDAR data.' },
  laz:      { name: 'Compressed LiDAR', blurb: 'LAZ is a losslessly compressed LAS LiDAR point cloud.', fact: 'LAZ shrinks bulky LAS point clouds to a fraction of their size with no data loss.' },
  pcd:      { name: 'Point Cloud Data', blurb: 'PCD is the native point-cloud format of the Point Cloud Library (PCL).', fact: 'PCD is the format the open-source Point Cloud Library reads and writes.' },
  pts:      { name: 'Point cloud (PTS)', blurb: 'PTS is a plain-text point cloud of 3D coordinates with colour or intensity.', fact: 'PTS stores a laser scan as a simple list of points, one per line.' },
  e57:      { name: 'E57 point cloud', blurb: 'E57 stores laser-scan point clouds together with images and metadata.', fact: 'E57, standardised by ASTM in 2011, is a vendor-neutral format for 3D imaging data.' },
  ifc:      { name: 'IFC building model', blurb: 'IFC (Industry Foundation Classes) is the open standard for sharing building-information models. Used across BIM tools.', fact: 'IFC lets architecture and engineering software exchange whole building models, regardless of vendor.' },
  ifczip:   { name: 'Zipped IFC model', blurb: 'IFCZIP is a compressed IFC building-information model.', fact: 'IFCZIP is just an IFC building model packed into a ZIP to save space.' },
  splat:    { name: 'Gaussian splat scene', blurb: 'A .splat file stores a 3D scene as Gaussian splats, a photoreal capture technique.', fact: '3D Gaussian splatting, published in 2023, renders photoreal scenes far faster than earlier methods.' },
  spz:      { name: 'Compressed Gaussian splat', blurb: 'SPZ is a compact format for 3D Gaussian splat scenes. Created by Niantic.', fact: 'Niantic released SPZ in 2024 to make Gaussian splat scenes far smaller to store and share.' },

  // ---- GIS & mapping ----
  topojson: { name: 'TopoJSON', blurb: 'TopoJSON is a GeoJSON extension that stores shared borders only once, making map files smaller.', fact: 'TopoJSON encodes topology so neighbouring regions share their boundaries instead of repeating them.' },
  osm:      { name: 'OpenStreetMap data', blurb: 'OSM is the XML data format of OpenStreetMap, the crowd-sourced world map.', fact: 'OpenStreetMap, started in 2004, is built by volunteers mapping the whole world.' },
  shx:      { name: 'Shapefile index', blurb: 'SHX is the index part of an Esri shapefile, paired with .shp and .dbf.', fact: 'A shapefile is really a set of files, and SHX is the index that speeds up access to the shapes.' },
  dbf:      { name: 'dBASE table', blurb: 'DBF is a dBASE database table, still used to hold the attributes of GIS shapefiles.', fact: 'The dBASE table format from the 1980s lives on as the attribute table of every shapefile.' },
  prj:      { name: 'Projection file', blurb: 'A .prj file records the coordinate system of a shapefile or raster, in Well-Known Text.', fact: 'The .prj file tells GIS software which map projection the data uses.' },
  cpg:      { name: 'Code page file', blurb: 'CPG records the character encoding of a shapefile’s attribute table.', fact: 'The .cpg file tells GIS tools how to read non-English text in a shapefile.' },
  pgw:      { name: 'PNG world file', blurb: 'PGW is a world file that georeferences a PNG image, placing it on the map.', fact: 'A world file pairs with an image to tell GIS software where on Earth it belongs.' },
  tfw:      { name: 'TIFF world file', blurb: 'TFW is a world file that georeferences a TIFF image for GIS use.', fact: 'TFW gives a plain TIFF its position and scale on the map.' },
  jgw:      { name: 'JPEG world file', blurb: 'JGW is a world file that georeferences a JPEG image.', fact: 'JGW places a JPEG aerial photo correctly on the map.' },
  wld:      { name: 'World file', blurb: 'A .wld world file georeferences an image so GIS software can map it.', fact: 'The world file is a tiny text file holding an image’s map coordinates and scale.' },
  gml:      { name: 'Geography Markup Language', blurb: 'GML is an XML standard for describing geographic features. Defined by the Open Geospatial Consortium.', fact: 'GML is the OGC’s XML grammar for sharing maps and spatial data.' },
  nmea:     { name: 'NMEA GPS log', blurb: 'NMEA files hold GPS sentences - position, time and speed - as plain text.', fact: 'NMEA 0183 is the text protocol nearly every GPS receiver uses to report its position.' },
  igc:      { name: 'Glider flight log', blurb: 'IGC is the standard flight-log format from glider and paraglider GPS recorders.', fact: 'IGC logs are the official record used to verify gliding records and competitions.' },
  tab:      { name: 'MapInfo table', blurb: 'TAB is the table format of MapInfo, a long-running GIS package.', fact: 'TAB is to MapInfo what the shapefile is to Esri’s ArcGIS.' },
  mif:      { name: 'MapInfo Interchange', blurb: 'MIF is MapInfo’s text interchange format for moving map data between systems.', fact: 'MIF is the plain-text export MapInfo uses to share data with other GIS tools.' },
  vrt:      { name: 'GDAL virtual raster', blurb: 'VRT is a GDAL virtual file that stitches other raster files into one dataset.', fact: 'A VRT is just an XML recipe pointing at other files, so it costs almost no disk space.' },
  pmtiles:  { name: 'PMTiles map archive', blurb: 'PMTiles packs an entire map tileset into one file that can be served with no backend.', fact: 'PMTiles lets a whole interactive map be hosted from a single static file.' },
  dt0:      { name: 'DTED level 0', blurb: 'DT0 is Digital Terrain Elevation Data at the coarsest resolution.', fact: 'DTED was created by the US military to store ground elevation in standard levels.' },
  dt1:      { name: 'DTED level 1', blurb: 'DT1 is Digital Terrain Elevation Data at medium resolution.', fact: 'DTED levels 0 to 2 store terrain elevation at increasing detail.' },
  dt2:      { name: 'DTED level 2', blurb: 'DT2 is Digital Terrain Elevation Data at the finest standard resolution.', fact: 'DTED level 2 packs the most detailed elevation grid of the standard DTED levels.' },
  dted:     { name: 'DTED elevation', blurb: 'DTED (Digital Terrain Elevation Data) is a military-standard grid of ground heights.', fact: 'DTED began as a US Defense Mapping Agency format for terrain elevation.' },
  asc:      { name: 'Esri ASCII grid', blurb: 'ASC is an Esri ASCII grid - a plain-text raster of elevation or other gridded values.', fact: 'The ASCII grid stores a whole raster as readable numbers, easy to inspect by eye.' },
  hgt:      { name: 'SRTM elevation', blurb: 'HGT files hold elevation data from NASA’s Shuttle Radar Topography Mission.', fact: 'The Shuttle Radar Topography Mission mapped most of Earth’s land elevation in the year 2000.' },
  grib:     { name: 'GRIB weather data', blurb: 'GRIB stores weather and climate model output. Used by meteorological agencies worldwide.', fact: 'GRIB is the World Meteorological Organization’s standard for sharing forecast data.' },
  grb:      { name: 'GRIB weather data', blurb: 'GRB is a GRIB file of weather or climate model data.', fact: 'GRIB packs gridded forecast data efficiently for global weather services.' },
  grib2:    { name: 'GRIB2 weather data', blurb: 'GRIB2 is the second-generation GRIB format for weather and climate data.', fact: 'GRIB2 added more flexibility and better compression to the original GRIB standard.' },
  cdf:      { name: 'NetCDF data', blurb: 'CDF is a NetCDF file storing array-based scientific data like climate and ocean models.', fact: 'NetCDF, from Unidata, is a mainstay of climate and earth-science data.' },
  nc4:      { name: 'NetCDF-4 data', blurb: 'NC4 is a NetCDF-4 file, the HDF5-based version of the scientific data format.', fact: 'NetCDF-4 builds on HDF5 to handle larger and more complex scientific datasets.' },
  pbf:      { name: 'OSM/vector tile binary', blurb: 'PBF is a compact binary format for OpenStreetMap data and Mapbox vector tiles.', fact: 'PBF uses Protocol Buffers to pack map data far smaller than XML.' },
  gpkg:     { name: 'GeoPackage', blurb: 'GeoPackage stores maps and geodata in a single SQLite database file. An OGC standard.', fact: 'GeoPackage put a whole GIS dataset into one portable SQLite file.' },
  mbtiles:  { name: 'MBTiles map', blurb: 'MBTiles packs map tiles into a SQLite database. Popularised by Mapbox.', fact: 'MBTiles made it easy to ship a whole offline map as one file.' },
  sid:      { name: 'MrSID image', blurb: 'SID is a MrSID image, compressing huge aerial and satellite photos for fast viewing.', fact: 'MrSID lets gigapixel aerial imagery be panned and zoomed smoothly.' },
  ecw:      { name: 'ECW image', blurb: 'ECW (Enhanced Compression Wavelet) compresses massive aerial and satellite imagery for GIS.', fact: 'ECW squeezes enormous aerial photos down while keeping them quick to view.' },
  gdb:      { name: 'Esri geodatabase', blurb: 'A .gdb is an Esri file geodatabase - a folder holding many GIS layers and tables.', fact: 'The file geodatabase is Esri’s modern container for organising GIS data.' },

  // ---- Lossless & specialist audio ----
  ape:  { name: 'Monkey’s Audio', blurb: 'APE is a Monkey’s Audio file, a popular lossless audio compressor.', fact: 'Monkey’s Audio achieves high lossless compression at the cost of slower encoding.' },
  wv:   { name: 'WavPack', blurb: 'WV is a WavPack file, an open lossless audio format.', fact: 'WavPack can store a lossless file with a small lossy version tucked inside it.' },
  tak:  { name: 'TAK lossless audio', blurb: 'TAK (Tom’s lossless Audio Kompressor) is a lossless audio format known for fast decoding.', fact: 'TAK aims to match the best lossless compression while decoding quickly.' },
  tta:  { name: 'True Audio', blurb: 'TTA (True Audio) is a free, simple lossless audio codec.', fact: 'True Audio is an open lossless format favoured for archiving music.' },
  ofr:  { name: 'OptimFROG', blurb: 'OFR is an OptimFROG file, squeezing audio losslessly to very small sizes.', fact: 'OptimFROG trades speed for some of the highest lossless compression around.' },
  dsf:  { name: 'DSD audio (DSF)', blurb: 'DSF holds DSD audio, the high-resolution format behind Super Audio CD. Created by Sony.', fact: 'DSF stores the 1-bit DSD audio used by Super Audio CD.' },
  dff:  { name: 'DSD audio (DFF)', blurb: 'DFF (DSDIFF) stores DSD high-resolution audio.', fact: 'DFF is the interchange form of the DSD audio used in Super Audio CD mastering.' },
  mpc:  { name: 'Musepack', blurb: 'MPC is a Musepack audio file, a lossy format tuned for high-quality music.', fact: 'Musepack was designed for transparent music quality at higher bitrates.' },
  caf:  { name: 'Core Audio Format', blurb: 'CAF is Apple’s Core Audio Format, able to hold very large audio files. Created by Apple.', fact: 'CAF lifts the size limits of WAV and AIFF for long, high-resolution recordings.' },
  rf64: { name: 'RF64 broadcast WAV', blurb: 'RF64 extends WAV past its 4 GB limit for long broadcast recordings.', fact: 'RF64 was created so broadcasters could record audio longer than WAV’s 4 GB ceiling.' },
  bw64: { name: 'Broadcast Wave 64-bit', blurb: 'BW64 is an ITU broadcast-WAV format for audio files larger than 4 GB.', fact: 'BW64 carries large broadcast audio along with rich production metadata.' },
  w64:  { name: 'Sony Wave64', blurb: 'W64 (Wave64) lifts WAV’s 4 GB size limit. Created by Sony for Sound Forge.', fact: 'Wave64 let Sound Forge record audio well beyond the old WAV size limit.' },
  au:   { name: 'Sun audio', blurb: 'AU is the Sun/NeXT audio format, one of the oldest digital sound formats.', fact: 'The AU format comes from Sun Microsystems in the late 1980s.', factApprox: true },
  snd:  { name: 'NeXT/Sun sound', blurb: 'SND is the NeXT and Sun sound format, a close sibling of AU.', fact: 'SND and AU share a heritage in early Unix workstation audio.' },
  voc:  { name: 'Creative Voice', blurb: 'VOC is the Creative Voice format from Sound Blaster sound cards.', fact: 'VOC was the native sound format of Creative’s Sound Blaster cards in the early 1990s.', factApprox: true },
  bwf:  { name: 'Broadcast Wave', blurb: 'BWF (Broadcast Wave) adds production metadata and timecode to WAV, standard in pro audio.', fact: 'Broadcast Wave lets recordings carry timecode so they can be synced in editing.' },
  spx:  { name: 'Speex audio', blurb: 'SPX is a Speex file, an open voice codec from the Xiph.Org foundation.', fact: 'Speex was a free speech codec, later superseded by the more capable Opus.' },
  awb:  { name: 'AMR Wideband', blurb: 'AWB holds AMR Wideband speech, used for HD voice calls.', fact: 'AMR-WB brought wider, clearer speech to mobile HD voice calls.' },
  qcp:  { name: 'Qualcomm PureVoice', blurb: 'QCP holds Qualcomm PureVoice audio, recorded by older CDMA phones.', fact: 'QCP was the voice-recording format of many early Qualcomm-based phones.' },
  '3ga':{ name: '3GPP audio', blurb: '3GA holds audio in the 3GPP container, often from Samsung voice recorders.', fact: '3GA is essentially a 3GP file holding only an audio track.' },
  m4r:  { name: 'iPhone ringtone', blurb: 'M4R is the AAC ringtone format for the iPhone. Created by Apple.', fact: 'An M4R is just an AAC audio clip renamed to mark it as an iPhone ringtone.' },
  gsm:  { name: 'GSM audio', blurb: 'GSM audio uses the low-bitrate codec built for early mobile phone calls.', fact: 'The GSM codec was designed in the 1980s to carry voice over digital mobile networks.', factApprox: true },
  mp2:  { name: 'MPEG-1 Layer II audio', blurb: 'MP2 is MPEG-1 Audio Layer II, still used in digital radio and TV broadcasting.', fact: 'MP2 predates MP3 and remains common in broadcasting for its robustness.' },
  mp1:  { name: 'MPEG-1 Layer I audio', blurb: 'MP1 is MPEG-1 Audio Layer I, the simplest of the MPEG-1 audio layers.', fact: 'MP1 was the first MPEG audio layer, soon eclipsed by MP2 and MP3.' },

  // ---- Music synthesis & ringtones ----
  sf2:   { name: 'SoundFont 2', blurb: 'SF2 is a SoundFont bank of sampled instruments for software synthesisers.', fact: 'SoundFont banks store recorded instruments so a MIDI file can play with real sounds.' },
  sf3:   { name: 'Compressed SoundFont', blurb: 'SF3 is a SoundFont with its samples compressed as Ogg Vorbis.', fact: 'SF3 shrinks a SoundFont by compressing its instrument samples.' },
  sfz:   { name: 'SFZ instrument', blurb: 'SFZ is an open text format describing a sampled instrument and how to play it.', fact: 'SFZ is a free, human-readable way to define sampled instruments.' },
  dls:   { name: 'Downloadable Sounds', blurb: 'DLS is a downloadable-instruments bank, defined by the MIDI Manufacturers Association.', fact: 'DLS was the standard way to ship custom instruments alongside MIDI music.' },
  rmi:   { name: 'RMID MIDI', blurb: 'RMI wraps a MIDI song in a RIFF container, sometimes with embedded instruments.', fact: 'RMI lets a MIDI file carry its own sound bank so it plays the same everywhere.' },
  mmf:   { name: 'Yamaha SMAF', blurb: 'MMF (Yamaha SMAF) carried ringtones and sound to early mobile phones.', fact: 'SMAF was Yamaha’s rich ringtone format in the era before MP3 ringtones.' },
  gig:   { name: 'GigaStudio instrument', blurb: 'GIG holds the large sampled instruments of the GigaStudio sampler.', fact: 'GigaStudio streamed huge instrument samples straight from disk for realism.' },
  rtttl: { name: 'Nokia ringtone', blurb: 'RTTTL is the simple text format behind classic monophonic Nokia ringtones.', fact: 'RTTTL let people type out and share ringtones as short lines of text.' },
  imy:   { name: 'iMelody ringtone', blurb: 'IMY (iMelody) was an early text-based mobile ringtone format.', fact: 'iMelody was a standard ringtone format in the early mobile phone era.' },
  sap:   { name: 'Atari SAP music', blurb: 'SAP holds chiptune music from the Atari 8-bit home computers.', fact: 'SAP captures the music of the Atari 8-bit’s POKEY sound chip.' },

  // ---- Trackers & chiptune ----
  mod:  { name: 'Amiga module', blurb: 'MOD is a tracker music module, the format that launched the demoscene.', fact: 'The MOD format began on the Commodore Amiga in 1987 and started a whole music tradition.' },
  xm:   { name: 'FastTracker module', blurb: 'XM is the module format of FastTracker 2, hugely popular in the demoscene.', fact: 'FastTracker 2 and its XM format dominated PC tracker music in the 1990s.' },
  it:   { name: 'Impulse Tracker module', blurb: 'IT is the module format of Impulse Tracker, prized for its sound quality.', fact: 'Impulse Tracker was many musicians’ favourite tracker of the late 1990s.' },
  s3m:  { name: 'Scream Tracker 3 module', blurb: 'S3M is the module format of Scream Tracker 3.', fact: 'Scream Tracker 3 and its S3M format were released by Future Crew in 1994.' },
  stm:  { name: 'Scream Tracker 2 module', blurb: 'STM is an early module format from Scream Tracker 2.', fact: 'STM came from Scream Tracker before the more capable S3M format.' },
  mtm:  { name: 'MultiTracker module', blurb: 'MTM is the module format of the MultiTracker editor.', fact: 'MTM was the format of the MultiTracker music editor.' },
  med:  { name: 'OctaMED module', blurb: 'MED is a music module from the Amiga’s OctaMED tracker.', fact: 'OctaMED could play eight channels on the Amiga, twice the hardware’s usual four.' },
  '669':{ name: 'Composer 669 module', blurb: 'A .669 file is a music module from the Composer 669 tracker.', fact: 'The 669 format came from the Composer 669 tracker of the early 1990s.' },
  far:  { name: 'Farandole module', blurb: 'FAR is the module format of the Farandole Composer tracker.', fact: 'FAR was the native format of the Farandole Composer.' },
  okt:  { name: 'Oktalyzer module', blurb: 'OKT is the eight-channel module format of the Amiga’s Oktalyzer.', fact: 'Oktalyzer was an early tool for eight-channel music on the Amiga.' },
  nsfe: { name: 'Extended NES sound', blurb: 'NSFE is an extended NES Sound Format with track titles and metadata.', fact: 'NSFE adds song names and details to the original NES music rip format.' },
  spc:  { name: 'SNES music rip', blurb: 'SPC files are rips of Super Nintendo game music, captured from its SPC700 sound chip.', fact: 'An SPC is a snapshot of the SNES sound chip’s memory, so it plays exactly as in-game.' },
  vgm:  { name: 'Video game music log', blurb: 'VGM logs the exact sound-chip commands of retro game music for accurate playback.', fact: 'VGM replays the original chip instructions, so the music sounds just like the hardware.' },
  vgz:  { name: 'Compressed VGM', blurb: 'VGZ is a gzip-compressed VGM video-game music log.', fact: 'VGZ is simply a VGM music file squeezed with gzip.' },
  gbs:  { name: 'Game Boy sound', blurb: 'GBS holds music ripped from Game Boy games.', fact: 'GBS plays back the original Game Boy sound code for authentic chiptunes.' },
  ay:   { name: 'AY chiptune', blurb: 'AY files hold chiptune music for the AY sound chip of the ZX Spectrum and Amstrad.', fact: 'The AY-3-8910 chip gave 1980s home computers and arcades their bleepy soundtracks.' },
  ym:   { name: 'Atari ST chiptune', blurb: 'YM holds chiptune music from the Atari ST’s YM2149 sound chip.', fact: 'YM captures the distinctive sound of the Atari ST’s music chip.' },

  // ---- Audio projects & game sound ----
  aup:  { name: 'Audacity project (legacy)', blurb: 'AUP was the project format of the Audacity audio editor before version 3.', fact: 'Old Audacity projects kept their audio in a separate _data folder beside the .aup file.' },
  aup3: { name: 'Audacity project', blurb: 'AUP3 is the single-file Audacity project format, based on SQLite. Created by Audacity.', fact: 'Audacity 3 moved to the self-contained AUP3 project in 2021, ending the old folder split.' },
  psf:  { name: 'Portable Sound Format', blurb: 'PSF packs a game’s actual sound program so its music plays exactly as on the console.', fact: 'PSF embeds the real console sound code, so playback matches the original hardware.' },
  m3u8: { name: 'UTF-8 playlist / HLS', blurb: 'M3U8 is a UTF-8 playlist, also the backbone of HLS adaptive streaming. Used by Apple.', fact: 'Apple’s HLS streaming, built on M3U8 playlists, carries much of the web’s live video.' },

  // ---- Playlists & streaming manifests ----
  m3u:  { name: 'M3U playlist', blurb: 'M3U is the simple text playlist understood by nearly every media player.', fact: 'M3U began in the Winamp era and is still the most common playlist format.' },
  mpd:  { name: 'MPEG-DASH manifest', blurb: 'An MPD manifest drives MPEG-DASH adaptive streaming.', fact: 'MPEG-DASH is the open standard alternative to Apple’s HLS streaming.' },
  ism:  { name: 'Smooth Streaming manifest', blurb: 'ISM describes a Microsoft Smooth Streaming presentation.', fact: 'Smooth Streaming was Microsoft’s adaptive-bitrate technology for Silverlight and beyond.' },
  ismc: { name: 'Smooth Streaming client manifest', blurb: 'ISMC is the client manifest for a Microsoft Smooth Streaming stream.', fact: 'The ISMC tells the player which quality levels a Smooth Streaming video offers.' },
  f4m:  { name: 'Flash Media Manifest', blurb: 'F4M described Adobe HTTP Dynamic Streaming, now largely retired with Flash.', fact: 'F4M powered Adobe’s HDS streaming before HLS and DASH took over.' },
  asx:  { name: 'Windows Media playlist', blurb: 'ASX is a Windows Media playlist, pointing players at streams or files.', fact: 'ASX was the metafile that launched streams in Windows Media Player.' },
  wpl:  { name: 'Windows Media Player playlist', blurb: 'WPL is the native playlist format of Windows Media Player.', fact: 'WPL is the playlist Windows Media Player saves your music queues as.' },
  xspf: { name: 'XSPF playlist', blurb: 'XSPF is an open XML playlist format, nicknamed "spiff".', fact: 'XSPF was designed as a free, portable alternative to proprietary playlists.' },
  pls:  { name: 'PLS playlist', blurb: 'PLS is a playlist format especially common for internet radio stations.', fact: 'PLS playlists often point listeners straight at a streaming radio URL.' },

  // ---- Professional & broadcast video ----
  mxf:    { name: 'Material Exchange Format', blurb: 'MXF is the professional broadcast and film video container, used by Avid, Sony and others.', fact: 'MXF was standardised in 2004 as the workhorse container of professional video.' },
  gxf:    { name: 'General Exchange Format', blurb: 'GXF is a broadcast video interchange format from Grass Valley.', fact: 'GXF was built to move finished video between broadcast servers.' },
  lxf:    { name: 'Leitch broadcast video', blurb: 'LXF is a broadcast-server video format from Leitch (later Harris).', fact: 'LXF stored video on Leitch broadcast playout servers.' },
  dv:     { name: 'Digital Video', blurb: 'DV is the format of MiniDV camcorder tapes.', fact: 'DV powered the MiniDV camcorders of the late 1990s and early 2000s.' },
  dif:    { name: 'DV stream', blurb: 'DIF holds raw DV digital-video data.', fact: 'DIF is the raw block structure inside DV camcorder footage.' },
  asf:    { name: 'Advanced Systems Format', blurb: 'ASF is Microsoft’s container behind WMV video and WMA audio.', fact: 'ASF is the wrapper that holds Windows Media’s WMV and WMA streams.' },
  'dvr-ms':{ name: 'Media Center recording', blurb: 'DVR-MS held TV recordings made by Windows Media Center.', fact: 'DVR-MS was how Windows Media Center saved recorded television, later replaced by WTV.' },
  rm:     { name: 'RealMedia', blurb: 'RM (RealMedia) was a dominant streaming video and audio format of the early web.', fact: 'RealMedia ruled internet video streaming in the late 1990s.' },
  rmvb:   { name: 'RealMedia Variable Bitrate', blurb: 'RMVB was a RealVideo variant hugely popular for sharing films, especially in Asia.', fact: 'RMVB packed films into small files and spread widely across Asia in the 2000s.' },
  divx:   { name: 'DivX video', blurb: 'DIVX is video encoded with the DivX codec.', fact: 'DivX made it possible to fit a whole DVD movie onto a single CD around the year 2000.' },
  f4v:    { name: 'Flash MP4 video', blurb: 'F4V was Adobe’s MP4-based Flash video, succeeding the older FLV.', fact: 'F4V moved Flash video onto the standard MP4 structure.' },
  insv:   { name: 'Insta360 video', blurb: 'INSV is the video format of Insta360 action and 360-degree cameras.', fact: 'INSV holds the footage Insta360 cameras stitch into 360-degree video.' },
  insp:   { name: 'Insta360 photo', blurb: 'INSP is the photo format of Insta360 cameras.', fact: 'INSP is the still-image counterpart to Insta360’s INSV video.' },
  lrv:    { name: 'Low-res proxy video', blurb: 'LRV is a low-resolution proxy clip cameras like GoPro record beside the full video.', fact: 'The LRV proxy lets you preview and edit footage before handling the heavy original.' },
  gifv:   { name: 'GIF-style video', blurb: 'GIFV was Imgur’s trick of serving silent video in place of heavy animated GIFs.', fact: 'GIFV looked like a GIF but was really compact video, saving huge amounts of bandwidth.' },
  ivf:    { name: 'IVF video', blurb: 'IVF is a simple container used for testing VP8, VP9 and AV1 video.', fact: 'IVF is a bare-bones wrapper developers use to test modern video codecs.' },
  y4m:    { name: 'YUV4MPEG video', blurb: 'Y4M stores raw uncompressed video, used to test and benchmark codecs.', fact: 'Y4M keeps video completely uncompressed so codec quality can be measured fairly.' },
  m2v:    { name: 'MPEG-2 video', blurb: 'M2V holds an MPEG-2 video stream, the format behind DVDs.', fact: 'MPEG-2 video is what fills the discs of the DVD era.' },
  m1v:    { name: 'MPEG-1 video', blurb: 'M1V holds an MPEG-1 video stream, the format behind Video CD.', fact: 'MPEG-1 video powered the Video CD, an early-1990s precursor to the DVD.' },
  mpv:    { name: 'MPEG video stream', blurb: 'MPV holds a bare MPEG video stream without audio.', fact: 'An MPV file is just the picture half of an MPEG movie.' },
  obu:    { name: 'AV1 video stream', blurb: 'OBU holds a raw AV1 video stream, the modern open video codec.', fact: 'AV1, released in 2018, is the royalty-free codec backed by Google, Netflix and others.' },
  m2p:    { name: 'MPEG-2 program stream', blurb: 'M2P is an MPEG-2 program stream, as used on DVDs.', fact: 'The program stream packages MPEG-2 video and audio for storage on disc.' },
  m2t:    { name: 'MPEG-2 transport stream', blurb: 'M2T carries MPEG-2 video in the transport stream used by HD camcorders and broadcast.', fact: 'The transport stream was built to survive the errors of broadcast and tape.' },
  trp:    { name: 'HD transport stream', blurb: 'TRP is an MPEG transport-stream recording from HDTV receivers.', fact: 'TRP files are the raw HD recordings many set-top boxes produce.' },
  wtv:    { name: 'Windows Recorded TV', blurb: 'WTV is the recorded-TV format of Windows Media Center, replacing DVR-MS.', fact: 'WTV was the format Windows Media Center used for HD television recordings.' },
  ogm:    { name: 'Ogg Media', blurb: 'OGM was an early container for video alongside Ogg audio, before Matroska took over.', fact: 'OGM was a community hack to add video to Ogg, later superseded by the MKV format.' },
  nut:    { name: 'NUT container', blurb: 'NUT is an open multimedia container from the FFmpeg and MPlayer projects.', fact: 'NUT was designed by the FFmpeg community as a clean, open media container.' },
  dpx:    { name: 'Digital Picture Exchange', blurb: 'DPX stores single film frames at full quality, standard in film scanning and VFX.', fact: 'DPX grew out of Kodak’s Cineon format to become the SMPTE standard for film frames.' },
  cin:    { name: 'Kodak Cineon', blurb: 'CIN (Cineon) was Kodak’s film-scan frame format, the ancestor of DPX.', fact: 'Cineon was Kodak’s pioneering format for scanning film into the computer.' },
  dav:    { name: 'Dahua CCTV video', blurb: 'DAV is the recording format of many Dahua CCTV systems.', fact: 'DAV files are the footage saved by a large share of the world’s security cameras.' },
  yuv:    { name: 'Raw YUV video', blurb: 'YUV files hold raw uncompressed video frames.', fact: 'Raw YUV keeps every pixel, making it ideal for testing but huge on disk.' },

  // ---- Comic book archives ----
  cbz: { name: 'Comic Book ZIP', blurb: 'CBZ is a ZIP of comic page images, the most common digital-comic format.', fact: 'A CBZ is simply a ZIP full of page images that comic readers display in order.' },
  cbr: { name: 'Comic Book RAR', blurb: 'CBR is a RAR archive of comic page images.', fact: 'CBR is the RAR-based cousin of the ZIP-based CBZ comic format.' },
  cbt: { name: 'Comic Book TAR', blurb: 'CBT is a TAR archive of comic page images.', fact: 'CBT packs comic pages into a TAR archive instead of a ZIP.' },
  cb7: { name: 'Comic Book 7z', blurb: 'CB7 is a 7-Zip archive of comic page images.', fact: 'CB7 uses 7-Zip compression to pack a digital comic.' },

  // ---- Documents, ebooks & publishing ----
  xps:    { name: 'XML Paper Specification', blurb: 'XPS was Microsoft’s fixed-layout document format, a PDF rival. Created by Microsoft.', fact: 'Microsoft introduced XPS with Windows Vista in 2006 to compete with PDF.' },
  oxps:   { name: 'OpenXPS', blurb: 'OXPS is the open, standardised version of Microsoft’s XPS document format.', fact: 'OXPS is the Ecma-standard form of XPS used by newer Windows.' },
  hwpx:   { name: 'Hancom HWPX', blurb: 'HWPX is the modern XML format of Hancom Office, the leading word processor in South Korea.', fact: 'Hancom’s word processor is so dominant in South Korea that HWP files are everywhere there.' },
  hwp:    { name: 'Hancom Hangul', blurb: 'HWP is the document format of Hancom’s Hangul, ubiquitous in South Korean offices and government.', fact: 'HWP is the default document format across much of South Korea’s public sector.' },
  fb3:    { name: 'FictionBook 3', blurb: 'FB3 is the ZIP-based successor to the FictionBook e-book format.', fact: 'FB3 modernised FictionBook by switching to a ZIP-and-XML structure.' },
  ibooks: { name: 'iBooks Author book', blurb: 'The .ibooks format came from Apple’s iBooks Author for interactive textbooks. Created by Apple.', fact: 'iBooks Author let teachers build rich interactive textbooks for the iPad.' },
  scriv:  { name: 'Scrivener project', blurb: 'A Scrivener project holds an entire manuscript - chapters, notes and research - in one bundle. Created by Literature & Latte.', fact: 'Scrivener is a favourite tool of novelists for organising long writing projects.' },
  abw:    { name: 'AbiWord document', blurb: 'ABW is the document format of the free AbiWord word processor.', fact: 'AbiWord is a lightweight open-source word processor, and ABW is its native format.' },
  sxw:    { name: 'OpenOffice.org Writer', blurb: 'SXW was the OpenOffice.org 1 word-processor format before ODF arrived.', fact: 'SXW was the original OpenOffice format, replaced by today’s ODT.' },
  sxc:    { name: 'OpenOffice.org Calc', blurb: 'SXC was the OpenOffice.org 1 spreadsheet format before ODF.', fact: 'SXC was OpenOffice’s early spreadsheet format, replaced by ODS.' },
  fodt:   { name: 'Flat ODF Text', blurb: 'FODT is an OpenDocument text file stored as a single flat XML file.', fact: 'FODT keeps a whole word-processor document in one readable XML file.' },
  fods:   { name: 'Flat ODF Spreadsheet', blurb: 'FODS is an OpenDocument spreadsheet stored as flat XML.', fact: 'FODS is a spreadsheet saved as one plain XML file rather than a zipped package.' },
  fodp:   { name: 'Flat ODF Presentation', blurb: 'FODP is an OpenDocument presentation stored as a single flat XML file rather than a zipped package.' },
  fodg:   { name: 'Flat ODF Graphics', blurb: 'FODG is an OpenDocument graphics/drawing stored as a single flat XML file rather than a zipped package.' },
  ott:    { name: 'ODF text template', blurb: 'OTT is the OpenDocument template for word-processor documents.', fact: 'OTT is the OpenDocument equivalent of a Word .dotx template.' },
  dotx:   { name: 'Word template', blurb: 'DOTX is the modern Microsoft Word template format.', fact: 'A DOTX provides the starting layout and styles for new Word documents.' },
  dotm:   { name: 'Word macro template', blurb: 'DOTM is a Microsoft Word template that can carry macros.', fact: 'DOTM is a Word template allowed to contain automation macros.' },
  vsdx:   { name: 'Visio drawing', blurb: 'VSDX is the modern Microsoft Visio diagram format.', fact: 'VSDX is what Visio saves flowcharts and diagrams as today.' },
  tex:    { name: 'TeX source', blurb: 'TEX is a TeX or LaTeX typesetting source file. Created by Donald Knuth.', fact: 'Knuth created TeX in 1978, and it still typesets most of the world’s scientific papers.' },
  latex:  { name: 'LaTeX document', blurb: 'LATEX is a LaTeX document, the system that typesets academic and mathematical writing.', fact: 'LaTeX, built on TeX in the 1980s, is the standard for scientific publishing.' },
  bib:    { name: 'BibTeX bibliography', blurb: 'BIB holds BibTeX references that LaTeX turns into a formatted bibliography.', fact: 'A .bib file is the reference database that feeds citations into a LaTeX paper.' },
  rst:    { name: 'reStructuredText', blurb: 'RST is reStructuredText, the markup behind much Python documentation.', fact: 'reStructuredText is the markup language of the Sphinx documentation system.' },
  adoc:   { name: 'AsciiDoc', blurb: 'ADOC is an AsciiDoc document, a readable markup used for technical books and docs.', fact: 'AsciiDoc offers more power than Markdown for long technical writing.' },
  org:    { name: 'Org mode', blurb: 'ORG is an Emacs Org mode file for notes, to-do lists and writing.', fact: 'Org mode is one of Emacs’s most beloved features for organising work and ideas.' },
  textile:{ name: 'Textile markup', blurb: 'TEXTILE is a lightweight markup language once popular in blogs and wikis.', fact: 'Textile was an early web markup that turned plain text into HTML.' },
  tei:    { name: 'TEI document', blurb: 'TEI is the XML standard for digitising literary and historical texts in the humanities.', fact: 'The Text Encoding Initiative is the scholarly standard for marking up old manuscripts and books.' },
  rmd:    { name: 'R Markdown', blurb: 'RMD weaves R code and its results into a single document. Used with RStudio.', fact: 'R Markdown lets researchers mix code, charts and prose in one reproducible report.' },
  qmd:    { name: 'Quarto document', blurb: 'QMD is a Quarto document, the successor to R Markdown for reproducible publishing.', fact: 'Quarto, released in 2022, extends R Markdown to Python, Julia and more.' },
  rtfd:   { name: 'macOS rich text', blurb: 'RTFD is the macOS rich-text format that bundles images and attachments. Created by Apple.', fact: 'RTFD is really a folder, letting a TextEdit document carry its own images.' },
  mht:    { name: 'Web archive (MHT)', blurb: 'MHT saves a whole web page - text and images - in one file.', fact: 'MHT bundles a complete web page so it can be read offline as a single file.' },
  mhtml:  { name: 'Web archive (MHTML)', blurb: 'MHTML packs an entire web page into a single archive file.', fact: 'MHTML uses the email MIME format to store a page and all its parts together.' },
  warc:   { name: 'Web ARChive', blurb: 'WARC is the standard format web archives use to store crawled pages. Used by the Wayback Machine.', fact: 'WARC is how the Internet Archive’s Wayback Machine preserves the web.' },
  maff:   { name: 'Mozilla Archive Format', blurb: 'MAFF was a Firefox add-on’s way of saving complete web pages in one file.', fact: 'MAFF saved web pages as a ZIP, but faded after Firefox changed its add-on system.' },
  jats:   { name: 'Journal Article Tag Suite', blurb: 'JATS is the XML standard for scholarly journal articles.', fact: 'JATS is how academic publishers structure research articles for archiving.' },
  nxml:   { name: 'PubMed article XML', blurb: 'NXML holds journal articles in the NLM/JATS format used by PubMed Central.', fact: 'NXML is the format behind millions of articles in PubMed Central.' },
  dvi:    { name: 'TeX DVI', blurb: 'DVI was TeX’s original device-independent output format before PDF.', fact: 'DVI was the page format TeX produced before PDF became the standard.' },
  chm:    { name: 'Compiled HTML Help', blurb: 'CHM is Microsoft’s Compiled HTML Help format, the help files of classic Windows software.', fact: 'CHM packs a help system - pages, images and an index - into one searchable file.' },
  wpd:    { name: 'WordPerfect document', blurb: 'WPD is a WordPerfect document, the word processor that ruled offices before Word.', fact: 'WordPerfect dominated office word processing in the 1980s and early 1990s.' },
  qxd:    { name: 'QuarkXPress layout', blurb: 'QXD is a QuarkXPress layout, the desktop-publishing standard of the 1990s.', fact: 'QuarkXPress laid out most of the magazines and newspapers of the 1990s.' },
  pmd:    { name: 'PageMaker layout', blurb: 'PMD is an Adobe PageMaker layout, a pioneer of desktop publishing.', fact: 'PageMaker helped start the desktop-publishing revolution in the mid-1980s.' },
  lit:    { name: 'Microsoft Reader ebook', blurb: 'LIT was Microsoft Reader’s e-book format.', fact: 'Microsoft discontinued its Reader and the LIT e-book format in 2012.' },
  kfx:    { name: 'Kindle KFX ebook', blurb: 'KFX is Amazon’s modern Kindle e-book format, with advanced typography.', fact: 'KFX gives Kindle books better fonts and layout than the older Kindle formats.' },

  // ---- Developer & data serialisation ----
  lock:      { name: 'Dependency lockfile', blurb: 'A lock file pins the exact versions of a project’s dependencies for reproducible builds.', fact: 'Lockfiles make sure every developer and server installs identical package versions.' },
  json5:     { name: 'JSON5', blurb: 'JSON5 extends JSON with comments and trailing commas for human-edited config.', fact: 'JSON5 makes JSON friendlier to write by hand.' },
  jsonc:     { name: 'JSON with Comments', blurb: 'JSONC is JSON that allows comments, used by Visual Studio Code’s config files.', fact: 'JSONC lets you annotate configuration that strict JSON would reject.' },
  hjson:     { name: 'Human JSON', blurb: 'Hjson is a human-friendly take on JSON with comments and relaxed syntax.', fact: 'Hjson drops JSON’s strict punctuation to make config easier for people to edit.' },
  pb:        { name: 'Protocol Buffers data', blurb: 'A .pb file holds data serialised with Google’s Protocol Buffers.', fact: 'PB files are compact binary messages defined by a Protocol Buffers schema.' },
  msgpack:   { name: 'MessagePack', blurb: 'MessagePack serialises data like JSON but in a compact binary form.', fact: 'MessagePack calls itself "JSON, but fast and small".' },
  mpk:       { name: 'MessagePack', blurb: 'MPK holds data in the compact binary MessagePack format.', fact: 'MPK is the binary, space-saving cousin of JSON.' },
  bson:      { name: 'Binary JSON', blurb: 'BSON is the binary JSON form used by the MongoDB database.', fact: 'BSON is how MongoDB stores documents on disk and over the wire.' },
  cbor:      { name: 'CBOR data', blurb: 'CBOR (Concise Binary Object Representation) is a compact binary data format.', fact: 'CBOR was standardised as RFC 8949 for small, efficient machine-to-machine data.' },
  pkl:       { name: 'Python pickle', blurb: 'A pickle file stores Python objects in binary form - convenient but unsafe from untrusted sources.', fact: 'Opening a pickle from an untrusted source can run hidden malicious code.' },
  pickle:    { name: 'Python pickle', blurb: 'Pickle serialises Python objects to disk, and should only be loaded from sources you trust.', fact: 'A malicious pickle can execute code when loaded, so treat unknown ones with caution.' },
  npz:       { name: 'Zipped NumPy arrays', blurb: 'NPZ is a ZIP holding several NumPy arrays in one file.', fact: 'NPZ bundles multiple NumPy arrays together, each kept in the efficient .npy format.' },
  jar:       { name: 'Java Archive', blurb: 'A JAR bundles a Java program and its resources into one runnable ZIP.', fact: 'A JAR is really a ZIP, so its contents can be inspected with any archive tool.' },
  war:       { name: 'Web Application Archive', blurb: 'A WAR packages a Java web application for a server like Tomcat.', fact: 'A WAR holds everything a Java web app needs to deploy to a server.' },
  ear:       { name: 'Enterprise Archive', blurb: 'An EAR bundles multiple modules of a Java enterprise application.', fact: 'An EAR groups several Java modules into one deployable enterprise package.' },
  fbs:       { name: 'FlatBuffers schema', blurb: 'FBS defines FlatBuffers data structures, Google’s zero-copy serialisation format.', fact: 'FlatBuffers lets programs read data without unpacking it first, prized in games.' },
  thrift:    { name: 'Apache Thrift', blurb: 'A Thrift file defines cross-language services and data structures. Created at Facebook, now Apache.', fact: 'Thrift came out of Facebook to let services written in different languages talk to each other.' },
  capnproto: { name: 'Cap’n Proto schema', blurb: 'A Cap’n Proto schema defines a fast serialisation format that needs no parsing step.', fact: 'Cap’n Proto was made by a Protocol Buffers author to be even faster - no decoding required.' },
  hcl:       { name: 'HashiCorp config', blurb: 'HCL is the configuration language behind Terraform and other HashiCorp tools.', fact: 'HCL aims to be readable by people yet precise enough for machines.' },
  mat:       { name: 'MATLAB data', blurb: 'MAT files store the variables and matrices of a MATLAB session. Created by MathWorks.', fact: 'A MAT-file saves your whole MATLAB workspace to reload later.' },
  rdb:       { name: 'Redis snapshot', blurb: 'RDB is a point-in-time snapshot of a Redis in-memory database.', fact: 'Redis writes an RDB snapshot so its in-memory data survives a restart.' },
  arrow:     { name: 'Apache Arrow', blurb: 'Arrow is an in-memory columnar data format for fast analytics across languages.', fact: 'Apache Arrow lets tools share data in memory without slow conversions.' },
  feather:   { name: 'Arrow Feather', blurb: 'Feather stores data frames on disk using Apache Arrow for quick reads.', fact: 'Feather was built to move data frames between Python and R at high speed.' },
  parquet:   { name: 'Apache Parquet', blurb: 'Parquet is a columnar storage format that powers much of modern big-data analytics.', fact: 'Parquet’s columnar layout makes huge datasets fast and cheap to query.' },
  orc:       { name: 'ORC columnar data', blurb: 'ORC (Optimized Row Columnar) is a columnar big-data format from the Hadoop world.', fact: 'ORC was created to store Hive data tables compactly and query them fast.' },
  desc:      { name: 'Protobuf descriptor set', blurb: 'A .desc file holds compiled Protocol Buffers schema descriptors.', fact: 'A descriptor set lets tools understand Protobuf messages without the original .proto file.' },
  dump:      { name: 'Data dump', blurb: 'A .dump file is a raw export of a database or a program’s memory.', fact: 'Dumps capture a system’s state for backup, transfer or debugging.' },

  // ---- Archives, packages & installers ----
  xar:     { name: 'eXtensible ARchive', blurb: 'XAR is the archive format behind macOS installer packages.', fact: 'XAR is the container Apple’s .pkg installers are built on.' },
  pkg:     { name: 'macOS installer', blurb: 'A PKG is the installer package double-clicked to set up software on macOS.', fact: 'A PKG walks you through installing a Mac app, files and all.' },
  mpkg:    { name: 'macOS meta-package', blurb: 'An MPKG groups several macOS installer packages into one.', fact: 'An MPKG lets one installer run a bundle of separate packages.' },
  msu:     { name: 'Windows Update package', blurb: 'MSU is the package format for standalone Windows updates.', fact: 'MSU files are the patches you install when updating Windows by hand.' },
  snap:    { name: 'Snap package', blurb: 'Snap packages bundle a Linux app with its dependencies. Created by Canonical.', fact: 'Snap packages, made by Canonical, let one Linux app run across many distributions.' },
  flatpak: { name: 'Flatpak bundle', blurb: 'Flatpak distributes sandboxed Linux apps that run across distributions.', fact: 'Flatpak apps run in a sandbox and bring their own libraries, so they work everywhere.' },
  sit:     { name: 'StuffIt archive', blurb: 'SIT is a StuffIt archive, the dominant compression format on the classic Mac.', fact: 'StuffIt was to the classic Mac what ZIP was to Windows.' },
  sitx:    { name: 'StuffIt X archive', blurb: 'SITX is the newer StuffIt X archive format for macOS.', fact: 'StuffIt X improved on the original SIT format with better compression.' },
  lzo:     { name: 'LZO stream', blurb: 'LZO is a compression format built for very fast decompression.', fact: 'LZO favours speed, making it popular for real-time compression.' },
  br:      { name: 'Brotli stream', blurb: 'BR is a Brotli-compressed file. Created by Google.', fact: 'Brotli, released in 2015, compresses web pages and fonts better than gzip.' },
  jnlp:    { name: 'Java Web Start', blurb: 'JNLP launched Java applications straight from the web.', fact: 'Java Web Start let apps run from a link, a technology now retired.' },
  tlz:     { name: 'LZMA tarball', blurb: 'TLZ is a tar archive compressed with LZMA.', fact: 'TLZ is shorthand for a tar.lzma compressed archive.' },
  tbz:     { name: 'bzip2 tarball', blurb: 'TBZ is a tar archive compressed with bzip2.', fact: 'TBZ is shorthand for a tar.bz2 compressed archive.' },
  tz:      { name: 'Compressed tarball', blurb: 'TZ is a tar archive compressed with Unix compress.', fact: 'TZ is the old shorthand for a tar.Z archive.' },

  // ---- 3D & CAD (advanced) ----
  drc:     { name: 'Draco mesh', blurb: 'DRC is a Draco-compressed 3D mesh or point cloud. Created by Google.', fact: 'Draco shrinks 3D models so they load quickly over the web.' },
  ksplat:  { name: 'Compressed Gaussian splat', blurb: 'KSplat is a compressed format for 3D Gaussian splat scenes.', fact: 'KSplat packs photoreal Gaussian splat captures into a smaller file.' },
  u3d:     { name: 'Universal 3D', blurb: 'U3D is a 3D format designed to embed interactive models inside PDFs.', fact: 'U3D, standardised as ECMA-363, is what lets a PDF hold a spinnable 3D model.' },
  '3dxml': { name: 'Dassault 3DXML', blurb: '3DXML is Dassault Systèmes’ lightweight XML format for sharing 3D models.', fact: '3DXML lets people view CATIA models without the full CAD software.' },
  x:       { name: 'DirectX model', blurb: 'The .x format held 3D models and animation for Microsoft’s DirectX.', fact: 'The .x mesh format was widely used by games built on early DirectX.' },
  qb:      { name: 'Qubicle voxel model', blurb: 'QB is the voxel-model format of the Qubicle editor.', fact: 'Qubicle is a popular tool for building voxel art for games.' },
  wings:   { name: 'Wings 3D model', blurb: 'A .wings file is a model from Wings 3D, a free subdivision modeller.', fact: 'Wings 3D is a free, approachable tool for organic 3D modelling.' },
  rvt:     { name: 'Revit project', blurb: 'RVT is an Autodesk Revit project, the leading building-information-modelling tool.', fact: 'A Revit project holds an entire building as intelligent, connected components.' },
  rfa:     { name: 'Revit family', blurb: 'RFA holds a reusable Revit component, like a door, window or fixture.', fact: 'Revit families are the smart building blocks architects drop into a model.' },
  rte:     { name: 'Revit template', blurb: 'RTE is an Autodesk Revit project template.', fact: 'An RTE gives a new Revit project its standard settings and views.' },
  rft:     { name: 'Revit family template', blurb: 'RFT is the template used to create new Revit families.', fact: 'An RFT is the starting point for building a custom Revit component.' },
  par:     { name: 'Solid Edge part', blurb: 'PAR is a part file from Siemens Solid Edge CAD.', fact: 'PAR holds a single mechanical part designed in Solid Edge.' },
  psm:     { name: 'Solid Edge sheet metal', blurb: 'PSM is a Solid Edge sheet-metal part file.', fact: 'PSM is Solid Edge’s format for parts to be folded from sheet metal.' },
  pwd:     { name: 'Solid Edge weldment', blurb: 'PWD is a Solid Edge weldment file.', fact: 'PWD holds a welded assembly designed in Solid Edge.' },
  nwd:     { name: 'Navisworks model', blurb: 'NWD is a published Autodesk Navisworks model for design review and clash detection.', fact: 'A Navisworks NWD combines many models so teams can spot clashes before building.' },
  nwf:     { name: 'Navisworks file set', blurb: 'NWF links the source models that make up a Navisworks project.', fact: 'An NWF references the original CAD files rather than copying them in.' },
  nwc:     { name: 'Navisworks cache', blurb: 'NWC is the lightweight cache Navisworks creates from a CAD model.', fact: 'The NWC cache lets Navisworks reopen a heavy model quickly.' },
  model:   { name: 'CATIA V4 model', blurb: 'A .model file is a part from older versions of CATIA.', fact: 'The .model format dates from CATIA version 4, before CATPart took over.' },
  exp:     { name: 'CATIA export', blurb: 'EXP is an export/exchange file from CATIA CAD.', fact: 'EXP was used to move data in and out of older CATIA systems.' },
  dlv:     { name: 'CATIA V4 file', blurb: 'DLV is a CATIA V4 file, used alongside .model and .exp.', fact: 'DLV is one of the CATIA V4 part formats, now considered legacy.' },
  session: { name: 'CATIA session', blurb: 'A .session file stores a CATIA work session of several models.', fact: 'A CATIA session bundles the models a designer was working with together.' },
  cl3:     { name: 'Topcon scan (CL3)', blurb: 'CL3 is a terrestrial laser-scanner point cloud from Topcon scanning systems.', fact: 'CL3 stores the dense point clouds captured by ground-based Topcon 3D scanners.' },
  clr:     { name: 'Topcon scan (CLR)', blurb: 'CLR is a Topcon terrestrial laser-scanner point-cloud file.', fact: 'CLR holds 3D scan data from Topcon ground-based laser scanners.' },
  tzf:     { name: 'Terrestrial scan (TZF)', blurb: 'TZF is a Trimble terrestrial laser-scanner point-cloud file.', fact: 'TZF stores point clouds from Trimble 3D scanning hardware.' },
  vsd:     { name: 'Visio drawing (legacy)', blurb: 'VSD is the legacy binary Microsoft Visio diagram format.', fact: 'VSD was Visio’s format before the XML-based VSDX took over.' },

  // ---- Disk images, firmware & VMs ----
  trx:   { name: 'Router firmware', blurb: 'TRX is a Broadcom-based router firmware image, used by OpenWrt and others.', fact: 'TRX is the firmware format flashed onto many home Wi-Fi routers.' },
  dfu:   { name: 'USB DFU image', blurb: 'DFU is a Device Firmware Upgrade image, used to flash chips like the STM32 over USB.', fact: 'DFU is a standard way to update a device’s firmware straight over USB.' },
  fd:    { name: 'UEFI/BIOS flash', blurb: 'FD is a UEFI or BIOS flash-volume image, used by coreboot and EDK2.', fact: 'An FD image is the raw contents of a motherboard’s firmware chip.' },
  rom:   { name: 'Firmware/ROM image', blurb: 'A .rom file is a firmware or BIOS image dumped from a chip.', fact: 'ROM images hold the low-level code a device runs the moment it powers on.' },
  ubi:   { name: 'UBI flash volume', blurb: 'UBI is a Linux flash-memory volume image for raw NAND in embedded devices.', fact: 'UBI manages wear and bad blocks on the flash chips inside many gadgets.' },
  simg:  { name: 'Android sparse image', blurb: 'SIMG is an Android sparse disk image, used when flashing a phone.', fact: 'A sparse image skips empty space, so flashing an Android partition is faster.' },
  itb:   { name: 'U-Boot FIT image', blurb: 'ITB is a U-Boot FIT image bundling a kernel, device tree and more for booting.', fact: 'A FIT image lets the U-Boot bootloader carry everything it needs in one file.' },
  dsk:   { name: 'Floppy disk image', blurb: 'DSK is a raw floppy-disk image, common in retro computing and emulators.', fact: 'A DSK image is a sector-by-sector copy of an old floppy disk.' },
  ima:   { name: 'Floppy disk image', blurb: 'IMA is a raw floppy-disk image with a FAT boot sector.', fact: 'IMA files preserve old floppies for use in emulators and virtual machines.' },
  vfd:   { name: 'Virtual floppy disk', blurb: 'VFD is a virtual floppy-disk image used by virtual machines.', fact: 'A VFD lets a virtual machine read a floppy that no longer physically exists.' },
  vmsd:  { name: 'VMware snapshot metadata', blurb: 'VMSD records the snapshot information for a VMware virtual machine.', fact: 'The VMSD keeps track of a VM’s chain of snapshots.' },
  nvram: { name: 'VM firmware memory', blurb: 'An .nvram file stores a virtual machine’s BIOS or UEFI settings.', fact: 'NVRAM is where a virtual machine remembers its firmware settings between runs.' },
  pvm:   { name: 'Parallels VM', blurb: 'PVM is a Parallels Desktop virtual machine bundle for the Mac.', fact: 'A PVM holds a whole guest operating system run by Parallels on a Mac.' },
  hdd:   { name: 'Parallels virtual disk', blurb: 'HDD is a Parallels Desktop virtual hard-disk image.', fact: 'The HDD file is the virtual drive a Parallels virtual machine boots from.' },
  mf:    { name: 'OVF manifest', blurb: 'MF is the manifest of an OVF virtual-appliance package, listing file checksums.', fact: 'The OVF manifest verifies that a virtual appliance’s files arrived intact.' },
  vbk:   { name: 'Veeam backup', blurb: 'VBK is a full backup file created by Veeam Backup & Replication.', fact: 'A VBK holds a complete Veeam backup of a server or virtual machine.' },

  // ---- Game engine assets & more ROMs ----
  assets:      { name: 'Unity assets', blurb: 'An .assets file holds packed game content from the Unity engine.', fact: 'Unity stores a game’s art, audio and scenes inside assets files.' },
  bundle:      { name: 'Unity AssetBundle', blurb: 'A .bundle is a Unity AssetBundle of game content loaded on demand.', fact: 'AssetBundles let a Unity game download extra content after it ships.' },
  resource:    { name: 'Unity resource', blurb: 'A .resource file holds packed data for a Unity game.', fact: 'Unity keeps bulk data like audio in .resource files alongside its scenes.' },
  utoc:        { name: 'Unreal IoStore index', blurb: 'UTOC is an Unreal Engine IoStore table of contents for cooked game data.', fact: 'UTOC indexes the packed assets of a shipped Unreal Engine game.' },
  ucas:        { name: 'Unreal IoStore data', blurb: 'UCAS holds the cooked asset data of an Unreal Engine game, paired with UTOC.', fact: 'UCAS is the container that actually stores a packed Unreal game’s assets.' },
  uexp:        { name: 'Unreal asset data', blurb: 'UEXP holds the bulk data of an Unreal Engine asset, split from its header.', fact: 'Unreal splits an asset’s header and its heavy data into .uasset and .uexp.' },
  umd:         { name: 'PSP disc image (UMD)', blurb: 'UMD is a disc image of a Sony PlayStation Portable Universal Media Disc.', fact: 'The Universal Media Disc was Sony’s compact optical format for the PSP, launched in 2004.' },
  cso:         { name: 'Compressed ISO', blurb: 'CSO (CISO) is a compressed disc image, popular for PSP games.', fact: 'CSO shrinks a game ISO so more titles fit on a memory card.' },
  chd:         { name: 'MAME disc image', blurb: 'CHD is a compressed disc/drive image used by MAME and Dreamcast emulators.', fact: 'CHD stores arcade and console disc images compactly for emulation.' },
  fsb:         { name: 'FMOD sound bank', blurb: 'FSB is an FMOD sound bank holding a game’s audio. Created by Firelight FMOD.', fact: 'FMOD is a widely licensed audio engine, and FSB packs the sounds it plays.' },
  bank:        { name: 'Game sound bank', blurb: 'A .bank file is an FMOD sound bank of a game’s audio events.', fact: 'FMOD banks group a game’s sounds and the rules for when they play.' },
  bnk:         { name: 'Wwise sound bank', blurb: 'BNK is a Wwise sound bank of game audio. Created by Audiokinetic Wwise.', fact: 'Wwise is a leading game-audio middleware, and BNK holds its packaged sounds.' },
  wem:         { name: 'Wwise audio', blurb: 'WEM is an individual audio clip from the Wwise game-audio engine.', fact: 'WEM files are the actual sounds packed inside Wwise sound banks.' },
  spine:       { name: 'Spine skeleton', blurb: 'A Spine file holds a 2D skeletal animation. Created by Esoteric Software’s Spine.', fact: 'Spine animates 2D game characters with bones instead of frame-by-frame drawing.' },
  skel:        { name: 'Spine skeleton (binary)', blurb: 'SKEL is the binary skeleton data for a Spine 2D animation.', fact: 'SKEL stores the bones and animations of a Spine character compactly.' },
  atlas:       { name: 'Texture atlas', blurb: 'An .atlas file maps the packed images on a sprite sheet, used with Spine and game engines.', fact: 'An atlas lets a game pack many sprites into one image and find each one again.' },
  yyp:         { name: 'GameMaker project', blurb: 'YYP is a GameMaker Studio project file. Created by YoYo Games.', fact: 'GameMaker is a popular engine for 2D games, and YYP is its project format.' },
  yy:          { name: 'GameMaker resource', blurb: 'A .yy file describes a single GameMaker resource, like a sprite or object.', fact: 'GameMaker stores each game resource as its own .yy file.' },
  gmx:         { name: 'GameMaker resource (legacy)', blurb: 'GMX is a resource file from older versions of GameMaker Studio.', fact: 'GMX was the resource format of GameMaker: Studio 1.' },
  mca:         { name: 'Minecraft region', blurb: 'MCA is a Minecraft Anvil region file, storing a 32x32 chunk area of a world.', fact: 'Minecraft splits its endless worlds into MCA region files on disk.' },
  mcr:         { name: 'Minecraft region (legacy)', blurb: 'MCR is the older Minecraft region format, before Anvil.', fact: 'MCR was Minecraft’s region format before the Anvil update raised the height limit.' },
  mctemplate:  { name: 'Minecraft world template', blurb: 'MCTEMPLATE is a Minecraft: Bedrock world template, a starting point for new worlds.', fact: 'A world template lets creators share a pre-built Minecraft starting world.' },
  '3dsx':      { name: '3DS homebrew', blurb: '3DSX is a homebrew application for the Nintendo 3DS.', fact: '3DSX is the format community-made 3DS apps run in.' },
  a78:         { name: 'Atari 7800 ROM', blurb: 'A78 is an Atari 7800 game ROM, run on emulators.', fact: 'The Atari 7800 launched in 1986 and could play most Atari 2600 games too.' },
  a26:         { name: 'Atari 2600 ROM', blurb: 'A26 is an Atari 2600 game ROM, run on emulators.', fact: 'The Atari 2600, from 1977, brought cartridge gaming into the home.' },
  lnx:         { name: 'Atari Lynx ROM', blurb: 'LNX is an Atari Lynx handheld game ROM.', fact: 'The Atari Lynx, from 1989, was the first colour handheld console.' },
  j64:         { name: 'Atari Jaguar ROM', blurb: 'J64 is an Atari Jaguar game ROM.', fact: 'The Atari Jaguar, launched in 1993, was marketed as the first 64-bit console.' },
  pce:         { name: 'PC Engine ROM', blurb: 'PCE is a PC Engine (TurboGrafx-16) game ROM.', fact: 'The PC Engine was a hit in Japan, sold as the TurboGrafx-16 elsewhere.' },
  gg:          { name: 'Game Gear ROM', blurb: 'GG is a Sega Game Gear handheld game ROM.', fact: 'The Game Gear was Sega’s colour answer to the Game Boy in 1990.' },
  sms:         { name: 'Master System ROM', blurb: 'SMS is a Sega Master System game ROM.', fact: 'The Sega Master System was Sega’s 8-bit rival to the NES.' },
  ws:          { name: 'WonderSwan ROM', blurb: 'WS is a Bandai WonderSwan handheld game ROM.', fact: 'The WonderSwan, designed by Game Boy’s creator, was a hit in late-1990s Japan.' },
  wsc:         { name: 'WonderSwan Color ROM', blurb: 'WSC is a Bandai WonderSwan Color game ROM.', fact: 'The WonderSwan Color added colour to Bandai’s Japan-only handheld.' },
  w3x:         { name: 'Warcraft III map', blurb: 'W3X is a Warcraft III: The Frozen Throne map. Created with Blizzard’s World Editor.', fact: 'Custom W3X maps gave rise to the MOBA genre, including the original DotA.' },
  w3m:         { name: 'Warcraft III map', blurb: 'W3M is a Warcraft III map from the original Reign of Chaos.', fact: 'W3M maps powered the huge custom-game scene of Warcraft III.' },

  // ---- Game saves, scripts & emulator data ----
  rpyc:    { name: 'Ren’Py compiled script', blurb: 'RPYC is a compiled script from the Ren’Py visual-novel engine.', fact: 'Ren’Py is the engine behind a huge number of indie visual novels.' },
  rvdata2: { name: 'RPG Maker VX Ace data', blurb: 'RVDATA2 holds game data for RPG Maker VX Ace, stored as Ruby objects.', fact: 'RPG Maker lets people build role-playing games with little or no coding.' },
  rxdata:  { name: 'RPG Maker XP data', blurb: 'RXDATA holds game data for RPG Maker XP.', fact: 'RXDATA stores the maps and database of an RPG Maker XP game.' },
  pyxel:   { name: 'Pyxel Edit document', blurb: 'A Pyxel file is a pixel-art and tileset document from Pyxel Edit.', fact: 'Pyxel Edit is a popular tool for drawing pixel-art tiles and animations.' },
  ldtk:    { name: 'LDtk level', blurb: 'LDtk is a modern 2D level-editor project. Created by the maker of Dead Cells.', fact: 'LDtk is a free level editor built by one of the developers of Dead Cells.' },
  tic:     { name: 'TIC-80 cartridge', blurb: 'TIC is a cartridge for the TIC-80 fantasy console.', fact: 'TIC-80 is a tiny make-believe retro console for building and sharing little games.' },
  xdelta:  { name: 'xdelta patch', blurb: 'XDELTA is a binary patch in VCDIFF format, often used to patch game ROMs.', fact: 'xdelta turns the difference between two files into a small patch.' },
  basis:   { name: 'Basis Universal texture', blurb: 'BASIS is a Basis Universal compressed texture for games and the web.', fact: 'Basis Universal textures can be transcoded to whatever format a GPU prefers.' },
  srm:     { name: 'Emulator save', blurb: 'SRM is a cartridge save (battery RAM) from a game emulator.', fact: 'An SRM holds the saved game an emulator would have written to the cartridge.' },
  state:   { name: 'Emulator savestate', blurb: 'A .state file is an emulator savestate - a frozen snapshot of a game in progress.', fact: 'A savestate captures the exact moment of play, letting you resume instantly.' },
  dsv:     { name: 'DeSmuME save', blurb: 'DSV is a battery save from the DeSmuME Nintendo DS emulator.', fact: 'DSV stores the in-game saves of DS titles played in DeSmuME.' },
  dsm:     { name: 'DeSmuME movie', blurb: 'DSM is a recorded input movie from the DeSmuME DS emulator.', fact: 'Input movies like DSM record every button press for tool-assisted speedruns.' },
  vbm:     { name: 'VisualBoyAdvance movie', blurb: 'VBM is a recorded input movie from the VisualBoyAdvance emulator.', fact: 'VBM replays a Game Boy game by replaying every recorded button press.' },
  fm2:     { name: 'FCEUX movie', blurb: 'FM2 is a recorded input movie from the FCEUX NES emulator.', fact: 'FM2 movies are central to the NES tool-assisted speedrun community.' },

  // ---- More documents & publishing ----
  dita:    { name: 'DITA topic', blurb: 'DITA is an XML topic for technical documentation. An OASIS standard.', fact: 'DITA lets technical writers reuse small topics across many manuals.' },
  ditamap: { name: 'DITA map', blurb: 'DITAMAP organises DITA topics into a complete document or help system.', fact: 'A DITA map is the table of contents that assembles reusable topics into a book.' },
  sla:     { name: 'Scribus document', blurb: 'SLA is a Scribus desktop-publishing document.', fact: 'Scribus is a free, open-source page-layout program for magazines and brochures.' },
  scd:     { name: 'Scribus document', blurb: 'SCD is a Scribus desktop-publishing file.', fact: 'SCD is an older Scribus document format.' },
  wps:     { name: 'Microsoft Works document', blurb: 'WPS is a document from Microsoft Works, the budget office suite.', fact: 'Microsoft Works was a cut-down, cheaper alternative to Office in the 1990s.' },
  wpt:     { name: 'Microsoft Works template', blurb: 'WPT is a template from Microsoft Works.', fact: 'WPT provided ready-made layouts in the Microsoft Works word processor.' },
  wri:     { name: 'Windows Write document', blurb: 'WRI is a document from Windows Write, the word processor bundled with early Windows.', fact: 'Windows Write came free with Windows 3.x before WordPad replaced it.' },
  dot:     { name: 'Word 97 template', blurb: 'DOT is a legacy Microsoft Word template.', fact: 'DOT was Word’s template format before the XML-based DOTX.' },
  sdw:     { name: 'StarOffice Writer', blurb: 'SDW is a StarOffice 5 word-processor document, an ancestor of OpenOffice.', fact: 'StarOffice was the commercial suite that became OpenOffice and then LibreOffice.' },
  sdc:     { name: 'StarOffice Calc', blurb: 'SDC is a StarOffice 5 spreadsheet document.', fact: 'SDC was StarOffice’s spreadsheet before the move to open ODF formats.' },
  sdd:     { name: 'StarOffice Impress', blurb: 'SDD is a StarOffice 5 presentation document.', fact: 'SDD held StarOffice slideshows in the suite that became OpenOffice.' },
  snb:     { name: 'Shanda Bambook ebook', blurb: 'SNB is an e-book for the Shanda Bambook reader.', fact: 'SNB was the e-book format of China’s Shanda Bambook e-reader.' },
  lrf:     { name: 'Sony BBeB ebook', blurb: 'LRF is a Sony BBeB e-book, used by early Sony Reader devices.', fact: 'LRF was the format of Sony’s e-readers before EPUB took over.' },
  lrx:     { name: 'Sony BBeB ebook (DRM)', blurb: 'LRX is a DRM-protected Sony BBeB e-book.', fact: 'LRX was the encrypted form of Sony’s early e-book format.' },
  tcr:     { name: 'Psion ebook', blurb: 'TCR is a compressed-text e-book format from the Psion era.', fact: 'TCR was a simple compressed-text e-book format for early handhelds.' },
  cba:     { name: 'Comic Book ACE', blurb: 'CBA is a comic book packed in an ACE archive.', fact: 'CBA is a rarer comic format using the old ACE compression.' },
  fm:      { name: 'FrameMaker document', blurb: 'FM is an Adobe FrameMaker document, used for long technical books and manuals.', fact: 'FrameMaker is built for huge structured documents like aircraft manuals.' },
  book:    { name: 'FrameMaker book', blurb: 'A .book file ties together the chapters of an Adobe FrameMaker book.', fact: 'A FrameMaker book file assembles many documents into one numbered publication.' },
  awt:     { name: 'AbiWord template', blurb: 'AWT is a template for the free AbiWord word processor.', fact: 'AWT gives new AbiWord documents a ready-made starting layout.' },
  sxd:     { name: 'StarOffice Draw', blurb: 'SXD is a StarOffice/OpenOffice Draw vector graphic.', fact: 'SXD was the drawing format of the OpenOffice 1 era.' },
  otg:     { name: 'ODF graphics template', blurb: 'OTG is an OpenDocument template for vector drawings.', fact: 'OTG is the OpenDocument template behind LibreOffice Draw graphics.' },
  pm6:     { name: 'PageMaker 6 layout', blurb: 'PM6 is an Adobe PageMaker 6 desktop-publishing layout.', fact: 'PageMaker 6 was a mainstay of 1990s desktop publishing.' },
  p65:     { name: 'PageMaker 6.5 layout', blurb: 'P65 is an Adobe PageMaker 6.5 layout.', fact: 'P65 came from PageMaker 6.5, near the end of the program’s life.' },
  pt6:     { name: 'PageMaker template', blurb: 'PT6 is an Adobe PageMaker 6 template.', fact: 'PT6 provided reusable layouts for PageMaker documents.' },
  adf:     { name: 'ADF file', blurb: 'ADF is an ambiguous extension shared by several unrelated formats.', fact: 'The .adf extension is reused by a range of unrelated formats, from Amiga disk images to Esri grids.' },

  // ---- Email, calendar & contacts (more) ----
  olm:   { name: 'Outlook for Mac archive', blurb: 'OLM is an archive of mail and data from Outlook for Mac.', fact: 'OLM is how Outlook on the Mac exports a mailbox for backup or transfer.' },
  oft:   { name: 'Outlook template', blurb: 'OFT is a reusable Microsoft Outlook message template.', fact: 'An OFT lets you send the same formatted email again and again.' },
  p7m:   { name: 'S/MIME encrypted email', blurb: 'P7M is an encrypted S/MIME email message.', fact: 'P7M wraps an email in encryption so only the intended reader can open it.' },
  p7s:   { name: 'S/MIME signature', blurb: 'P7S is the digital signature attached to a signed S/MIME email.', fact: 'A P7S signature proves an email really came from the claimed sender.' },
  msf:   { name: 'Mozilla mail index', blurb: 'MSF is a Thunderbird mail-summary index in the Mork format.', fact: 'The MSF index lets Thunderbird show a folder without re-reading every message.' },
  mab:   { name: 'Mozilla address book', blurb: 'MAB is a Mozilla/Thunderbird address book in the Mork format.', fact: 'MAB stored Thunderbird contacts before it moved to SQLite.' },
  mbx:   { name: 'Eudora mailbox', blurb: 'MBX is a mailbox file from Eudora or Outlook Express.', fact: 'MBX held a whole folder of email in classic desktop mail clients.' },
  toc:   { name: 'Eudora index', blurb: 'TOC is the table-of-contents index for a Eudora mailbox.', fact: 'TOC let Eudora list a mailbox quickly without scanning every message.' },
  vmg:   { name: 'Nokia SMS backup', blurb: 'VMG is a vMessage file, used to back up SMS text messages from phones.', fact: 'VMG was how many older Nokia phones exported their text messages.' },
  vnt:   { name: 'Phone note (vNote)', blurb: 'VNT is a vNote file holding a note exported from a mobile phone.', fact: 'VNT was the standard way feature phones saved and shared notes.' },
  xcal:  { name: 'xCal calendar', blurb: 'XCAL is an XML form of an iCalendar event, defined by RFC 6321.', fact: 'xCal expresses calendar data in XML for systems that prefer it over iCalendar.' },
  jcal:  { name: 'jCal calendar', blurb: 'JCAL is a JSON form of an iCalendar event, defined by RFC 7265.', fact: 'jCal carries calendar data as JSON for easy use in web apps.' },
  xcard: { name: 'xCard contact', blurb: 'XCARD is an XML form of a vCard contact, defined by RFC 6351.', fact: 'xCard expresses contact details in XML rather than the classic vCard text.' },
  jcard: { name: 'jCard contact', blurb: 'JCARD is a JSON form of a vCard contact, defined by RFC 7095.', fact: 'jCard carries contact details as JSON for web applications.' },
  ldi:   { name: 'LDIF directory export', blurb: 'LDI is an LDIF export of directory entries such as users or contacts.', fact: 'LDI is a text dump of LDAP directory data, like the more common .ldif.' },
  pab:   { name: 'Personal Address Book', blurb: 'PAB is a legacy Microsoft Outlook Personal Address Book.', fact: 'PAB held Outlook contacts before they moved into the main data file.' },
  wab:   { name: 'Windows Address Book', blurb: 'WAB is the Windows Address Book used by Outlook Express.', fact: 'WAB was where Windows kept your contacts in the Outlook Express era.' },
  abbu:  { name: 'Apple Contacts backup', blurb: 'ABBU is an Apple Address Book / Contacts backup archive.', fact: 'An ABBU is a full backup of your contacts from the macOS Contacts app.' },

  // ---- Security & forensics (more) ----
  pgp:     { name: 'OpenPGP message', blurb: 'PGP is an OpenPGP encrypted message, key or signature.', fact: 'PGP brought strong public-key encryption to ordinary email back in 1991.' },
  gpg:     { name: 'GnuPG file', blurb: 'GPG is a file encrypted or signed with GnuPG, the free OpenPGP implementation.', fact: 'GnuPG is the free software behind much of the world’s OpenPGP encryption.' },
  sig:     { name: 'Digital signature', blurb: 'A .sig file is a detached digital signature verifying a file’s authenticity.', fact: 'A signature file lets you confirm a download came from who it claims and was not tampered with.' },
  evt:     { name: 'Windows Event Log (legacy)', blurb: 'EVT is the classic Windows Event Log format, from Windows XP and earlier.', fact: 'EVT was the event-log format before Windows Vista switched to EVTX.' },
  yar:     { name: 'YARA rule', blurb: 'YAR is a YARA rule used to detect and classify malware.', fact: 'YARA rules let analysts describe malware patterns and hunt for matches.' },
  yara:    { name: 'YARA rule', blurb: 'YARA is a malware-detection rule file.', fact: 'YARA is nicknamed "the pattern-matching swiss knife for malware researchers".' },
  rules:   { name: 'IDS rules', blurb: 'A .rules file holds intrusion-detection rules for Snort or Suricata.', fact: 'These rules tell network monitors which traffic patterns signal an attack.' },
  stix:    { name: 'STIX threat intel', blurb: 'STIX is a standard format for sharing cyber-threat intelligence.', fact: 'STIX lets security teams exchange details of attacks in a common language.' },
  ioc:     { name: 'OpenIOC indicator', blurb: 'IOC is an OpenIOC file describing indicators of a security compromise. Created by Mandiant.', fact: 'OpenIOC describes the tell-tale signs that a system has been breached.' },
  saz:     { name: 'Fiddler capture', blurb: 'SAZ is a saved HTTP session captured by the Fiddler web-debugging tool.', fact: 'A SAZ archive bundles up a recorded set of web requests for analysis.' },
  '1pux':  { name: '1Password export', blurb: '1PUX is an export of a 1Password vault.', fact: '1PUX is the format 1Password uses to export your passwords for backup or migration.' },
  opvault: { name: '1Password OPVault', blurb: 'OPVault is a 1Password vault format storing encrypted credentials.', fact: 'OPVault was 1Password’s on-disk vault format for syncing across devices.' },
  keychain:{ name: 'Apple Keychain', blurb: 'A .keychain file is an Apple Keychain storing passwords and certificates.', fact: 'The Keychain is where macOS safely keeps your saved passwords and keys.' },
  aff:     { name: 'Forensic disk image', blurb: 'AFF is an Advanced Forensic Format disk image used in digital investigations.', fact: 'AFF was created as an open alternative for storing forensic disk images.' },
  aff4:    { name: 'Forensic image (AFF4)', blurb: 'AFF4 is the modern Advanced Forensic Format for evidence disk images.', fact: 'AFF4 modernised forensic imaging to handle today’s huge drives.' },
  kdb:     { name: 'KeePass 1.x database', blurb: 'KDB is a KeePass 1.x encrypted password database.', fact: 'KDB is the original KeePass vault, since succeeded by the KDBX format.' },
  pvk:     { name: 'Microsoft private key', blurb: 'PVK is a Microsoft private-key file, used with Authenticode code signing.', fact: 'A PVK holds the private key developers use to sign Windows software.' },

  // ---- Science, statistics & engineering (more) ----
  rds:    { name: 'R data object', blurb: 'RDS stores a single serialised R object. Used by RStudio and R.', fact: 'RDS lets an R user save one object and load it back later exactly as it was.' },
  rdata:  { name: 'R workspace', blurb: 'RData stores an entire R workspace of objects.', fact: 'An RData file can save all your R variables at once to reload later.' },
  rda:    { name: 'R workspace', blurb: 'RDA is an R workspace file, the same format as RData.', fact: 'RDA is just a shorter name for an R workspace file.' },
  ab1:    { name: 'DNA sequencing trace', blurb: 'AB1 is an ABIF chromatogram from Sanger DNA sequencing.', fact: 'AB1 holds the coloured peaks a sequencing machine reads to spell out DNA.' },
  poscar: { name: 'VASP structure', blurb: 'POSCAR describes a crystal structure for the VASP physics simulation package.', fact: 'POSCAR is the input that tells VASP where every atom in a crystal sits.' },
  cube:   { name: 'Gaussian cube', blurb: 'CUBE stores volumetric data such as electron density from chemistry simulations.', fact: 'A cube file maps a property like electron density across a 3D grid.' },
  xsf:    { name: 'XCrySDen structure', blurb: 'XSF is a crystal-structure file for the XCrySDen visualisation tool.', fact: 'XSF lets researchers visualise crystals and their properties in XCrySDen.' },
  cdx:    { name: 'ChemDraw drawing', blurb: 'CDX is a ChemDraw chemical-structure drawing. Created by PerkinElmer.', fact: 'ChemDraw is the standard tool chemists use to draw molecules for publication.' },
  cdxml:  { name: 'ChemDraw XML', blurb: 'CDXML is the XML form of a ChemDraw chemical structure.', fact: 'CDXML stores a drawn molecule as readable XML.' },
  abf:    { name: 'Axon electrophysiology', blurb: 'ABF is an Axon Binary File from pCLAMP electrophysiology recordings.', fact: 'ABF holds the electrical recordings of cells made in neuroscience labs.' },
  tdms:   { name: 'LabVIEW measurement data', blurb: 'TDMS stores measurement data from National Instruments LabVIEW.', fact: 'TDMS is built to log fast streams of sensor data with their metadata.' },
  vhdr:   { name: 'BrainVision header', blurb: 'VHDR is the header of a BrainVision EEG recording.', fact: 'BrainVision splits an EEG recording into a header, markers and the raw signal.' },
  vmrk:   { name: 'BrainVision markers', blurb: 'VMRK holds the event markers for a BrainVision EEG recording.', fact: 'The VMRK file notes when each event happened during an EEG session.' },
  cnt:    { name: 'Neuroscan EEG', blurb: 'CNT is a continuous EEG recording from Neuroscan systems.', fact: 'CNT holds the brain-wave signals captured in a Neuroscan EEG study.' },
  eeg:    { name: 'EEG recording', blurb: 'An .eeg file holds an electroencephalography brain-signal recording.', fact: 'EEG files store the tiny electrical signals measured from the scalp.' },
  set:    { name: 'EEGLAB dataset', blurb: 'SET is an EEGLAB dataset of processed EEG data, used in MATLAB.', fact: 'EEGLAB is a widely used MATLAB toolbox for analysing brain signals.' },
  vts:    { name: 'VTK structured grid', blurb: 'VTS is a VTK XML structured-grid file for scientific visualisation.', fact: 'VTS stores data on a curved structured grid for tools like ParaView.' },
  vtr:    { name: 'VTK rectilinear grid', blurb: 'VTR is a VTK XML rectilinear-grid file for scientific visualisation.', fact: 'VTR stores values on a rectangular grid with uneven spacing.' },
  net:    { name: 'SPICE netlist', blurb: 'A .net file is a circuit netlist, often for SPICE simulation.', fact: 'A netlist lists a circuit’s parts and how they connect.' },
  msh:    { name: 'Gmsh mesh', blurb: 'MSH is a finite-element mesh from the Gmsh tool, used in simulation.', fact: 'Gmsh carves a shape into small elements so physics can be simulated on it.' },
  inp:    { name: 'FEA input deck', blurb: 'INP is a finite-element input deck for Abaqus or Nastran.', fact: 'An INP deck tells engineering solvers the model, loads and materials to analyse.' },
  cdb:    { name: 'ANSYS model database', blurb: 'CDB is an ANSYS APDL model database for engineering analysis.', fact: 'CDB stores a meshed model for the ANSYS simulation software.' },
  wfm:    { name: 'Oscilloscope waveform', blurb: 'WFM is a captured waveform from a digital oscilloscope.', fact: 'A WFM saves the exact trace an oscilloscope measured for later study.' },

  // ---- GIS & mapping (more) ----
  o5m:  { name: 'OpenStreetMap o5m', blurb: 'O5M is a compact binary form of OpenStreetMap data, used by osmconvert.', fact: 'O5M speeds up processing of large OpenStreetMap extracts.' },
  o5c:  { name: 'OpenStreetMap change', blurb: 'O5C is a binary OpenStreetMap change file in the o5m family.', fact: 'O5C records the edits needed to update an OpenStreetMap dataset.' },
  lyr:  { name: 'ArcMap layer', blurb: 'LYR is an Esri ArcMap layer file, storing how a map layer looks.', fact: 'A LYR remembers a layer’s symbols and styling so it can be reused.' },
  lyrx: { name: 'ArcGIS Pro layer', blurb: 'LYRX is an Esri ArcGIS Pro layer file, holding styling as CIM JSON.', fact: 'LYRX is the modern ArcGIS Pro replacement for the older LYR layer file.' },
  qgs:  { name: 'QGIS project', blurb: 'QGS is a QGIS project file, holding a map’s layers and styling. Created by QGIS.', fact: 'QGIS is the leading free, open-source desktop GIS.' },
  qgz:  { name: 'QGIS project (zipped)', blurb: 'QGZ is a compressed QGIS project bundling the .qgs file and its data.', fact: 'QGZ packs a whole QGIS project into one tidy zipped file.' },
  sbn:  { name: 'Shapefile spatial index', blurb: 'SBN is an Esri spatial index that speeds up queries on a shapefile.', fact: 'The SBN index helps GIS software find shapes by location quickly.' },
  sbx:  { name: 'Shapefile spatial index', blurb: 'SBX is the companion index to a shapefile’s SBN spatial index.', fact: 'SBX works with SBN to speed up spatial searches in a shapefile.' },
  cpt:  { name: 'Colour palette (CPT)', blurb: 'CPT is a colour-palette file used by GMT and GDAL to colour maps.', fact: 'A CPT maps data values to colours, for example shading elevation on a map.' },
  bil:  { name: 'ENVI band-interleaved raster', blurb: 'BIL is a band-interleaved-by-line raster, common in remote sensing.', fact: 'BIL interleaves a satellite image’s colour bands line by line.' },
  bip:  { name: 'ENVI band-interleaved raster', blurb: 'BIP is a band-interleaved-by-pixel raster used in remote sensing.', fact: 'BIP stores all of a pixel’s bands together, one pixel after another.' },
  bsq:  { name: 'ENVI band-sequential raster', blurb: 'BSQ is a band-sequential raster, storing each image band one after another.', fact: 'BSQ keeps each band of a satellite image as a complete separate layer.' },

  pack: { name: 'Git pack file', blurb: 'PACK is the compressed bundle git uses to store many repository objects together, delta-compressed against one another, under .git/objects/pack. Created and read by git.', fact: 'When you clone or fetch, git transfers history as a single packfile rather than thousands of loose objects, then keeps it paired with a .idx index for fast lookup.' },
  idx:  { name: 'Git pack index', blurb: 'IDX is the index that sits beside a git .pack file, mapping each object’s SHA-1 to its offset so git can find objects without scanning the whole pack. Created and read by git.', fact: 'The index begins with the bytes \\377tOc, a deliberately non-text signature so older git versions could tell the version 2 index from the headerless version 1.' },

  'sqlite-wal': { name: 'SQLite write-ahead log', blurb: 'A .sqlite-wal file is the write-ahead log SQLite keeps beside a database in WAL journalling mode, holding committed changes that have not yet been folded back into the main file. Written by SQLite and anything built on it.', fact: 'In WAL mode a writer and several readers can work at once, because new changes land in the -wal sidecar first and are only checkpointed into the database later.' },
  'sqlite-shm': { name: 'SQLite shared-memory index', blurb: 'A .sqlite-shm file is the shared-memory index that lets several processes navigate a SQLite write-ahead log at the same time, mapping WAL frames to database pages. Written by SQLite alongside the -wal file.', fact: 'The -shm file holds no real data of its own - it is a rebuildable index over the -wal log, and SQLite recreates it from scratch if it is missing.' },
  'db-wal': { name: 'SQLite write-ahead log (.db sidecar)', blurb: 'A .db-wal file is the write-ahead log for a SQLite database stored as .db, holding committed changes that are waiting to be checkpointed into the main file. Same format as .sqlite-wal.', fact: 'The log is named after its database with a "-wal" suffix, so closing the database cleanly lets SQLite checkpoint and then remove it.' },
  'db-shm': { name: 'SQLite shared-memory index (.db sidecar)', blurb: 'A .db-shm file is the shared-memory WAL index for a SQLite database stored as .db, coordinating concurrent access to its write-ahead log. Same format as .sqlite-shm.', fact: 'Both WAL sidecars (-wal and -shm) exist only while a database uses WAL journalling mode, and disappear on a clean shutdown.' },

  // EXT_PAGES_END
};
